                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">ROOM {activeRoomId}</span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.idx, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.idx, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedToEvaluation} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                PROCEED TO EVALUATION
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

