import React, { useState } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state (Key 0, 1 for Semis, 2 for Final)
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State (Store MVP and Ratings per match index)
  const [matchEvaluations, setMatchEvaluations] = useState<Record<number, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    teamName: string;
    teamIndex: number;
    role: Role;
    winnerName: string;
    candidates: string[];
  } | null>(null);

  // --- PREPARE DATA ---

  // 1. Organize Semi-Finals
  const semiFinalMatches: { teamA: any; teamB: any | null; label: string; mode: string; originalIdx: number }[] = [];
  for (let i = 0; i < match.teams.length; i += 2) {
    const matchIdx = i / 2;
    // Limit to 2 semi-finals for the visual bracket (handling 4 teams max for this specific view logic)
    if (matchIdx < 2) {
      semiFinalMatches.push({
        teamA: match.teams[i],
        teamB: match.teams[i + 1] || null,
        label: `Semi-Final ${matchIdx + 1}`,
        mode: 'BO1',
        originalIdx: matchIdx
      });
    }
  }

  // 2. Determine Grand Finalists based on Scores
  const getWinnerTeam = (matchIdx: number, matchData: any) => {
    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // Simple logic: If score is entered and one is higher
    if (scoreA > scoreB) return matchData.teamA;
    if (scoreB > scoreA && matchData.teamB) return matchData.teamB;

    // Auto-advance if BYE
    if (!matchData.teamB) return matchData.teamA;

    return null;
  };

  const gfTeamA = semiFinalMatches[0] ? getWinnerTeam(0, semiFinalMatches[0]) : null;
  const gfTeamB = semiFinalMatches[1] ? getWinnerTeam(1, semiFinalMatches[1]) : null;

  // 3. Construct Grand Final Match Object
  // We assign index 2 to the Grand Final
  const grandFinalMatch = {
     teamA: gfTeamA,
     teamB: gfTeamB,
     label: 'Grand Final',
     mode: 'BO3',
     idx: 2
  };

  const hasGrandFinal = match.teams.length >= 3; 

  // --- REVEAL & EVALUATION DATA HELPERS ---

  // Determine which match is currently active for reveal/evaluation
  let activeMatchData: { teamA: any; teamB: any | null; idx: number; label: string } | null = null;

  if (currentMatchIdx === 2) {
      activeMatchData = { teamA: grandFinalMatch.teamA, teamB: grandFinalMatch.teamB, idx: 2, label: 'Grand Final' };
  } else {
      const m = semiFinalMatches[currentMatchIdx];
      if (m) activeMatchData = { teamA: m.teamA, teamB: m.teamB, idx: currentMatchIdx, label: m.label };
  }

  const activeRoomId = matchRoomIds[currentMatchIdx] || '0000';

  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  const startReveal = (idx: number) => {
    setCurrentMatchIdx(idx);
    setPhase('REVEAL');
    setRevealedSlots(new Set());
    setCurrentRoleIdx(-1);
  };

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;

    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.idx;

    ROLES_ORDER.forEach(role => {
        // Team A
        newRevealed.add(getSlotId(idx, 'A', role));

        // Team B (if exists)
        if (activeMatchData!.teamB) {
            newRevealed.add(getSlotId(idx, 'B', role));
        }
    });

    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null); // Cancel any active spin
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;

    // Candidates are all players in the tournament for flavor
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1, // Just for color mapping (0=Azure, 1=Crimson style)
      role,
      winnerName: winner.name,
      candidates
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    const { role, teamIndex } = wheelState;
    const teamSide = teamIndex === 0 ? 'A' : 'B';

    const id = getSlotId(currentMatchIdx, teamSide, role);

    setRevealedSlots(prev => {
        const next = new Set(prev);
        next.add(id);
        return next;
    });

    const isTeamB = teamSide === 'B';
    const isBye = !activeMatchData.teamB;

    if (isTeamB || isBye) {
        setCurrentRoleIdx(prev => prev + 1);
    }
    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  // --- EVALUATION LOGIC ---

  const proceedToEvaluation = () => {
    setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     setMatchEvaluations(prev => ({
        ...prev,
        [currentMatchIdx]: { mvpId, ratings }
     }));
     setPhase('OVERVIEW');
  };

  const getMatchForEvaluation = (): { matchResult: MatchResult, winner: 'azure' | 'crimson' } | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;

      // Construct a temporary MatchResult object for the EvaluationScreen component
      const tempMatchResult: MatchResult = {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false, // Bracket usually 5v5 standard
          timestamp: Date.now()
      };

      // Determine winner based on scores entered in bracket
      const scoreA = scores[`${currentMatchIdx}-A`] || 0;
      const scoreB = scores[`${currentMatchIdx}-B`] || 0;
      let winner: 'azure' | 'crimson' = 'azure'; // Default

      if (scoreB > scoreA) winner = 'crimson';

      return { matchResult: tempMatchResult, winner };
  };


  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const handleScoreChange = (matchIdx: number, teamSide: 'A' | 'B', val: string) => {
    const num = parseInt(val) || 0;
    setScores(prev => ({ ...prev, [`${matchIdx}-${teamSide}`]: num }));
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[], color: string) => {
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
        return (
            <div className="h-14 w-full bg-black/40 border border-white/5 clip-corner-sm flex items-center justify-center opacity-30">
                <span className="text-[10px] font-orbitron text-white/20 uppercase tracking-[0.2em]">Locked</span>
            </div>
        );
    }

    return (
        <div className="h-14 w-full bg-[#0a1a2f] border-l-4 clip-corner-sm flex items-center px-4 animate-slide-in relative overflow-hidden" style={{ borderColor: color }}>
            <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>
            <div className="mr-3 scale-75 opacity-70" style={{ color }}>{RoleIcons[role]}</div>
            <div className="font-orbitron font-bold text-white text-sm md:text-base truncate">{slot?.player.name}</div>
        </div>
    );
  };

  // --- COMPONENT RETURN ---

  // Handle Evaluation Phase Render
  if (phase === 'EVALUATION') {
      const evalData = getMatchForEvaluation();
      if (evalData) {
          return (
              <EvaluationScreen 
                  match={evalData.matchResult} 
                  winner={evalData.winner} 
                  onComplete={handleEvaluationComplete} 
              />
          );
      }
      // Fallback if data missing
      setPhase('OVERVIEW');
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full max-w-7xl mx-auto px-6 py-12 flex flex-col items-center">
          {/* Header */}
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               SEMI-FINALS BO1 . GRAND FINAL BO3
             </p>
          </div>

          {/* Bracket Tree Layout */}
          <div className="w-full flex items-center justify-center py-20 relative">

            {/* Left Column: Semi-Finals */}
            <div className="flex flex-col gap-16 relative z-20">
              {semiFinalMatches.map((m, idx) => (
                <div key={idx} className="relative group animate-slide-in" style={{ animationDelay: `${idx * 150}ms` }}>

                  {/* Match Card */}
                  <div className="w-80 bg-[#081221]/90 border border-white/5 clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 group-hover:border-[#dcb06b]/30">

                    {/* Card Header */}
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                      <div className="flex gap-2">
                          {matchEvaluations[idx] && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">EVAL DONE</span>}
                          <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                      </div>
                    </div>

                    {/* Team Rows with Score Inputs */}
                    <div className="space-y-2">
                      {/* Team A */}
                      <div className="flex items-center gap-3 bg-black/40 border border-white/5 p-2 rounded group/team">
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                        <input 
                            type="number" 
                            min="0"
                            value={scores[`${idx}-A`] || 0}
                            onChange={(e) => handleScoreChange(idx, 'A', e.target.value)}
                            className="w-10 h-6 bg-[#05090f] border border-[#1e3a5f] text-center text-xs font-bold text-white focus:border-[#dcb06b] focus:outline-none clip-corner-sm"
                        />
                      </div>

                      <div className="flex justify-center h-4 items-center">
                        <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                      </div>

                      {/* Team B */}
                      <div className="flex items-center gap-3 bg-black/40 border border-white/5 p-2 rounded group/team">
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB?.color || '#444' }}></div>
                        <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">
                          {m.teamB?.name || 'BYE'}
                        </span>
                        {m.teamB && (
                            <input 
                                type="number" 
                                min="0"
                                value={scores[`${idx}-B`] || 0}
                                onChange={(e) => handleScoreChange(idx, 'B', e.target.value)}
                                className="w-10 h-6 bg-[#05090f] border border-[#1e3a5f] text-center text-xs font-bold text-white focus:border-[#dcb06b] focus:outline-none clip-corner-sm"
                            />
                        )}
                      </div>
                    </div>

                    {/* Footer: Room ID & Start Reveal */}
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                      <div className="flex-1">
                          <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                          <input 
                            type="text" 
                            placeholder="0000"
                            value={matchRoomIds[idx] || ''}
                            onChange={(e) => handleRoomIdChange(idx, e.target.value)}
                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                          />
                      </div>
                      <Button 
                          onClick={() => startReveal(idx)}
                          disabled={!matchRoomIds[idx] || matchRoomIds[idx].length < 4}
                          size="sm"
                          className="h-[30px] text-[8px] px-4"
                      >
                          START
                      </Button>
                    </div>
                  </div>

                  {/* Horizontal Connector Line Right */}
                  <div className="absolute top-1/2 -right-12 w-12 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              ))}

              {/* Central Connector Fork */}
              <div className="absolute top-1/2 -right-16 h-[75%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
              </div>
            </div>

            {/* Spacer */}
            <div className="w-32"></div>

            {/* Right Column: Grand Final */}
            {hasGrandFinal && (
              <div className="relative z-20 animate-slide-in" style={{ animationDelay: '500ms' }}>
                 <div className="w-80 bg-[#081221]/90 border border-[#dcb06b]/20 clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)]">
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                      <div className="flex gap-2">
                        {matchEvaluations[2] && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">EVAL DONE</span>}
                        <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                      </div>
                    </div>

                    <div className="space-y-4">
                       {/* GF Team A */}
                       <div className="bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3">
                          {grandFinalMatch.teamA ? (
                              <>
                                <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamA.color }}></div>
                                <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamA.name}</span>
                              </>
                          ) : (
                              <>
                                <div className="w-1.5 h-6 bg-white/10"></div>
                                <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                              </>
                          )}
                       </div>

                       <div className="flex justify-center items-center h-2">
                         <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                       </div>

                       {/* GF Team B */}
                       <div className="bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3">
                          {grandFinalMatch.teamB ? (
                              <>
                                <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamB.color }}></div>
                                <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamB.name}</span>
                              </>
                          ) : (
                              <>
                                <div className="w-1.5 h-6 bg-white/10"></div>
                                <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                              </>
                          )}
                       </div>
                    </div>

                    {/* GF Footer: Room ID & Start (Only if teams exist) */}
                    <div className="mt-4 pt-4 border-t border-white/5">
                        {grandFinalMatch.teamA && grandFinalMatch.teamB ? (
                            <div className="flex items-end gap-3">
                                <div className="flex-1">
                                    <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                    <input 
                                        type="text" 
                                        placeholder="0000"
                                        value={matchRoomIds[2] || ''}
                                        onChange={(e) => handleRoomIdChange(2, e.target.value)}
                                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                    />
                                </div>
                                <Button 
                                    onClick={() => startReveal(2)}
                                    disabled={!matchRoomIds[2] || matchRoomIds[2].length < 4}
                                    size="sm"
                                    className="h-[30px] text-[8px] px-4"
                                >
                                    START
                                </Button>
                            </div>
                        ) : (
                            <div className="flex flex-col items-center opacity-40">
                                <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                <span className="text-[10px] text-white font-orbitron font-bold">WAITING FOR RESULTS</span>
                            </div>
                        )}
                    </div>
                 </div>
              </div>
            )}
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col px-6 py-8 overflow-hidden">
            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* Reveal Header */}
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex gap-4">
                            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>
                            {!isRevealFinished && (
                                <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                            )}
                        </div>
                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">ROOM {activeRoomId}</span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.idx, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.idx, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedToEvaluation} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                PROCEED TO EVALUATION
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state (Key 0, 1 for Semis, 2 for Final)
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    teamName: string;
    teamIndex: number;
    role: Role;
    winnerName: string;
    candidates: string[];
  } | null>(null);

  // --- PREPARE DATA ---

  // 1. Organize Semi-Finals
  const semiFinalMatches: { teamA: any; teamB: any | null; label: string; mode: string; originalIdx: number }[] = [];
  for (let i = 0; i < match.teams.length; i += 2) {
    const matchIdx = i / 2;
    if (matchIdx < 2) {
      semiFinalMatches.push({
        teamA: match.teams[i],
        teamB: match.teams[i + 1] || null,
        label: `Semi-Final ${matchIdx + 1}`,
        mode: 'BO1',
        originalIdx: matchIdx
      });
    }
  }

  // 2. Determine Grand Finalists based on Scores
  const getWinnerTeam = (matchIdx: number, matchData: any) => {
    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // In BO1 (Semis), score 1 means win.
    if (scoreA > scoreB) return matchData.teamA;
    if (scoreB > scoreA && matchData.teamB) return matchData.teamB;

    // Auto-advance if BYE
    if (!matchData.teamB) return matchData.teamA;

    return null;
  };

  const gfTeamA = semiFinalMatches[0] ? getWinnerTeam(0, semiFinalMatches[0]) : null;
  const gfTeamB = semiFinalMatches[1] ? getWinnerTeam(1, semiFinalMatches[1]) : null;

  // 3. Construct Grand Final Match Object
  const grandFinalMatch = {
     teamA: gfTeamA,
     teamB: gfTeamB,
     label: 'Grand Final',
     mode: 'BO3',
     idx: 2
  };

  const hasGrandFinal = match.teams.length >= 3; 

  // --- ACTIVE MATCH HELPERS ---

  let activeMatchData: { teamA: any; teamB: any | null; idx: number; label: string } | null = null;

  if (currentMatchIdx === 2) {
      activeMatchData = { teamA: grandFinalMatch.teamA, teamB: grandFinalMatch.teamB, idx: 2, label: 'Grand Final' };
  } else {
      const m = semiFinalMatches[currentMatchIdx];
      if (m) activeMatchData = { teamA: m.teamA, teamB: m.teamB, idx: currentMatchIdx, label: m.label };
  }

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === 2) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC (Only for Semis) ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.idx;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    const { role, teamIndex } = wheelState;
    const teamSide = teamIndex === 0 ? 'A' : 'B';
    const id = getSlotId(currentMatchIdx, teamSide, role);
    setRevealedSlots(prev => new Set(prev).add(id));
    if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      setPhase('TRANSITION');
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          // Aborted or Draw? For bracket usually we force a win.
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     // 2. Update Global State
     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     // Store evaluation for this specific game (could key by game number if desired, simplifying here)
     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < 2) {
         // Semi Finals (BO1): Immediate End
         setPhase('OVERVIEW');
     } else {
         // Grand Final (BO3): Check if series won
         if (newScoreA >= 2 || newScoreB >= 2) {
             setPhase('OVERVIEW'); // Tournament Over
         } else {
             // LOOP: Start Next Game Immediately
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[], color: string) => {
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
        return (
            <div className="h-14 w-full bg-black/40 border border-white/5 clip-corner-sm flex items-center justify-center opacity-30">
                <span className="text-[10px] font-orbitron text-white/20 uppercase tracking-[0.2em]">Locked</span>
            </div>
        );
    }

    return (
        <div className="h-14 w-full bg-[#0a1a2f] border-l-4 clip-corner-sm flex items-center px-4 animate-slide-in relative overflow-hidden" style={{ borderColor: color }}>
            <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>
            <div className="mr-3 scale-75 opacity-70" style={{ color }}>{RoleIcons[role]}</div>
            <div className="font-orbitron font-bold text-white text-sm md:text-base truncate">{slot?.player.name}</div>
        </div>
    );
  };

  // --- COMPONENT RETURN ---

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full max-w-7xl mx-auto px-6 py-12 flex flex-col items-center">
          {/* Header */}
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               SEMI-FINALS BO1 . GRAND FINAL BO3
             </p>
          </div>

          {/* Bracket Tree Layout */}
          <div className="w-full flex items-center justify-center py-20 relative">

            {/* Left Column: Semi-Finals */}
            <div className="flex flex-col gap-16 relative z-20">
              {semiFinalMatches.map((m, idx) => {
                const sA = scores[`${idx}-A`] || 0;
                const sB = scores[`${idx}-B`] || 0;
                const isDone = sA > 0 || sB > 0;

                return (
                <div key={idx} className="relative group animate-slide-in" style={{ animationDelay: `${idx * 150}ms` }}>

                  {/* Match Card */}
                  <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>

                    {/* Card Header */}
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                      <div className="flex gap-2">
                          {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                          <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                      </div>
                    </div>

                    {/* Team Rows */}
                    <div className="space-y-2">
                      {/* Team A */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                      </div>

                      <div className="flex justify-center h-4 items-center">
                        <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                      </div>

                      {/* Team B */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB?.color || '#444' }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>
                          {m.teamB?.name || 'BYE'}
                        </span>
                        {m.teamB && <span className="font-orbitron font-bold text-white">{sB}</span>}
                      </div>
                    </div>

                    {/* Footer */}
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                      <div className="flex-1">
                          <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                          <input 
                            type="text" 
                            placeholder="0000"
                            value={matchRoomIds[idx] || ''}
                            onChange={(e) => handleRoomIdChange(idx, e.target.value)}
                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                          />
                      </div>
                      {!isDone && (
                        <Button 
                            onClick={() => startMatchFlow(idx)}
                            disabled={!matchRoomIds[idx] || matchRoomIds[idx].length < 4}
                            size="sm"
                            className="h-[30px] text-[8px] px-4"
                        >
                            START
                        </Button>
                      )}
                    </div>
                  </div>

                  {/* Horizontal Connector Line Right */}
                  <div className="absolute top-1/2 -right-12 w-12 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              );
              })}

              {/* Central Connector Fork */}
              <div className="absolute top-1/2 -right-16 h-[75%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
              </div>
            </div>

            {/* Spacer */}
            <div className="w-32"></div>

            {/* Right Column: Grand Final */}
            {hasGrandFinal && (
              <div className="relative z-20 animate-slide-in" style={{ animationDelay: '500ms' }}>
                 {(() => {
                    const sA = scores[`2-A`] || 0;
                    const sB = scores[`2-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = grandFinalMatch.teamA && grandFinalMatch.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        {/* GF Team A */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        {/* GF Team B */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        {/* GF Footer */}
                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[2] || ''}
                                            onChange={(e) => handleRoomIdChange(2, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(2)}
                                        disabled={!matchRoomIds[2] || matchRoomIds[2].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})}
              </div>
            )}
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col px-6 py-8 overflow-hidden">
            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* Reveal Header */}
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex gap-4">
                            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>
                            {!isRevealFinished && (
                                <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                            )}
                        </div>
                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">ROOM {activeRoomId}</span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.idx, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.idx, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedFromReveal} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                INITIALIZE BATTLE
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state (Key 0, 1 for Semis, 2 for Final)
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    teamName: string;
    teamIndex: number;
    role: Role;
    winnerName: string;
    candidates: string[];
  } | null>(null);

  // --- PREPARE DATA ---

  // 1. Organize Semi-Finals
  const semiFinalMatches: { teamA: any; teamB: any | null; label: string; mode: string; originalIdx: number }[] = [];
  for (let i = 0; i < match.teams.length; i += 2) {
    const matchIdx = i / 2;
    if (matchIdx < 2) {
      semiFinalMatches.push({
        teamA: match.teams[i],
        teamB: match.teams[i + 1] || null,
        label: `Semi-Final ${matchIdx + 1}`,
        mode: 'BO1',
        originalIdx: matchIdx
      });
    }
  }

  // 2. Determine Grand Finalists based on Scores
  const getWinnerTeam = (matchIdx: number, matchData: any) => {
    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // In BO1 (Semis), score 1 means win.
    if (scoreA > scoreB) return matchData.teamA;
    if (scoreB > scoreA && matchData.teamB) return matchData.teamB;

    // Auto-advance if BYE (Using score convention 1-0 handled in logic, but safe fallback here)
    if (!matchData.teamB && scoreA > 0) return matchData.teamA;

    return null;
  };

  const gfTeamA = semiFinalMatches[0] ? getWinnerTeam(0, semiFinalMatches[0]) : null;
  const gfTeamB = semiFinalMatches[1] ? getWinnerTeam(1, semiFinalMatches[1]) : null;

  // 3. Construct Grand Final Match Object
  const grandFinalMatch = {
     teamA: gfTeamA,
     teamB: gfTeamB,
     label: 'Grand Final',
     mode: 'BO3',
     idx: 2
  };

  const hasGrandFinal = match.teams.length >= 3; 

  // --- ACTIVE MATCH HELPERS ---

  let activeMatchData: { teamA: any; teamB: any | null; idx: number; label: string } | null = null;

  if (currentMatchIdx === 2) {
      activeMatchData = { teamA: grandFinalMatch.teamA, teamB: grandFinalMatch.teamB, idx: 2, label: 'Grand Final' };
  } else {
      const m = semiFinalMatches[currentMatchIdx];
      if (m) activeMatchData = { teamA: m.teamA, teamB: m.teamB, idx: currentMatchIdx, label: m.label };
  }

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === 2) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC (Only for Semis) ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.idx;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    const { role, teamIndex } = wheelState;
    const teamSide = teamIndex === 0 ? 'A' : 'B';
    const id = getSlotId(currentMatchIdx, teamSide, role);
    setRevealedSlots(prev => new Set(prev).add(id));
    if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.idx;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          // Aborted or Draw? For bracket usually we force a win.
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     // 2. Update Global State
     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     // Store evaluation for this specific game (could key by game number if desired, simplifying here)
     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < 2) {
         // Semi Finals (BO1): Immediate End
         setPhase('OVERVIEW');
     } else {
         // Grand Final (BO3): Check if series won
         if (newScoreA >= 2 || newScoreB >= 2) {
             setPhase('OVERVIEW'); // Tournament Over
         } else {
             // LOOP: Start Next Game Immediately
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[], color: string) => {
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
        return (
            <div className="h-14 w-full bg-black/40 border border-white/5 clip-corner-sm flex items-center justify-center opacity-30">
                <span className="text-[10px] font-orbitron text-white/20 uppercase tracking-[0.2em]">Locked</span>
            </div>
        );
    }

    return (
        <div className="h-14 w-full bg-[#0a1a2f] border-l-4 clip-corner-sm flex items-center px-4 animate-slide-in relative overflow-hidden" style={{ borderColor: color }}>
            <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>
            <div className="mr-3 scale-75 opacity-70" style={{ color }}>{RoleIcons[role]}</div>
            <div className="font-orbitron font-bold text-white text-sm md:text-base truncate">{slot?.player.name}</div>
        </div>
    );
  };

  // --- COMPONENT RETURN ---

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full max-w-7xl mx-auto px-6 py-12 flex flex-col items-center">
          {/* Header */}
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               SEMI-FINALS BO1 . GRAND FINAL BO3
             </p>
          </div>

          {/* Bracket Tree Layout */}
          <div className="w-full flex items-center justify-center py-20 relative">

            {/* Left Column: Semi-Finals */}
            <div className="flex flex-col gap-16 relative z-20">
              {semiFinalMatches.map((m, idx) => {
                const sA = scores[`${idx}-A`] || 0;
                const sB = scores[`${idx}-B`] || 0;
                const isDone = sA > 0 || sB > 0;
                const isBye = !m.teamB;

                return (
                <div key={idx} className="relative group animate-slide-in" style={{ animationDelay: `${idx * 150}ms` }}>

                  {/* Match Card */}
                  <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>

                    {/* Card Header */}
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                      <div className="flex gap-2">
                          {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                          <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                      </div>
                    </div>

                    {/* Team Rows */}
                    <div className="space-y-2">
                      {/* Team A */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                      </div>

                      <div className="flex justify-center h-4 items-center">
                        <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                      </div>

                      {/* Team B */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB?.color || '#444' }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>
                          {m.teamB?.name || 'BYE'}
                        </span>
                        {m.teamB && <span className="font-orbitron font-bold text-white">{sB}</span>}
                      </div>
                    </div>

                    {/* Footer */}
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                      {isBye ? (
                         <div className="flex-1">
                             <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                             <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">AUTO ADVANCE</div>
                         </div>
                      ) : (
                         <div className="flex-1">
                             <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                             <input 
                               type="text" 
                               placeholder="0000"
                               value={matchRoomIds[idx] || ''}
                               onChange={(e) => handleRoomIdChange(idx, e.target.value)}
                               className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                             />
                         </div>
                      )}

                      {!isDone && (
                        <Button 
                            onClick={() => startMatchFlow(idx)}
                            disabled={!isBye && (!matchRoomIds[idx] || matchRoomIds[idx].length < 4)}
                            size="sm"
                            className="h-[30px] text-[8px] px-4"
                        >
                            {isBye ? 'ADVANCE' : 'START'}
                        </Button>
                      )}
                    </div>
                  </div>

                  {/* Horizontal Connector Line Right */}
                  <div className="absolute top-1/2 -right-12 w-12 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              );
              })}

              {/* Central Connector Fork */}
              <div className="absolute top-1/2 -right-16 h-[75%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
              </div>
            </div>

            {/* Spacer */}
            <div className="w-32"></div>

            {/* Right Column: Grand Final */}
            {hasGrandFinal && (
              <div className="relative z-20 animate-slide-in" style={{ animationDelay: '500ms' }}>
                 {(() => {
                    const sA = scores[`2-A`] || 0;
                    const sB = scores[`2-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = grandFinalMatch.teamA && grandFinalMatch.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        {/* GF Team A */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        {/* GF Team B */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        {/* GF Footer */}
                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[2] || ''}
                                            onChange={(e) => handleRoomIdChange(2, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(2)}
                                        disabled={!matchRoomIds[2] || matchRoomIds[2].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})}
              </div>
            )}
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col px-6 py-8 overflow-hidden">
            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* Reveal Header */}
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex gap-4">
                            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>
                            {!isRevealFinished && (
                                <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                            )}
                        </div>
                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.idx, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.idx, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedFromReveal} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state (Key 0, 1 for Semis, 2 for Final)
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    teamName: string;
    teamIndex: number;
    role: Role;
    winnerName: string;
    candidates: string[];
  } | null>(null);

  // --- PREPARE DATA ---

  // 1. Organize Semi-Finals
  const semiFinalMatches: { teamA: any; teamB: any | null; label: string; mode: string; originalIdx: number }[] = [];
  for (let i = 0; i < match.teams.length; i += 2) {
    const matchIdx = i / 2;
    if (matchIdx < 2) {
      semiFinalMatches.push({
        teamA: match.teams[i],
        teamB: match.teams[i + 1] || null,
        label: `Semi-Final ${matchIdx + 1}`,
        mode: 'BO1',
        originalIdx: matchIdx
      });
    }
  }

  // 2. Determine Grand Finalists based on Scores
  const getWinnerTeam = (matchIdx: number, matchData: any) => {
    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // In BO1 (Semis), score 1 means win.
    if (scoreA > scoreB) return matchData.teamA;
    if (scoreB > scoreA && matchData.teamB) return matchData.teamB;

    // Auto-advance if BYE (Using score convention 1-0 handled in logic, but safe fallback here)
    if (!matchData.teamB && scoreA > 0) return matchData.teamA;

    return null;
  };

  const gfTeamA = semiFinalMatches[0] ? getWinnerTeam(0, semiFinalMatches[0]) : null;
  const gfTeamB = semiFinalMatches[1] ? getWinnerTeam(1, semiFinalMatches[1]) : null;

  // 3. Construct Grand Final Match Object
  const grandFinalMatch = {
     teamA: gfTeamA,
     teamB: gfTeamB,
     label: 'Grand Final',
     mode: 'BO3',
     idx: 2
  };

  const hasGrandFinal = match.teams.length >= 3; 

  // --- ACTIVE MATCH HELPERS ---

  let activeMatchData: { teamA: any; teamB: any | null; idx: number; label: string } | null = null;

  if (currentMatchIdx === 2) {
      activeMatchData = { teamA: grandFinalMatch.teamA, teamB: grandFinalMatch.teamB, idx: 2, label: 'Grand Final' };
  } else {
      const m = semiFinalMatches[currentMatchIdx];
      if (m) activeMatchData = { teamA: m.teamA, teamB: m.teamB, idx: currentMatchIdx, label: m.label };
  }

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === 2) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC (Only for Semis) ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.idx;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    const { role, teamIndex } = wheelState;
    const teamSide = teamIndex === 0 ? 'A' : 'B';
    const id = getSlotId(currentMatchIdx, teamSide, role);
    setRevealedSlots(prev => new Set(prev).add(id));
    if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.idx;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          // Aborted or Draw? For bracket usually we force a win.
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     // 2. Update Global State
     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     // Store evaluation for this specific game (could key by game number if desired, simplifying here)
     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < 2) {
         // Semi Finals (BO1): Immediate End
         setPhase('OVERVIEW');
     } else {
         // Grand Final (BO3): Check if series won
         if (newScoreA >= 2 || newScoreB >= 2) {
             setPhase('OVERVIEW'); // Tournament Over
         } else {
             // LOOP: Start Next Game Immediately
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[], color: string) => {
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
        return (
            <div className="h-14 w-full bg-black/40 border border-white/5 clip-corner-sm flex items-center justify-center opacity-30">
                <span className="text-[10px] font-orbitron text-white/20 uppercase tracking-[0.2em]">Locked</span>
            </div>
        );
    }

    return (
        <div className="h-14 w-full bg-[#0a1a2f] border-l-4 clip-corner-sm flex items-center px-4 animate-slide-in relative overflow-hidden" style={{ borderColor: color }}>
            <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>
            <div className="mr-3 scale-75 opacity-70" style={{ color }}>{RoleIcons[role]}</div>
            <div className="font-orbitron font-bold text-white text-sm md:text-base truncate">{slot?.player.name}</div>
        </div>
    );
  };

  // --- COMPONENT RETURN ---

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full max-w-7xl mx-auto px-6 py-12 flex flex-col items-center">
          {/* Header */}
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               SEMI-FINALS BO1 . GRAND FINAL BO3
             </p>
          </div>

          {/* Bracket Tree Layout */}
          <div className="w-full flex items-center justify-center py-20 relative">

            {/* Left Column: Semi-Finals */}
            <div className="flex flex-col gap-16 relative z-20">
              {semiFinalMatches.map((m, idx) => {
                const sA = scores[`${idx}-A`] || 0;
                const sB = scores[`${idx}-B`] || 0;
                const isDone = sA > 0 || sB > 0;
                const isBye = !m.teamB;

                return (
                <div key={idx} className="relative group animate-slide-in" style={{ animationDelay: `${idx * 150}ms` }}>

                  {/* Match Card */}
                  <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>

                    {/* Card Header */}
                    <div className="flex justify-between items-center mb-4">
                      <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                      <div className="flex gap-2">
                          {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                          <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                      </div>
                    </div>

                    {/* Team Rows */}
                    <div className="space-y-2">
                      {/* Team A */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                      </div>

                      <div className="flex justify-center h-4 items-center">
                        <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                      </div>

                      {/* Team B */}
                      <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB?.color || '#444' }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>
                          {m.teamB?.name || 'BYE'}
                        </span>
                        {m.teamB && <span className="font-orbitron font-bold text-white">{sB}</span>}
                      </div>
                    </div>

                    {/* Footer */}
                    <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                      {isBye ? (
                         <div className="flex-1">
                             <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                             <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">AUTO ADVANCE</div>
                         </div>
                      ) : (
                         <div className="flex-1">
                             <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                             <input 
                               type="text" 
                               placeholder="0000"
                               value={matchRoomIds[idx] || ''}
                               onChange={(e) => handleRoomIdChange(idx, e.target.value)}
                               className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                             />
                         </div>
                      )}

                      {!isDone && (
                        <Button 
                            onClick={() => startMatchFlow(idx)}
                            disabled={!isBye && (!matchRoomIds[idx] || matchRoomIds[idx].length < 4)}
                            size="sm"
                            className="h-[30px] text-[8px] px-4"
                        >
                            {isBye ? 'ADVANCE' : 'START'}
                        </Button>
                      )}
                    </div>
                  </div>

                  {/* Horizontal Connector Line Right */}
                  <div className="absolute top-1/2 -right-12 w-12 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              );
              })}

              {/* Central Connector Fork */}
              <div className="absolute top-1/2 -right-16 h-[75%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
              </div>
            </div>

            {/* Spacer */}
            <div className="w-32"></div>

            {/* Right Column: Grand Final */}
            {hasGrandFinal && (
              <div className="relative z-20 animate-slide-in" style={{ animationDelay: '500ms' }}>
                 {(() => {
                    const sA = scores[`2-A`] || 0;
                    const sB = scores[`2-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = grandFinalMatch.teamA && grandFinalMatch.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        {/* GF Team A */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        {/* GF Team B */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {grandFinalMatch.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: grandFinalMatch.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{grandFinalMatch.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        {/* GF Footer */}
                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[2] || ''}
                                            onChange={(e) => handleRoomIdChange(2, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(2)}
                                        disabled={!matchRoomIds[2] || matchRoomIds[2].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
              </div>
            )}
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col px-6 py-8 overflow-hidden">
            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* Reveal Header */}
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex gap-4">
                            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>
                            {!isRevealFinished && (
                                <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                            )}
                        </div>
                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.idx, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.idx, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedFromReveal} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    teamName: string;
    teamIndex: number;
    role: Role;
    winnerName: string;
    candidates: string[];
  } | null>(null);

  // --- DYNAMIC BRACKET GENERATION ---

  const hasQuarterFinals = match.teams.length > 4;

  // Helper to get winner from scores
  const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
    // If it's a ghost match (no team A), no winner
    if (!teamA) return null;

    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // Win Condition
    if (scoreA > scoreB) return teamA;
    if (scoreB > scoreA && teamB) return teamB;

    // Auto-advance if BYE (No Opponent) and score is set (or implicitly 1-0 via auto-advance logic)
    if (!teamB && scoreA > 0) return teamA;

    return null;
  };

  // 1. Generate Quarter Finals (Indices 0-3 if hasQF)
  const quarterMatches: any[] = [];
  if (hasQuarterFinals) {
      for (let i = 0; i < 4; i++) {
          const teamA = match.teams[i * 2] || null;
          const teamB = match.teams[i * 2 + 1] || null;
          quarterMatches.push({
              id: i,
              label: `Quarter ${i + 1}`,
              mode: 'BO1',
              teamA,
              teamB
          });
      }
  }

  // 2. Generate Semi Finals
  // If hasQF: Indices 4-5. Winners from QF.
  // Else: Indices 0-1. Direct from match.teams.
  const semiMatches: any[] = [];
  if (hasQuarterFinals) {
      // Semi 1: Winner Q1 vs Winner Q2
      const q1 = quarterMatches[0];
      const q2 = quarterMatches[1];
      const q3 = quarterMatches[2];
      const q4 = quarterMatches[3];

      semiMatches.push({
          id: 4,
          label: 'Semi-Final 1',
          mode: 'BO1',
          teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
          teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
      });
      semiMatches.push({
          id: 5,
          label: 'Semi-Final 2',
          mode: 'BO1',
          teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
          teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
      });
  } else {
      // Standard 4-team bracket logic (or 3 teams)
      for (let i = 0; i < 2; i++) {
          semiMatches.push({
              id: i,
              label: `Semi-Final ${i + 1}`,
              mode: 'BO1',
              teamA: match.teams[i * 2] || null, // Handles ghost matches naturally if < 3 teams, though App logic usually prevents < 3
              teamB: match.teams[i * 2 + 1] || null
          });
      }
  }

  // 3. Generate Grand Final
  // Index: hasQF ? 6 : 2
  const gfIndex = hasQuarterFinals ? 6 : 2;
  const s1 = semiMatches[0];
  const s2 = semiMatches[1];

  const grandFinalMatch = {
      id: gfIndex,
      label: 'Grand Final',
      mode: 'BO3',
      teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
      teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
  };

  // Combine all for lookup
  const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === gfIndex) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    const { role, teamIndex } = wheelState;
    const teamSide = teamIndex === 0 ? 'A' : 'B';
    const id = getSlotId(currentMatchIdx, teamSide, role);
    setRevealedSlots(prev => new Set(prev).add(id));
    if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          // Aborted or Draw? For bracket usually we force a win.
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     // 2. Update Global State
     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < gfIndex) {
         // Not Grand Final: Immediate End
         setPhase('OVERVIEW');
     } else {
         // Grand Final (BO3): Check if series won
         if (newScoreA >= 2 || newScoreB >= 2) {
             setPhase('OVERVIEW'); // Tournament Over
         } else {
             // LOOP: Start Next Game Immediately
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[], color: string) => {
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
        return (
            <div className="h-14 w-full bg-black/40 border border-white/5 clip-corner-sm flex items-center justify-center opacity-30">
                <span className="text-[10px] font-orbitron text-white/20 uppercase tracking-[0.2em]">Locked</span>
            </div>
        );
    }

    return (
        <div className="h-14 w-full bg-[#0a1a2f] border-l-4 clip-corner-sm flex items-center px-4 animate-slide-in relative overflow-hidden" style={{ borderColor: color }}>
            <div className="absolute inset-0 bg-gradient-to-r from-white/5 to-transparent pointer-events-none"></div>
            <div className="mr-3 scale-75 opacity-70" style={{ color }}>{RoleIcons[role]}</div>
            <div className="font-orbitron font-bold text-white text-sm md:text-base truncate">{slot?.player.name}</div>
        </div>
    );
  };

  // Helper to render a bracket match card
  const renderBracketMatchCard = (m: any) => {
      // Ghost match check
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[170px] opacity-10 border border-dashed border-white/20 clip-corner-sm flex items-center justify-center">
                  <span className="font-orbitron text-[10px] uppercase">No Match</span>
              </div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;

      return (
        <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>

            {/* Card Header */}
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                <div className="flex gap-2">
                    {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                    <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                </div>
            </div>

            {/* Team Rows */}
            <div className="space-y-2">
                {/* Team A */}
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamA ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>

                <div className="flex justify-center h-4 items-center">
                <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                </div>

                {/* Team B */}
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamB ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB.name}</span>
                        <span className="font-orbitron font-bold text-white">{sB}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>
            </div>

            {/* Footer */}
            <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1">
                        <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                        <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">
                            {isGhostA ? 'WAITING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1">
                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                        <input 
                        type="text" 
                        placeholder="0000"
                        value={matchRoomIds[m.id] || ''}
                        onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                        />
                    </div>
                )}

                {!isDone && m.teamA && (
                    <Button 
                        onClick={() => startMatchFlow(m.id)}
                        disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                        size="sm"
                        className="h-[30px] text-[8px] px-4"
                    >
                        {isBye ? 'ADVANCE' : 'START'}
                    </Button>
                )}
            </div>
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          {/* Header */}
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               {hasQuarterFinals ? 'QUARTERS BO1 . ' : ''}SEMIS BO1 . GRAND FINAL BO3
             </p>
          </div>

          {/* Bracket Tree Layout */}
          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4">

            {/* Quarter Finals Column */}
            {hasQuarterFinals && (
                <div className="flex flex-col gap-8 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            {/* Connector to Semis */}
                            <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                        </div>
                    ))}
                    {/* Vertical connectors for Quarters would go here ideally */}
                </div>
            )}

            {/* Semi Finals Column */}
            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-48' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  {/* Connector to Final */}
                  <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              ))}
              {/* Central Fork */}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                 <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
               </div>
            </div>

            {/* Grand Final Column */}
            <div className="relative z-20 animate-slide-in">
                 {(() => {
                    const m = grandFinalMatch;
                    const sA = scores[`${m.id}-A`] || 0;
                    const sB = scores[`${m.id}-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = m.teamA && m.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        {/* GF Team A */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        {/* GF Team B */}
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        {/* GF Footer */}
                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[m.id] || ''}
                                            onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(m.id)}
                                        disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
            </div>
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col px-6 py-8 overflow-hidden">
            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* Reveal Header */}
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex gap-4">
                            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>
                            {!isRevealFinished && (
                                <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                            )}
                        </div>
                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>
                        <div className="w-32"></div>
                    </div>

                    {/* Reveal Arena */}
                    <div className="flex-1 flex flex-col justify-center max-w-5xl mx-auto w-full">
                        <div className="grid grid-cols-2 gap-8 md:gap-24 mb-6">
                            <div className="text-center">
                                <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamA.color }}>{activeMatchData.teamA.name}</h2>
                                <div className="h-1 w-full bg-gradient-to-r from-white/20 to-transparent"></div>
                            </div>
                            <div className="text-center">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-3xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)] mb-2" style={{ color: activeMatchData.teamB.color }}>{activeMatchData.teamB.name}</h2>
                                        <div className="h-1 w-full bg-gradient-to-l from-white/20 to-transparent"></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        <div className="space-y-4">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-8 md:gap-24 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', activeMatchData!.teamA.name, role, activeMatchData!.teamA.slots, activeMatchData!.teamA.color)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', activeMatchData!.teamB.name, role, activeMatchData!.teamB.slots, activeMatchData!.teamB.color) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Reveal Controls */}
                    <div className="mt-12 flex justify-center pb-12">
                        {!isRevealFinished ? (
                            <button 
                                onClick={handleNextReveal}
                                className="px-12 h-14 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold tracking-widest hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_20px_rgba(220,176,107,0.3)]"
                            >
                                {currentRoleIdx === -1 ? 'START ROLLING' : 'REVEAL NEXT UNIT'}
                            </button>
                        ) : (
                            <Button onClick={proceedFromReveal} className="px-12 h-14 shadow-[0_0_20px_rgba(220,176,107,0.4)]">
                                {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                            </Button>
                        )}
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Player, MatchResult, Role, MatchHistoryEntry, BracketMatchResult } from './types';
import { PlayerForm } from './components/PlayerForm';
import { PlayerList } from './components/PlayerList';
import { MatchDisplay } from './components/MatchDisplay';
import { EditPlayerModal } from './components/EditPlayerModal';
import { HistoryList } from './components/HistoryList';
import { generateMatch, generateBracketMatch } from './utils/matchmaker';
import { Button } from './components/Button';
import { BackgroundParticles } from './components/BackgroundParticles';
import { LocalClock } from './components/LocalClock';
import { ConfirmModal } from './components/ConfirmModal';
import { BracketDisplay } from './components/BracketDisplay';

const HOK_HEROES = [
  { name: "Arthur", roles: [Role.CLASH] },
  { name: "Sun Ce", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Kaizer", roles: [Role.CLASH, Role.JUNGLE] },
  { name: "Biron", roles: [Role.CLASH] },
  { name: "Li Xin", roles: [Role.CLASH] },
  { name: "Charlotte", roles: [Role.CLASH] },
  { name: "Lam", roles: [Role.JUNGLE] },
  { name: "Prince of Lanling", roles: [Role.JUNGLE, Role.ROAM] },
  { name: "Wukong", roles: [Role.JUNGLE] },
  { name: "Li Bai", roles: [Role.JUNGLE] },
  { name: "Han Xin", roles: [Role.JUNGLE] },
  { name: "Luna", roles: [Role.JUNGLE, Role.MID] },
  { name: "Angela", roles: [Role.MID] },
  { name: "Diaochan", roles: [Role.MID] },
  { name: "Xiao Qiao", roles: [Role.MID] },
  { name: "Mai Shiranui", roles: [Role.MID, Role.JUNGLE] },
  { name: "Lady Zhen", roles: [Role.MID] },
  { name: "Milady", roles: [Role.MID] },
  { name: "Luban No.7", roles: [Role.FARM] },
  { name: "Marco Polo", roles: [Role.FARM] },
  { name: "Hou Yi", roles: [Role.FARM] },
  { name: "Consort Yu", roles: [Role.FARM] },
  { name: "Di Renjie", roles: [Role.FARM] },
  { name: "Arli", roles: [Role.FARM, Role.JUNGLE] },
  { name: "Dolia", roles: [Role.ROAM] },
  { name: "Kui", roles: [Role.ROAM] },
  { name: "Zhuangzi", roles: [Role.ROAM, Role.CLASH] },
  { name: "Zhang Fei", roles: [Role.ROAM] },
  { name: "Da Qiao", roles: [Role.ROAM, Role.MID] },
  { name: "Yaria", roles: [Role.ROAM] }
];

type ViewMode = 'lobby' | 'match' | 'battle' | 'bracket';

// Persistence Keys
const STORAGE_KEY_PLAYERS = 'hok_roster_data_v2';
const STORAGE_KEY_HISTORY = 'hok_match_history_v2';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');

  // Initialize from LocalStorage or Hash
  const [players, setPlayers] = useState<Player[]>(() => {
    try {
      if (window.location.hash && window.location.hash.length > 1) {
        const hashData = window.location.hash.substring(1);
        const decoded = JSON.parse(atob(hashData));
        if (Array.isArray(decoded)) return decoded;
      }

      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.warn("Failed to load players from storage/hash", e);
      // Fallback to local storage if hash fails
      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    }
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [bracketMatch, setBracketMatch] = useState<BracketMatchResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [numBracketTeams, setNumBracketTeams] = useState(4);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Confirmation Modal State
  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    isDestructive?: boolean;
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  // Sync Players to LocalStorage & URL Hash
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));

    try {
      // Create a compact version of state for hashing to avoid URL length limits
      const compactData = players.map(p => ({
        id: p.id,
        name: p.name,
        roles: p.roles,
        isAllRoles: p.isAllRoles,
        isActive: p.isActive,
        stats: p.stats
      }));
      const hash = btoa(JSON.stringify(compactData));
      if (hash.length < 2000) {
         window.history.replaceState(null, '', `#${hash}`);
      }
    } catch (e) {}
  }, [players]);

  // Sync History to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
    else if (mode === 'bracket' && data) setBracketMatch(data);
  }, []);

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { 
                ...updatedPlayers[existingIndex], 
                roles: item.roles, 
                isAllRoles: item.isAllRoles, 
                isActive: true 
              };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    // Only validate global Room ID if NOT in Bracket Mode
    if (!isBracketMode) {
      if (!roomId.trim() || roomId.length < 4) { 
        setErrorMsg("Please enter a valid 4-digit Room ID."); 
        return; 
      }
    }

    if (isBracketMode) {
      const required = numBracketTeams * 5;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players for ${numBracketTeams} teams. Current: ${activePlayers.length}`); return; }
      const result = generateBracketMatch(activePlayers, roomId, numBracketTeams);
      if (result) { setBracketMatch(result); setErrorMsg(null); setViewMode('bracket'); }
      else { setErrorMsg("Failed to find valid composition."); }
    } else {
      const required = isCoachMode ? 12 : 10;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players. Current: ${activePlayers.length}`); return; }
      const result = generateMatch(activePlayers, roomId, isCoachMode);
      if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
      else { setErrorMsg("Failed to find valid composition."); }
    }
  };

  const handleClearAll = () => {
    setConfirmState({
      isOpen: true,
      title: "CLEAR ROSTER",
      message: "This will permanently delete ALL players from your squad list. Are you sure you want to proceed?",
      isDestructive: true,
      onConfirm: () => setPlayers([]),
    });
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot)
    };
    setCurrentMatch(updatedMatch); navigate('match', updatedMatch);
  };

  const handleBracketReroll = (teamIndex: number, role: Role, newPlayer: Player) => {
    if (!bracketMatch) return;
    const updatedTeams = bracketMatch.teams.map((team, idx) => {
        if (idx === teamIndex) {
            return {
                ...team,
                slots: team.slots.map(slot => slot.role === role ? { ...slot, player: newPlayer } : slot)
            };
        }
        return team;
    });
    setBracketMatch({ ...bracketMatch, teams: updatedTeams });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
    const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));
    const allMatchIds = new Set([...azureIds, ...crimsonIds]);

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      if (!allMatchIds.has(p.id)) return { ...p, isLastMatchMvp: false };

      const isAzure = azureIds.has(p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };

      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }

      return { 
        ...p, 
        stats: newStats, 
        isLastMatchMvp, 
        lastMatchRating: ratings?.[p.id] || 0 
      };
    });

    setPlayers(updatedPlayers); 
    navigate('lobby', updatedPlayers);
    setCurrentMatch(null); 
    setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Flex Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach Gemik", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach KPL", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  const handleClearHistory = () => {
    setConfirmState({
      isOpen: true,
      title: "ERASE HISTORY",
      message: "This will permanently delete all recorded battle logs. This action cannot be undone.",
      isDestructive: true,
      onConfirm: () => setMatchHistory([]),
    });
  };

  const isRoomReady = roomId.length === 4;

  const copyShareLink = () => {
    navigator.clipboard.writeText(window.location.href);
    alert("Share link copied to clipboard!");
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <LocalClock />

      <ConfirmModal 
        isOpen={confirmState.isOpen}
        title={confirmState.title}
        message={confirmState.message}
        onConfirm={confirmState.onConfirm}
        onCancel={() => setConfirmState(prev => ({ ...prev, isOpen: false }))}
        isDestructive={confirmState.isDestructive}
      />

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
