import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number; // 0 or 1 relative to display (not global)
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // --- DYNAMIC BRACKET GENERATION ---

  const hasQuarterFinals = match.teams.length > 4;

  // Helper to get winner from scores
  const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
    // If it's a ghost match (no team A), no winner
    if (!teamA) return null;

    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // Win Condition
    if (scoreA > scoreB) return teamA;
    if (scoreB > scoreA && teamB) return teamB;

    // Auto-advance if BYE (No Opponent) and score is set (or implicitly 1-0 via auto-advance logic)
    if (!teamB && scoreA > 0) return teamA;

    return null;
  };

  // 1. Generate Quarter Finals (Indices 0-3 if hasQF)
  const quarterMatches: any[] = [];
  if (hasQuarterFinals) {
      for (let i = 0; i < 4; i++) {
          const teamA = match.teams[i * 2] || null;
          const teamB = match.teams[i * 2 + 1] || null;
          quarterMatches.push({
              id: i,
              label: `Quarter ${i + 1}`,
              mode: 'BO1',
              teamA,
              teamB
          });
      }
  }

  // 2. Generate Semi Finals
  const semiMatches: any[] = [];
  if (hasQuarterFinals) {
      const q1 = quarterMatches[0];
      const q2 = quarterMatches[1];
      const q3 = quarterMatches[2];
      const q4 = quarterMatches[3];

      semiMatches.push({
          id: 4,
          label: 'Semi-Final 1',
          mode: 'BO1',
          teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
          teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
      });
      semiMatches.push({
          id: 5,
          label: 'Semi-Final 2',
          mode: 'BO1',
          teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
          teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
      });
  } else {
      for (let i = 0; i < 2; i++) {
          semiMatches.push({
              id: i,
              label: `Semi-Final ${i + 1}`,
              mode: 'BO1',
              teamA: match.teams[i * 2] || null,
              teamB: match.teams[i * 2 + 1] || null
          });
      }
  }

  // 3. Generate Grand Final
  const gfIndex = hasQuarterFinals ? 6 : 2;
  const s1 = semiMatches[0];
  const s2 = semiMatches[1];

  const grandFinalMatch = {
      id: gfIndex,
      label: 'Grand Final',
      mode: 'BO3',
      teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
      teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
  };

  const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === gfIndex) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      type: 'reveal',
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates,
      duration: Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000
    });
  };

  const handleRerollClick = (teamSide: 'A' | 'B', role: Role, teamData: any) => {
    // 1. Identify Global Team Index
    const globalTeamIdx = match.teams.findIndex(t => t.name === teamData.name);
    if (globalTeamIdx === -1) return;

    // 2. Determine Bench Players (Active players NOT currently assigned to ANY bracket team)
    const assignedIds = new Set(match.teams.flatMap(t => t.slots.map(s => s.player.id)));
    const benchPlayers = activePlayers.filter(p => !assignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    // 3. Filter candidates for the role
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const candidateNames = candidates.map(p => p.name);

    // 4. Auto-swap if only 1 candidate, else wheel
    if (candidates.length === 1) {
        onReroll(globalTeamIdx, role, candidates[0]);
        // Trigger visual flash
        const slotId = getSlotId(currentMatchIdx, teamSide, role);
        setAutoFillFlash(slotId);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000;

    setWheelState({
        isOpen: true,
        type: 'reroll',
        teamName: teamData.name,
        teamIndex: teamSide === 'A' ? 0 : 1,
        globalTeamIndex: globalTeamIdx,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;

    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < gfIndex) {
         setPhase('OVERVIEW');
     } else {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setPhase('OVERVIEW');
         } else {
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  // New Reroll-Compatible Card Renderer
  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const isAutoFilled = autoFillFlash === id;

    // Theme Construction based on Team Color or Default A/B
    const baseColor = teamData.color || (teamSide === 'A' ? '#00d2ff' : '#ef4444');

    // Inline styles for dynamic team colors
    const cardStyle = {
        borderColor: isAutoFilled ? '#dcb06b' : baseColor,
        boxShadow: isAutoFilled ? `0 0 30px #dcb06b` : (isRevealed ? `0 0 15px ${baseColor}` : 'none')
    };
    const textStyle = { color: isAutoFilled ? '#dcb06b' : (isRevealed ? baseColor : '#4a5f78') };

    if (!isRevealed) {
        return (
            <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
                <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
                    {RoleIcons[role]}
                </div>
            </div>
        );
    }

    return (
        <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
            <div 
                className={`absolute inset-0 clip-corner-md border-l-4 tilt-card bg-[#0a1a2f] border transition-all duration-300 shadow-[0_0_20px_rgba(0,0,0,0.6)]`}
                style={cardStyle}
            >
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'B' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className="mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 scale-[0.8] opacity-90" style={textStyle}>
                        {RoleIcons[role]}
                    </div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                        {slot?.player.name}
                    </span>
                    <div 
                        className="absolute inset-0 opacity-20 pointer-events-none"
                        style={{ background: `linear-gradient(${teamSide === 'B' ? 'to left' : 'to right'}, ${baseColor}, transparent)` }}
                    ></div>
                </div>

                {/* REROLL BUTTON */}
                <button 
                    onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role, teamData); }}
                    className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'A' ? 'right-4' : 'left-4'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                </button>
            </div>
        </div>
    );
  };

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[170px] opacity-10 border border-dashed border-white/20 clip-corner-sm flex items-center justify-center">
                  <span className="font-orbitron text-[10px] uppercase">No Match</span>
              </div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;

      return (
        <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                <div className="flex gap-2">
                    {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                    <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                </div>
            </div>

            <div className="space-y-2">
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamA ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>

                <div className="flex justify-center h-4 items-center">
                   <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                </div>

                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamB ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB.name}</span>
                        <span className="font-orbitron font-bold text-white">{sB}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>
            </div>

            <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1">
                        <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                        <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">
                            {isGhostA ? 'WAITING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1">
                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                        <input 
                        type="text" 
                        placeholder="0000"
                        value={matchRoomIds[m.id] || ''}
                        onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                        />
                    </div>
                )}

                {!isDone && m.teamA && (
                    <Button 
                        onClick={() => startMatchFlow(m.id)}
                        disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                        size="sm"
                        className="h-[30px] text-[8px] px-4"
                    >
                        {isBye ? 'ADVANCE' : 'START'}
                    </Button>
                )}
            </div>
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               {hasQuarterFinals ? 'QUARTERS BO1 . ' : ''}SEMIS BO1 . GRAND FINAL BO3
             </p>
          </div>

          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-8 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-48' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              ))}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                 <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
               </div>
            </div>

            <div className="relative z-20 animate-slide-in">
                 {(() => {
                    const m = grandFinalMatch;
                    const sA = scores[`${m.id}-A`] || 0;
                    const sB = scores[`${m.id}-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = m.teamA && m.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[m.id] || ''}
                                            onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(m.id)}
                                        disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
            </div>
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col justify-center overflow-hidden">

            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamName === activeMatchData.teamA.name ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={wheelState.duration || 5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* TOP CONTROLS */}
                    <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center px-4">
                        <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>

                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>

                        {!isRevealFinished && (
                            <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                        )}
                    </div>

                    {/* Reveal Arena - SPLIT VIEW UI */}
                    <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

                        {/* TEAM TITLES */}
                        <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                            <div className="text-left">
                                <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamA.color }}>
                                    {activeMatchData.teamA.name}
                                </h2>
                                <div className="mt-2 h-1 w-full bg-gradient-to-r from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamA.color }}></div>
                            </div>
                            <div className="text-right">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamB.color }}>
                                            {activeMatchData.teamB.name}
                                        </h2>
                                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamB.color }}></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        {/* VS INDICATOR */}
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                            <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                        </div>

                        <div className="space-y-4 relative z-10">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', role, activeMatchData!.teamA)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', role, activeMatchData!.teamB) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom Controls */}
                    <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                       <div className="pointer-events-auto">
                           {!isRevealFinished ? (
                                <button 
                                    onClick={handleNextReveal}
                                    className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                                >
                                    {currentRoleIdx === -1 ? 'START DRAFT' : 'REVEAL NEXT UNIT'}
                                </button>
                           ) : (
                                <Button onClick={proceedFromReveal} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                                    {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                                </Button>
                           )}
                       </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

