type ViewMode = 'lobby' | 'match' | 'battle' | 'bracket';

// Persistence Keys
const STORAGE_KEY_PLAYERS = 'hok_roster_data_v2';
const STORAGE_KEY_HISTORY = 'hok_match_history_v2';

export default function App() {
  const [viewMode, setViewMode] = useState<ViewMode>('lobby');

  // Initialize from LocalStorage or Hash
  const [players, setPlayers] = useState<Player[]>(() => {
    try {
      if (window.location.hash && window.location.hash.length > 1) {
        const hashData = window.location.hash.substring(1);
        const decoded = JSON.parse(atob(hashData));
        if (Array.isArray(decoded)) return decoded;
      }

      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.warn("Failed to load players from storage/hash", e);
      // Fallback to local storage if hash fails
      const saved = localStorage.getItem(STORAGE_KEY_PLAYERS);
      return saved ? JSON.parse(saved) : [];
    }
  });

  const [matchHistory, setMatchHistory] = useState<MatchHistoryEntry[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY_HISTORY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [currentMatch, setCurrentMatch] = useState<MatchResult | null>(null);
  const [bracketMatch, setBracketMatch] = useState<BracketMatchResult | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [roomId, setRoomId] = useState<string>('');
  const [isCoachMode, setIsCoachMode] = useState(false);
  const [isBracketMode, setIsBracketMode] = useState(false);
  const [numBracketTeams, setNumBracketTeams] = useState(4);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [editingPlayer, setEditingPlayer] = useState<Player | null>(null);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);

  // Confirmation Modal State
  const [confirmState, setConfirmState] = useState<{
    isOpen: boolean;
    title: string;
    message: string;
    onConfirm: () => void;
    isDestructive?: boolean;
  }>({
    isOpen: false,
    title: '',
    message: '',
    onConfirm: () => {},
  });

  // Sync Players to LocalStorage & URL Hash
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PLAYERS, JSON.stringify(players));

    try {
      // Create a compact version of state for hashing to avoid URL length limits
      const compactData = players.map(p => ({
        id: p.id,
        name: p.name,
        roles: p.roles,
        isAllRoles: p.isAllRoles,
        isActive: p.isActive,
        stats: p.stats
      }));
      const hash = btoa(JSON.stringify(compactData));
      if (hash.length < 2000) {
         window.history.replaceState(null, '', `#${hash}`);
      }
    } catch (e) {}
  }, [players]);

  // Sync History to LocalStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_HISTORY, JSON.stringify(matchHistory));
  }, [matchHistory]);

  const navigate = useCallback((mode: ViewMode, data: any) => {
    setViewMode(mode);
    if (mode === 'lobby' && Array.isArray(data)) setPlayers(data);
    else if ((mode === 'match' || mode === 'battle') && data) setCurrentMatch(data);
    else if (mode === 'bracket' && data) setBracketMatch(data);
  }, []);

  const handleBatchProcess = (batchData: { name: string; roles: Role[]; isAllRoles: boolean; action?: 'add' | 'bench' }[]) => {
    setPlayers(prev => {
      let updatedPlayers = [...prev];
      batchData.forEach(item => {
        const normalizedName = item.name.trim().toLowerCase();
        const existingIndex = updatedPlayers.findIndex(p => p.name.trim().toLowerCase() === normalizedName);
        if (item.action === 'bench') {
           if (existingIndex !== -1) updatedPlayers[existingIndex] = { ...updatedPlayers[existingIndex], isActive: false };
        } else {
           if (existingIndex !== -1) {
              updatedPlayers[existingIndex] = { 
                ...updatedPlayers[existingIndex], 
                roles: item.roles, 
                isAllRoles: item.isAllRoles, 
                isActive: true 
              };
           } else {
              updatedPlayers.push({
                 id: crypto.randomUUID(),
                 name: item.name,
                 roles: item.roles,
                 isAllRoles: item.isAllRoles,
                 isActive: true,
                 isLastMatchMvp: false,
                 stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
              });
           }
        }
      });
      return updatedPlayers;
    });
    setErrorMsg(null);
  };

  const removePlayer = (id: string) => setPlayers(prev => prev.filter(p => p.id !== id));
  const togglePlayerActive = (id: string) => setPlayers(prev => prev.map(p => p.id === id ? { ...p, isActive: !p.isActive } : p));
  const handleEditPlayer = (player: Player) => { setEditingPlayer(player); setIsEditModalOpen(true); };
  const handleUpdatePlayer = (updatedPlayer: Player) => setPlayers(prev => prev.map(p => p.id === updatedPlayer.id ? updatedPlayer : p));
  const activePlayers = players.filter(p => p.isActive);

  const handleGenerate = () => {
    // Only validate global Room ID if NOT in Bracket Mode
    if (!isBracketMode) {
      if (!roomId.trim() || roomId.length < 4) { 
        setErrorMsg("Please enter a valid 4-digit Room ID."); 
        return; 
      }
    }

    if (isBracketMode) {
      const required = numBracketTeams * 5;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players for ${numBracketTeams} teams. Current: ${activePlayers.length}`); return; }
      const result = generateBracketMatch(activePlayers, roomId, numBracketTeams);
      if (result) { setBracketMatch(result); setErrorMsg(null); setViewMode('bracket'); }
      else { setErrorMsg("Failed to find valid composition."); }
    } else {
      const required = isCoachMode ? 12 : 10;
      if (activePlayers.length < required) { setErrorMsg(`Need ${required} ACTIVE players. Current: ${activePlayers.length}`); return; }
      const result = generateMatch(activePlayers, roomId, isCoachMode);
      if (result) { setCurrentMatch(result); setErrorMsg(null); navigate('match', result); }
      else { setErrorMsg("Failed to find valid composition."); }
    }
  };

  const handleClearAll = () => {
    setConfirmState({
      isOpen: true,
      title: "CLEAR ROSTER",
      message: "This will permanently delete ALL players from your squad list. Are you sure you want to proceed?",
      isDestructive: true,
      onConfirm: () => setPlayers([]),
    });
  };

  const handleRerollSlot = (team: 'azure' | 'crimson', role: Role, newPlayer: Player) => {
    if (!currentMatch) return;
    const updatedMatch = {
        ...currentMatch,
        azureTeam: currentMatch.azureTeam.map(slot => (team === 'azure' && slot.role === role) ? { ...slot, player: newPlayer } : slot),
        crimsonTeam: currentMatch.crimsonTeam.map(slot => (team === 'crimson' && slot.role === role) ? { ...slot, player: newPlayer } : slot)
    };
    setCurrentMatch(updatedMatch); navigate('match', updatedMatch);
  };

  const handleBracketReroll = (teamIndex: number, role: Role, newPlayer: Player) => {
    if (!bracketMatch) return;
    const updatedTeams = bracketMatch.teams.map((team, idx) => {
        if (idx === teamIndex) {
            return {
                ...team,
                slots: team.slots.map(slot => slot.role === role ? { ...slot, player: newPlayer } : slot)
            };
        }
        return team;
    });
    setBracketMatch({ ...bracketMatch, teams: updatedTeams });
  };

  const handleMatchFinish = (winner: 'azure' | 'crimson' | null, mvpId?: string, ratings?: Record<string, number>) => {
    if (!currentMatch) return;
    const historyEntry = { ...currentMatch, id: crypto.randomUUID(), winningTeam: winner, mvpId, ratings };
    setMatchHistory(prev => [historyEntry, ...prev]);

    const azureIds = new Set(currentMatch.azureTeam.map(slot => slot.player.id));
    const crimsonIds = new Set(currentMatch.crimsonTeam.map(slot => slot.player.id));
    const allMatchIds = new Set([...azureIds, ...crimsonIds]);

    const updatedPlayers = players.map(p => {
      let isLastMatchMvp = mvpId === p.id;
      if (!allMatchIds.has(p.id)) return { ...p, isLastMatchMvp: false };

      const isAzure = azureIds.has(p.id);
      const isWinner = winner && ((isAzure && winner === 'azure') || (!isAzure && winner === 'crimson'));
      const newStats = { ...p.stats, matchesPlayed: p.stats.matchesPlayed + 1 };

      if (winner) {
        if (isWinner) {
           newStats.wins += 1; newStats.currentStreak += 1;
           if (newStats.currentStreak > newStats.maxStreak) newStats.maxStreak = newStats.currentStreak;
        } else { newStats.currentStreak = 0; }
      }

      return { 
        ...p, 
        stats: newStats, 
        isLastMatchMvp, 
        lastMatchRating: ratings?.[p.id] || 0 
      };
    });

    setPlayers(updatedPlayers); 
    navigate('lobby', updatedPlayers);
    setCurrentMatch(null); 
    setRoomId('');
  };

  const quickFill = () => {
     const shuffledHeroes = [...HOK_HEROES].sort(() => 0.5 - Math.random());
     const batchData = shuffledHeroes.slice(0, 15).map(hero => ({ name: hero.name, roles: hero.roles, isAllRoles: false, action: 'add' as const }));
     for(let i=0; i<5; i++) batchData.push({ name: `Flex Player ${i+1}`, roles: [], isAllRoles: true, action: 'add' });
     if (isCoachMode) {
        batchData.push({ name: "Coach Gemik", roles: [Role.COACH], isAllRoles: false, action: 'add' });
        batchData.push({ name: "Coach KPL", roles: [Role.COACH], isAllRoles: false, action: 'add' });
     }
     handleBatchProcess(batchData);
  };

  const handleClearHistory = () => {
    setConfirmState({
      isOpen: true,
      title: "ERASE HISTORY",
      message: "This will permanently delete all recorded battle logs. This action cannot be undone.",
      isDestructive: true,
      onConfirm: () => setMatchHistory([]),
    });
  };

  const isRoomReady = roomId.length === 4;

  const copyShareLink = () => {
    navigator.clipboard.writeText(window.location.href);
    alert("Share link copied to clipboard!");
  };

  return (
    <div className="min-h-screen text-slate-200 font-inter overflow-x-hidden relative flex flex-col">
      <BackgroundParticles />
      <LocalClock />

      <ConfirmModal 
        isOpen={confirmState.isOpen}
        title={confirmState.title}
        message={confirmState.message}
        onConfirm={confirmState.onConfirm}
        onCancel={() => setConfirmState(prev => ({ ...prev, isOpen: false }))}
        isDestructive={confirmState.isDestructive}
      />

      <div className="fixed inset-0 bg-black -z-10">
         <img src="https://www.levelinfinite.com/wp-content/uploads/2024/03/honor-of-kings-global-launch-pc.jpg" alt="HoK" className="absolute inset-0 w-full h-full object-cover opacity-50" />
         <div className="absolute inset-0 bg-gradient-to-b from-[#05090f]/90 via-[#05090f]/60 to-[#05090f] mix-blend-multiply"></div>
      </div>

      {editingPlayer && <EditPlayerModal player={editingPlayer} isOpen={isEditModalOpen} onClose={() => setIsEditModalOpen(false)} onSave={handleUpdatePlayer} />}

      {viewMode === 'lobby' && (
        <>
          <main className="relative z-10 pt-16 px-4 flex-grow max-w-7xl mx-auto w-full">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className={`lg:col-span-4 space-y-6 ${isSidebarOpen ? '' : 'hidden'}`}>

                {/* INTEGRATED ROOM ID CARD */}
                {isBracketMode ? (
                  // MINIMIZED BATTLE ROOM FOR BRACKET MODE
                  <div className="relative group opacity-80">
                    <div className="absolute -inset-[1px] bg-gradient-to-b from-white/10 to-transparent clip-corner-sm opacity-20"></div>
                    <div className="bg-[#0a1a2f]/60 backdrop-blur-sm p-4 clip-corner-sm border border-[#1e3a5f] relative">
                       <div className="flex justify-between items-center">
                          <div className="flex items-center gap-2">
                             <div className="w-1.5 h-1.5 bg-gray-500 rounded-full"></div>
                             <h3 className="text-xs text-[#8a9db8] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room</h3>
                          </div>
                          <span className="text-[9px] px-2 py-0.5 border border-white/10 rounded text-white/40 font-bold">AUTO-ASSIGN</span>
                       </div>
                       <div className="mt-2 text-[10px] text-[#4a5f78] font-orbitron tracking-wide leading-tight">
                          Room IDs will be assigned individually per match within the Bracket View.
                       </div>
                    </div>
                  </div>
                ) : (
                  // STANDARD BATTLE ROOM CARD
                  <div className="relative group">
                    <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                    <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative overflow-hidden">
                      <div className="flex items-center justify-between mb-4 border-b border-[#dcb06b]/20 pb-2">
                        <h3 className="text-sm text-[#dcb06b] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room</h3>
                        <span className={`text-[10px] font-orbitron font-bold transition-colors duration-300 ${isRoomReady ? 'text-green-500' : 'text-red-500'}`}>
                          LOBBY STATUS: {isRoomReady ? 'READY' : 'NOT READY'}
                        </span>
                      </div>

                      <div className="relative">
                        <input 
                          type="text" 
                          value={roomId} 
                          onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} 
                          placeholder="0000" 
                          className={`relative z-10 bg-black/40 border border-[#1e3a5f] p-4 text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 clip-corner-sm
                            ${roomId ? 'text-white border-[#dcb06b] shadow-[0_0_15px_rgba(220,176,107,0.2)] animate-[chromatic_0.2s_infinite]' : 'text-[#4a5f78] opacity-60'}
                            placeholder-[#1e3a5f]`}
                        />
                      </div>
                    </div>
                  </div>
                )}

                <div className="grid grid-cols-1 gap-3">
                  {/* COACH MODE BUTTON */}
                  {!isBracketMode && (
                    <button 
                      onClick={() => setIsCoachMode(!isCoachMode)}
                      className="relative w-full group overflow-hidden p-[3px] clip-corner-sm transition-all duration-300 transform hover:scale-[1.01] active:scale-[0.98]"
                    >
                      {isCoachMode && (
                        <div className="absolute inset-[-100%] transition-opacity duration-700">
                            <div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,#dcb06b_60deg,#f3dcb1_120deg,transparent_180deg,#dcb06b_240deg,#f3dcb1_300deg,transparent_360deg)] animate-[spin_3s_linear_infinite]"></div>
                        </div>
                      )}
                      <div className={`
                          relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border
                          ${isCoachMode 
                              ? 'bg-black text-[#dcb06b] border-transparent shadow-[inset_0_0_20px_rgba(220,176,107,0.5)]' 
                              : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}
                      `}>
                          <span className={`font-cinzel font-black text-xs tracking-[0.3em] uppercase transition-all duration-500 ${isCoachMode ? 'text-white drop-shadow-[0_0_10px_#dcb06b]' : ''}`}>
                            COACH MODE {isCoachMode ? 'ENABLED' : 'DISABLED'}
                          </span>
                      </div>
                    </button>
                  )}

                  {/* BRACKET MODE BUTTON - WHITE THEME */}
                  <button 
                    onClick={() => { setIsBracketMode(!isBracketMode); if(!isBracketMode) setIsCoachMode(false); }}
                    className="relative w-full group overflow-hidden p-[3px] clip-corner-sm transition-all duration-300 transform hover:scale-[1.01] active:scale-[0.98]"
                  >
                     {isBracketMode && (
                       <div className="absolute inset-[-100%] transition-opacity duration-700">
                          <div className="absolute inset-0 bg-[conic-gradient(from_0deg,transparent_0deg,#ffffff_60deg,#e2e8f0_120deg,transparent_180deg,#ffffff_240deg,#e2e8f0_300deg,transparent_360deg)] animate-[spin_3s_linear_infinite]"></div>
                       </div>
                     )}
                     <div className={`
                        relative z-10 py-4 px-6 flex items-center justify-center transition-all duration-300 clip-corner-sm border
                        ${isBracketMode 
                            ? 'bg-black text-white border-transparent shadow-[inset_0_0_20px_rgba(255,255,255,0.4)]' 
                            : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}
                     `}>
                        <span className={`font-cinzel font-black text-xs tracking-[0.3em] uppercase transition-all duration-500 ${isBracketMode ? 'text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.8)]' : ''}`}>
                           BRACKET MODE {isBracketMode ? 'ENABLED' : 'DISABLED'}
                        </span>
                     </div>
                  </button>

                  {/* BRACKET TEAM SELECTOR */}
                  {isBracketMode && (
                    <div className="relative animate-slide-in">
                       <div className="bg-[#0a1a2f]/80 border border-[#dcb06b]/30 p-4 clip-corner-sm">
                          <div className="text-[10px] text-[#8a9db8] font-black uppercase tracking-widest mb-3 flex justify-between">
                            <span>Number of Teams</span>
                            <span className="text-white font-orbitron">{numBracketTeams} TEAMS</span>
                          </div>
                          <div className="flex gap-1">
                            {[3, 4, 5, 6, 7, 8].map(n => (
                              <button 
                                key={n}
                                onClick={() => setNumBracketTeams(n)}
                                className={`flex-1 py-2 font-orbitron font-bold text-xs clip-corner-sm border transition-all ${numBracketTeams === n ? 'bg-[#dcb06b] text-black border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-black/40 text-[#4a5f78] border-[#1e3a5f]'}`}
                              >
                                {n}
                              </button>
                            ))}
                          </div>
                          <div className="mt-2 text-[8px] text-[#4a5f78] uppercase text-center font-bold tracking-widest">Requires {numBracketTeams * 5} active players</div>
                       </div>
                    </div>
                  )}
                </div>

                <PlayerForm onBatchProcess={handleBatchProcess} isCoachMode={isCoachMode} />

                <div className="relative group">
                  <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                  <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative">
                     <div className="flex justify-between items-end mb-6">
                        <div>
                           <div className="text-[#8a9db8] text-[10px] uppercase font-bold mb-1">Active Players</div>
                           <div className="flex items-baseline gap-2">
                              <div className="text-5xl font-orbitron font-bold text-white">{activePlayers.length}</div>
                              <div className="text-xl font-orbitron font-bold text-[#4a5f78]">/ {players.length}</div>
                           </div>
                        </div>
                        <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-3 py-1 hover:bg-[#dcb06b] hover:text-black transition-colors">Quick Fill</button>
                     </div>
                     {errorMsg && <div className="mb-4 p-3 border-l-2 border-red-500 bg-red-900/20 text-red-200 text-xs">{errorMsg}</div>}
                     <Button 
                        onClick={handleGenerate} 
                        className="w-full" 
                        disabled={activePlayers.length < (isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)) || (!isBracketMode && !isRoomReady)}
                     >
                        START MATCHMAKING
                     </Button>
                  </div>
                </div>

                {/* SHARE SQUAD LINK */}
                <button 
                  onClick={copyShareLink}
                  className="w-full py-2 px-4 border border-[#dcb06b]/30 text-[#dcb06b]/80 hover:text-[#dcb06b] hover:border-[#dcb06b] transition-all text-[10px] uppercase font-bold tracking-[0.2em] clip-corner-sm flex items-center justify-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                  Share Squad State
                </button>
              </div>

              <div className={`transition-all duration-500 ${isSidebarOpen ? 'lg:col-span-8' : 'lg:col-span-12'}`}>
                 <div className="flex items-center justify-between mb-6">
                    <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 border border-[#1e3a5f] text-[#dcb06b] bg-[#0a1a2f]/50 transition-all">
                       <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" /></svg>
                    </button>
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b]">SQUAD ROSTER</h2>
                    <button onClick={handleClearAll} className="text-xs text-[#4a5f78] hover:text-red-400 uppercase transition-colors">Clear All</button>
                 </div>
                 <div className="tech-border p-6 bg-[#0a1a2f]/40 min-h-[400px]">
                    <PlayerList players={players} onRemove={removePlayer} onToggleActive={togglePlayerActive} onEdit={handleEditPlayer} isSidebarOpen={isSidebarOpen} />
                 </div>
                 <div className="mt-12 tech-border p-6 bg-[#0a1a2f]/40">
                    <h2 className="text-2xl font-cinzel font-black text-[#dcb06b] mb-6">BATTLE HISTORY</h2>
                    <HistoryList history={matchHistory} onClear={handleClearHistory} />
                 </div>
              </div>
            </div>
          </main>

          <footer className="py-12 px-6 text-center border-t border-[#dcb06b]/10 bg-[#05090f] mt-auto">
              <div className="max-w-4xl mx-auto flex flex-col items-center gap-4">
                  <div className="w-12 h-0.5 bg-gradient-to-r from-transparent via-[#dcb06b] to-transparent mb-2"></div>
                  <div className="text-[#dcb06b] font-cinzel font-black text-sm tracking-[0.2em] mb-1">
                      APPLICATION DEVELOPED BY KAZEHUNT
                  </div>
                  <div className="text-[#4a5f78] font-orbitron text-[9px] leading-relaxed tracking-[0.1em] uppercase max-w-2xl flex flex-col gap-2">
                      <p>DESIGNED EXCLUSIVELY FOR HONOR OF KINGS CUSTOM FUN MATCHES ON THE OFFICIAL DISCORD. THE DEVELOPER ASSUMES NO RESPONSIBILITY FOR USAGE OUTSIDE THIS INTENDED SCOPE.</p>
                  </div>
              </div>
          </footer>
        </>
      )}

      {currentMatch && viewMode !== 'lobby' && viewMode !== 'bracket' && (
        <MatchDisplay 
          match={currentMatch} 
          activePlayers={activePlayers} 
          initialMode={viewMode === 'battle' ? 'battle' : 'draft'}
          onReset={() => { setCurrentMatch(null); setViewMode('lobby'); }}
          onCompleteMatch={handleMatchFinish}
          onReroll={handleRerollSlot}
          onStartBattle={() => setViewMode('battle')}
        />
      )}

      {bracketMatch && viewMode === 'bracket' && (
        <BracketDisplay 
          match={bracketMatch} 
          onReset={() => { setBracketMatch(null); setViewMode('lobby'); }} 
          activePlayers={activePlayers}
          onReroll={handleBracketReroll}
        />
      )}

      <style>{`
        @keyframes chromatic {
          0% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
          25% { text-shadow: -2px 0 0 #ff0000, 2px 0 0 #0000ff; }
          50% { text-shadow: 2px -1px 0 #ff0000, -2px 1px 0 #0000ff; }
          75% { text-shadow: -2px 1px 0 #ff0000, 2px -1px 0 #0000ff; }
          100% { text-shadow: 2px 0 0 #ff0000, -2px 0 0 #0000ff; }
        }
      `}</style>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Tournament End State
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);
  const [particles, setParticles] = useState<number[]>([]);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number; // 0 or 1 relative to display (not global)
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // Effect for confetti particles on Tournament End
  useEffect(() => {
    if (phase === 'TOURNAMENT_END') {
       setParticles(Array.from({ length: 50 }).map((_, i) => i));
    }
  }, [phase]);

  // --- DYNAMIC BRACKET GENERATION ---

  const hasQuarterFinals = match.teams.length > 4;

  // Helper to get winner from scores
  const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
    // If it's a ghost match (no team A), no winner
    if (!teamA) return null;

    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // Win Condition
    if (scoreA > scoreB) return teamA;
    if (scoreB > scoreA && teamB) return teamB;

    // Auto-advance if BYE (No Opponent) and score is set (or implicitly 1-0 via auto-advance logic)
    if (!teamB && scoreA > 0) return teamA;

    return null;
  };

  // 1. Generate Quarter Finals (Indices 0-3 if hasQF)
  const quarterMatches: any[] = [];
  if (hasQuarterFinals) {
      for (let i = 0; i < 4; i++) {
          const teamA = match.teams[i * 2] || null;
          const teamB = match.teams[i * 2 + 1] || null;
          quarterMatches.push({
              id: i,
              label: `Quarter ${i + 1}`,
              mode: 'BO1',
              teamA,
              teamB
          });
      }
  }

  // 2. Generate Semi Finals
  const semiMatches: any[] = [];
  if (hasQuarterFinals) {
      const q1 = quarterMatches[0];
      const q2 = quarterMatches[1];
      const q3 = quarterMatches[2];
      const q4 = quarterMatches[3];

      semiMatches.push({
          id: 4,
          label: 'Semi-Final 1',
          mode: 'BO1',
          teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
          teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
      });
      semiMatches.push({
          id: 5,
          label: 'Semi-Final 2',
          mode: 'BO1',
          teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
          teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
      });
  } else {
      for (let i = 0; i < 2; i++) {
          semiMatches.push({
              id: i,
              label: `Semi-Final ${i + 1}`,
              mode: 'BO1',
              teamA: match.teams[i * 2] || null,
              teamB: match.teams[i * 2 + 1] || null
          });
      }
  }

  // 3. Generate Grand Final
  const gfIndex = hasQuarterFinals ? 6 : 2;
  const s1 = semiMatches[0];
  const s2 = semiMatches[1];

  const grandFinalMatch = {
      id: gfIndex,
      label: 'Grand Final',
      mode: 'BO3',
      teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
      teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
  };

  const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === gfIndex) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      type: 'reveal',
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates,
      duration: Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000
    });
  };

  const handleRerollClick = (teamSide: 'A' | 'B', role: Role, teamData: any) => {
    // 1. Identify Global Team Index
    const globalTeamIdx = match.teams.findIndex(t => t.name === teamData.name);
    if (globalTeamIdx === -1) return;

    // 2. Determine Bench Players (Active players NOT currently assigned to ANY bracket team)
    const assignedIds = new Set(match.teams.flatMap(t => t.slots.map(s => s.player.id)));
    const benchPlayers = activePlayers.filter(p => !assignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    // 3. Filter candidates for the role
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const candidateNames = candidates.map(p => p.name);

    // 4. Auto-swap if only 1 candidate, else wheel
    if (candidates.length === 1) {
        onReroll(globalTeamIdx, role, candidates[0]);
        // Trigger visual flash
        const slotId = getSlotId(currentMatchIdx, teamSide, role);
        setAutoFillFlash(slotId);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000;

    setWheelState({
        isOpen: true,
        type: 'reroll',
        teamName: teamData.name,
        teamIndex: teamSide === 'A' ? 0 : 1,
        globalTeamIndex: globalTeamIdx,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;

    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < gfIndex) {
         setPhase('OVERVIEW');
     } else {
         if (newScoreA >= 2 || newScoreB >= 2) {
             // SERIES WON! Set Tournament Champion
             const winnerTeam = newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB;
             setTournamentChampion(winnerTeam);
             setPhase('TOURNAMENT_END');
         } else {
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  // New Reroll-Compatible Card Renderer
  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const isAutoFilled = autoFillFlash === id;

    // Theme Construction based on Team Color or Default A/B
    const baseColor = teamData.color || (teamSide === 'A' ? '#00d2ff' : '#ef4444');

    // Inline styles for dynamic team colors
    const cardStyle = {
        borderColor: isAutoFilled ? '#dcb06b' : baseColor,
        boxShadow: isAutoFilled ? `0 0 30px #dcb06b` : (isRevealed ? `0 0 15px ${baseColor}` : 'none')
    };
    const textStyle = { color: isAutoFilled ? '#dcb06b' : (isRevealed ? baseColor : '#4a5f78') };

    if (!isRevealed) {
        return (
            <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
                <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
                    {RoleIcons[role]}
                </div>
            </div>
        );
    }

    return (
        <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
            <div 
                className={`absolute inset-0 clip-corner-md border-l-4 tilt-card bg-[#0a1a2f] border transition-all duration-300 shadow-[0_0_20px_rgba(0,0,0,0.6)]`}
                style={cardStyle}
            >
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'B' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className="mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 scale-[0.8] opacity-90" style={textStyle}>
                        {RoleIcons[role]}
                    </div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                        {slot?.player.name}
                    </span>
                    <div 
                        className="absolute inset-0 opacity-20 pointer-events-none"
                        style={{ background: `linear-gradient(${teamSide === 'B' ? 'to left' : 'to right'}, ${baseColor}, transparent)` }}
                    ></div>
                </div>

                {/* REROLL BUTTON */}
                <button 
                    onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role, teamData); }}
                    className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'A' ? 'right-4' : 'left-4'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                </button>
            </div>
        </div>
    );
  };

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[170px] opacity-10 border border-dashed border-white/20 clip-corner-sm flex items-center justify-center">
                  <span className="font-orbitron text-[10px] uppercase">No Match</span>
              </div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;

      return (
        <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                <div className="flex gap-2">
                    {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                    <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                </div>
            </div>

            <div className="space-y-2">
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamA ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>

                <div className="flex justify-center h-4 items-center">
                   <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                </div>

                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamB ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB.name}</span>
                        <span className="font-orbitron font-bold text-white">{sB}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>
            </div>

            <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1">
                        <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                        <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">
                            {isGhostA ? 'WAITING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1">
                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                        <input 
                        type="text" 
                        placeholder="0000"
                        value={matchRoomIds[m.id] || ''}
                        onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                        />
                    </div>
                )}

                {!isDone && m.teamA && (
                    <Button 
                        onClick={() => startMatchFlow(m.id)}
                        disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                        size="sm"
                        className="h-[30px] text-[8px] px-4"
                    >
                        {isBye ? 'ADVANCE' : 'START'}
                    </Button>
                )}
            </div>
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  // *** NEW: Tournament End Screen ***
  if (phase === 'TOURNAMENT_END' && tournamentChampion) {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] animate-slide-in overflow-hidden">
            {/* Background Effects */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] z-0"></div>
            <div className="god-rays opacity-20"></div>

            {/* Confetti */}
            {particles.map(i => (
                <div 
                    key={i} 
                    className="confetti-piece"
                    style={{
                    left: `${Math.random() * 100}%`,
                    animationDelay: `${Math.random() * 2}s`,
                    backgroundColor: Math.random() > 0.5 ? '#dcb06b' : tournamentChampion.color
                    }}
                ></div>
            ))}

            <div className="relative z-10 flex flex-col items-center w-full max-w-6xl px-4">
                <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">
                    GRAND FINAL WINNER
                </h3>

                <h1 className="text-4xl md:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-8 tracking-wider">
                    TOURNAMENT CHAMPION
                </h1>

                <div className="relative mb-12 transform hover:scale-105 transition-transform duration-500">
                    <div className="absolute inset-0 bg-white/10 blur-[50px]"></div>
                    <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 py-6 clip-corner-md shadow-[0_0_50px_rgba(220,176,107,0.3)]">
                        <h2 className="text-5xl md:text-6xl font-black font-cinzel text-white tracking-[0.2em] uppercase" style={{ color: tournamentChampion.color, textShadow: `0 0 20px ${tournamentChampion.color}` }}>
                            {tournamentChampion.name}
                        </h2>
                    </div>
                </div>

                {/* Winning Roster */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-16">
                    {ROLES_ORDER.map((role, idx) => {
                        const slot = tournamentChampion.slots.find((s: TeamSlot) => s.role === role);
                        return (
                            <div 
                                key={role} 
                                className="flex flex-col items-center p-4 bg-black/40 border border-white/10 clip-corner-sm backdrop-blur-sm animate-slide-in"
                                style={{ animationDelay: `${idx * 100}ms` }}
                            >
                                <div className="text-[#dcb06b] mb-2 opacity-80 scale-75">
                                    {RoleIcons[role]}
                                </div>
                                <span className="text-white font-orbitron font-bold text-sm tracking-wide">
                                    {slot?.player.name}
                                </span>
                            </div>
                        );
                    })}
                </div>

                <Button onClick={onReset} size="lg" className="px-16 py-5 text-xl shadow-[0_0_30px_#dcb06b] animate-pulse">
                    RETURN TO LOBBY
                </Button>
            </div>
        </div>
      );
  }

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               {hasQuarterFinals ? 'QUARTERS BO1 . ' : ''}SEMIS BO1 . GRAND FINAL BO3
             </p>
          </div>

          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-8 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-48' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                </div>
              ))}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                 <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
               </div>
            </div>

            <div className="relative z-20 animate-slide-in">
                 {(() => {
                    const m = grandFinalMatch;
                    const sA = scores[`${m.id}-A`] || 0;
                    const sB = scores[`${m.id}-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = m.teamA && m.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[m.id] || ''}
                                            onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(m.id)}
                                        disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
            </div>
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col justify-center overflow-hidden">

            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamName === activeMatchData.teamA.name ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={wheelState.duration || 5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* TOP CONTROLS */}
                    <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center px-4">
                        <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>

                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>

                        {!isRevealFinished && (
                            <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                        )}
                    </div>

                    {/* Reveal Arena - SPLIT VIEW UI */}
                    <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

                        {/* TEAM TITLES */}
                        <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                            <div className="text-left">
                                <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamA.color }}>
                                    {activeMatchData.teamA.name}
                                </h2>
                                <div className="mt-2 h-1 w-full bg-gradient-to-r from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamA.color }}></div>
                            </div>
                            <div className="text-right">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamB.color }}>
                                            {activeMatchData.teamB.name}
                                        </h2>
                                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamB.color }}></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        {/* VS INDICATOR */}
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                            <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                        </div>

                        <div className="space-y-4 relative z-10">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', role, activeMatchData!.teamA)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', role, activeMatchData!.teamB) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom Controls */}
                    <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                       <div className="pointer-events-auto">
                           {!isRevealFinished ? (
                                <button 
                                    onClick={handleNextReveal}
                                    className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                                >
                                    {currentRoleIdx === -1 ? 'START DRAFT' : 'REVEAL NEXT UNIT'}
                                </button>
                           ) : (
                                <Button onClick={proceedFromReveal} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                                    {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                                </Button>
                           )}
                       </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Tournament End State
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);
  const [particles, setParticles] = useState<number[]>([]);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number; // 0 or 1 relative to display (not global)
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // Effect for confetti particles on Tournament End
  useEffect(() => {
    if (phase === 'TOURNAMENT_END') {
       setParticles(Array.from({ length: 50 }).map((_, i) => i));
    }
  }, [phase]);

  // --- DYNAMIC BRACKET GENERATION ---

  const hasQuarterFinals = match.teams.length > 4;

  // Helper to get winner from scores
  const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
    // If it's a ghost match (no team A), no winner
    if (!teamA) return null;

    const scoreA = scores[`${matchIdx}-A`] || 0;
    const scoreB = scores[`${matchIdx}-B`] || 0;

    // Win Condition
    if (scoreA > scoreB) return teamA;
    if (scoreB > scoreA && teamB) return teamB;

    // Auto-advance if BYE (No Opponent) and score is set (or implicitly 1-0 via auto-advance logic)
    if (!teamB && scoreA > 0) return teamA;

    return null;
  };

  // 1. Generate Quarter Finals (Indices 0-3 if hasQF)
  const quarterMatches: any[] = [];
  if (hasQuarterFinals) {
      for (let i = 0; i < 4; i++) {
          const teamA = match.teams[i * 2] || null;
          const teamB = match.teams[i * 2 + 1] || null;
          quarterMatches.push({
              id: i,
              label: `Quarter ${i + 1}`,
              mode: 'BO1',
              teamA,
              teamB
          });
      }
  }

  // 2. Generate Semi Finals
  const semiMatches: any[] = [];
  if (hasQuarterFinals) {
      const q1 = quarterMatches[0];
      const q2 = quarterMatches[1];
      const q3 = quarterMatches[2];
      const q4 = quarterMatches[3];

      semiMatches.push({
          id: 4,
          label: 'Semi-Final 1',
          mode: 'BO1',
          teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
          teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
      });
      semiMatches.push({
          id: 5,
          label: 'Semi-Final 2',
          mode: 'BO1',
          teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
          teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
      });
  } else {
      for (let i = 0; i < 2; i++) {
          semiMatches.push({
              id: i,
              label: `Semi-Final ${i + 1}`,
              mode: 'BO1',
              teamA: match.teams[i * 2] || null,
              teamB: match.teams[i * 2 + 1] || null
          });
      }
  }

  // 3. Generate Grand Final
  const gfIndex = hasQuarterFinals ? 6 : 2;
  const s1 = semiMatches[0];
  const s2 = semiMatches[1];

  const grandFinalMatch = {
      id: gfIndex,
      label: 'Grand Final',
      mode: 'BO3',
      teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
      teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
  };

  const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === gfIndex) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      type: 'reveal',
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates,
      duration: Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000
    });
  };

  const handleRerollClick = (teamSide: 'A' | 'B', role: Role, teamData: any) => {
    // 1. Identify Global Team Index
    const globalTeamIdx = match.teams.findIndex(t => t.name === teamData.name);
    if (globalTeamIdx === -1) return;

    // 2. Determine Bench Players (Active players NOT currently assigned to ANY bracket team)
    const assignedIds = new Set(match.teams.flatMap(t => t.slots.map(s => s.player.id)));
    const benchPlayers = activePlayers.filter(p => !assignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    // 3. Filter candidates for the role
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const candidateNames = candidates.map(p => p.name);

    // 4. Auto-swap if only 1 candidate, else wheel
    if (candidates.length === 1) {
        onReroll(globalTeamIdx, role, candidates[0]);
        // Trigger visual flash
        const slotId = getSlotId(currentMatchIdx, teamSide, role);
        setAutoFillFlash(slotId);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000;

    setWheelState({
        isOpen: true,
        type: 'reroll',
        teamName: teamData.name,
        teamIndex: teamSide === 'A' ? 0 : 1,
        globalTeamIndex: globalTeamIdx,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;

    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < gfIndex) {
         setPhase('OVERVIEW');
     } else {
         if (newScoreA >= 2 || newScoreB >= 2) {
             // SERIES WON! Set Tournament Champion
             const winnerTeam = newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB;
             setTournamentChampion(winnerTeam);
             setPhase('TOURNAMENT_END');
         } else {
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  // New Reroll-Compatible Card Renderer
  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const isAutoFilled = autoFillFlash === id;

    // Theme Construction based on Team Color or Default A/B
    const baseColor = teamData.color || (teamSide === 'A' ? '#00d2ff' : '#ef4444');

    // Inline styles for dynamic team colors
    const cardStyle = {
        borderColor: isAutoFilled ? '#dcb06b' : baseColor,
        boxShadow: isAutoFilled ? `0 0 30px #dcb06b` : (isRevealed ? `0 0 15px ${baseColor}` : 'none')
    };
    const textStyle = { color: isAutoFilled ? '#dcb06b' : (isRevealed ? baseColor : '#4a5f78') };

    if (!isRevealed) {
        return (
            <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
                <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
                    {RoleIcons[role]}
                </div>
            </div>
        );
    }

    return (
        <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
            <div 
                className={`absolute inset-0 clip-corner-md border-l-4 tilt-card bg-[#0a1a2f] border transition-all duration-300 shadow-[0_0_20px_rgba(0,0,0,0.6)]`}
                style={cardStyle}
            >
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'B' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className="mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 scale-[0.8] opacity-90" style={textStyle}>
                        {RoleIcons[role]}
                    </div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                        {slot?.player.name}
                    </span>
                    <div 
                        className="absolute inset-0 opacity-20 pointer-events-none"
                        style={{ background: `linear-gradient(${teamSide === 'B' ? 'to left' : 'to right'}, ${baseColor}, transparent)` }}
                    ></div>
                </div>

                {/* REROLL BUTTON */}
                <button 
                    onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role, teamData); }}
                    className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'A' ? 'right-4' : 'left-4'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                </button>
            </div>
        </div>
    );
  };

  const renderBracketMatchCard = (m: any) => {
      // FIX: Hide card if it's a ghost match (no teams), preserving space
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[170px] invisible"></div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;

      return (
        <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                <div className="flex gap-2">
                    {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                    <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                </div>
            </div>

            <div className="space-y-2">
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamA ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>

                <div className="flex justify-center h-4 items-center">
                   <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                </div>

                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamB ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB.name}</span>
                        <span className="font-orbitron font-bold text-white">{sB}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>
            </div>

            <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1">
                        <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                        <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">
                            {isGhostA ? 'WAITING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1">
                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                        <input 
                        type="text" 
                        placeholder="0000"
                        value={matchRoomIds[m.id] || ''}
                        onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                        />
                    </div>
                )}

                {!isDone && m.teamA && (
                    <Button 
                        onClick={() => startMatchFlow(m.id)}
                        disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                        size="sm"
                        className="h-[30px] text-[8px] px-4"
                    >
                        {isBye ? 'ADVANCE' : 'START'}
                    </Button>
                )}
            </div>
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  // *** NEW: Tournament End Screen ***
  if (phase === 'TOURNAMENT_END' && tournamentChampion) {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] animate-slide-in overflow-hidden">
            {/* Background Effects */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] z-0"></div>
            <div className="god-rays opacity-20"></div>

            {/* Confetti */}
            {particles.map(i => (
                <div 
                    key={i} 
                    className="confetti-piece"
                    style={{
                    left: `${Math.random() * 100}%`,
                    animationDelay: `${Math.random() * 2}s`,
                    backgroundColor: Math.random() > 0.5 ? '#dcb06b' : tournamentChampion.color
                    }}
                ></div>
            ))}

            <div className="relative z-10 flex flex-col items-center w-full max-w-6xl px-4">
                <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">
                    GRAND FINAL WINNER
                </h3>

                <h1 className="text-4xl md:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-8 tracking-wider">
                    TOURNAMENT CHAMPION
                </h1>

                <div className="relative mb-12 transform hover:scale-105 transition-transform duration-500">
                    <div className="absolute inset-0 bg-white/10 blur-[50px]"></div>
                    <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 py-6 clip-corner-md shadow-[0_0_50px_rgba(220,176,107,0.3)]">
                        <h2 className="text-5xl md:text-6xl font-black font-cinzel text-white tracking-[0.2em] uppercase" style={{ color: tournamentChampion.color, textShadow: `0 0 20px ${tournamentChampion.color}` }}>
                            {tournamentChampion.name}
                        </h2>
                    </div>
                </div>

                {/* Winning Roster */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-16">
                    {ROLES_ORDER.map((role, idx) => {
                        const slot = tournamentChampion.slots.find((s: TeamSlot) => s.role === role);
                        return (
                            <div 
                                key={role} 
                                className="flex flex-col items-center p-4 bg-black/40 border border-white/10 clip-corner-sm backdrop-blur-sm animate-slide-in"
                                style={{ animationDelay: `${idx * 100}ms` }}
                            >
                                <div className="text-[#dcb06b] mb-2 opacity-80 scale-75">
                                    {RoleIcons[role]}
                                </div>
                                <span className="text-white font-orbitron font-bold text-sm tracking-wide">
                                    {slot?.player.name}
                                </span>
                            </div>
                        );
                    })}
                </div>

                <Button onClick={onReset} size="lg" className="px-16 py-5 text-xl shadow-[0_0_30px_#dcb06b] animate-pulse">
                    RETURN TO LOBBY
                </Button>
            </div>
        </div>
      );
  }

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               {hasQuarterFinals ? 'QUARTERS BO1 . ' : ''}SEMIS BO1 . GRAND FINAL BO3
             </p>
          </div>

          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-8 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            {/* FIX: Only show connector if match exists */}
                            {(m.teamA || m.teamB) && (
                                <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-48' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  {/* FIX: Only show connector if match exists */}
                  {(m.teamA || m.teamB) && (
                      <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                  )}
                </div>
              ))}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                 <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
               </div>
            </div>

            <div className="relative z-20 animate-slide-in">
                 {(() => {
                    const m = grandFinalMatch;
                    const sA = scores[`${m.id}-A`] || 0;
                    const sB = scores[`${m.id}-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = m.teamA && m.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[m.id] || ''}
                                            onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(m.id)}
                                        disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
            </div>
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col justify-center overflow-hidden">

            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamName === activeMatchData.teamA.name ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={wheelState.duration || 5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* TOP CONTROLS */}
                    <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center px-4">
                        <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>

                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>

                        {!isRevealFinished && (
                            <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                        )}
                    </div>

                    {/* Reveal Arena - SPLIT VIEW UI */}
                    <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

                        {/* TEAM TITLES */}
                        <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                            <div className="text-left">
                                <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamA.color }}>
                                    {activeMatchData.teamA.name}
                                </h2>
                                <div className="mt-2 h-1 w-full bg-gradient-to-r from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamA.color }}></div>
                            </div>
                            <div className="text-right">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamB.color }}>
                                            {activeMatchData.teamB.name}
                                        </h2>
                                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamB.color }}></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        {/* VS INDICATOR */}
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                            <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                        </div>

                        <div className="space-y-4 relative z-10">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', role, activeMatchData!.teamA)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', role, activeMatchData!.teamB) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom Controls */}
                    <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                       <div className="pointer-events-auto">
                           {!isRevealFinished ? (
                                <button 
                                    onClick={handleNextReveal}
                                    className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                                >
                                    {currentRoleIdx === -1 ? 'START DRAFT' : 'REVEAL NEXT UNIT'}
                                </button>
                           ) : (
                                <Button onClick={proceedFromReveal} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                                    {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                                </Button>
                           )}
                       </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Tournament End State
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);
  const [particles, setParticles] = useState<number[]>([]);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number; // 0 or 1 relative to display (not global)
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // Effect for confetti particles on Tournament End
  useEffect(() => {
    if (phase === 'TOURNAMENT_END') {
       setParticles(Array.from({ length: 50 }).map((_, i) => i));
    }
  }, [phase]);

  // --- MEMOIZED BRACKET GENERATION (Fix for Lag/Freeze) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      // Helper to get winner from scores (local to useMemo to close over scores)
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA && teamB) return teamB;
        if (!teamB && scoreA > 0) return teamA;
        return null;
      };

      // 1. Generate Quarter Finals
      const quarterMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              const teamA = match.teams[i * 2] || null;
              const teamB = match.teams[i * 2 + 1] || null;
              quarterMatches.push({
                  id: i,
                  label: `Quarter ${i + 1}`,
                  mode: 'BO1',
                  teamA,
                  teamB
              });
          }
      }

      // 2. Generate Semi Finals
      const semiMatches: any[] = [];
      if (hasQuarterFinals) {
          const q1 = quarterMatches[0];
          const q2 = quarterMatches[1];
          const q3 = quarterMatches[2];
          const q4 = quarterMatches[3];

          semiMatches.push({
              id: 4,
              label: 'Semi-Final 1',
              mode: 'BO1',
              teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
              teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
          });
          semiMatches.push({
              id: 5,
              label: 'Semi-Final 2',
              mode: 'BO1',
              teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
              teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              semiMatches.push({
                  id: i,
                  label: `Semi-Final ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 3. Generate Grand Final
      const gfIndex = hasQuarterFinals ? 6 : 2;
      const s1 = semiMatches[0];
      const s2 = semiMatches[1];

      const grandFinalMatch = {
          id: gfIndex,
          label: 'Grand Final',
          mode: 'BO3',
          teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
          teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
      };

      const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

      return { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals };
  }, [match, scores]); // Only recalculate when match structure or scores change, NOT on Room ID input


  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      type: 'reveal',
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates,
      duration: Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000
    });
  };

  const handleRerollClick = (teamSide: 'A' | 'B', role: Role, teamData: any) => {
    // 1. Identify Global Team Index
    const globalTeamIdx = match.teams.findIndex(t => t.name === teamData.name);
    if (globalTeamIdx === -1) return;

    // 2. Determine Bench Players (Active players NOT currently assigned to ANY bracket team)
    const assignedIds = new Set(match.teams.flatMap(t => t.slots.map(s => s.player.id)));
    const benchPlayers = activePlayers.filter(p => !assignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    // 3. Filter candidates for the role
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const candidateNames = candidates.map(p => p.name);

    // 4. Auto-swap if only 1 candidate, else wheel
    if (candidates.length === 1) {
        onReroll(globalTeamIdx, role, candidates[0]);
        // Trigger visual flash
        const slotId = getSlotId(currentMatchIdx, teamSide, role);
        setAutoFillFlash(slotId);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000;

    setWheelState({
        isOpen: true,
        type: 'reroll',
        teamName: teamData.name,
        teamIndex: teamSide === 'A' ? 0 : 1,
        globalTeamIndex: globalTeamIdx,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;

    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < grandFinalMatch.id) {
         setPhase('OVERVIEW');
     } else {
         if (newScoreA >= 2 || newScoreB >= 2) {
             // SERIES WON! Set Tournament Champion
             const winnerTeam = newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB;
             setTournamentChampion(winnerTeam);
             setPhase('TOURNAMENT_END');
         } else {
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  // New Reroll-Compatible Card Renderer
  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const isAutoFilled = autoFillFlash === id;

    // Theme Construction based on Team Color or Default A/B
    const baseColor = teamData.color || (teamSide === 'A' ? '#00d2ff' : '#ef4444');

    // Inline styles for dynamic team colors
    const cardStyle = {
        borderColor: isAutoFilled ? '#dcb06b' : baseColor,
        boxShadow: isAutoFilled ? `0 0 30px #dcb06b` : (isRevealed ? `0 0 15px ${baseColor}` : 'none')
    };
    const textStyle = { color: isAutoFilled ? '#dcb06b' : (isRevealed ? baseColor : '#4a5f78') };

    if (!isRevealed) {
        return (
            <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
                <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
                    {RoleIcons[role]}
                </div>
            </div>
        );
    }

    return (
        <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
            <div 
                className={`absolute inset-0 clip-corner-md border-l-4 tilt-card bg-[#0a1a2f] border transition-all duration-300 shadow-[0_0_20px_rgba(0,0,0,0.6)]`}
                style={cardStyle}
            >
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'B' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className="mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 scale-[0.8] opacity-90" style={textStyle}>
                        {RoleIcons[role]}
                    </div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                        {slot?.player.name}
                    </span>
                    <div 
                        className="absolute inset-0 opacity-20 pointer-events-none"
                        style={{ background: `linear-gradient(${teamSide === 'B' ? 'to left' : 'to right'}, ${baseColor}, transparent)` }}
                    ></div>
                </div>

                {/* REROLL BUTTON */}
                <button 
                    onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role, teamData); }}
                    className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'A' ? 'right-4' : 'left-4'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                </button>
            </div>
        </div>
    );
  };

  const renderBracketMatchCard = (m: any) => {
      // FIX: Hide card if it's a ghost match (no teams), preserving space
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[170px] invisible"></div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;

      return (
        <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_15px_30px_rgba(0,0,0,0.5)] transition-all duration-300 ${isDone ? 'border-[#dcb06b]/30' : 'border-white/5'}`}>
            <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">{m.label}</h3>
                <div className="flex gap-2">
                    {isDone && <span className="text-[8px] px-1 py-0.5 bg-yellow-500/20 text-yellow-500 border border-yellow-500/50 rounded font-black">FINISHED</span>}
                    <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">{m.mode}</span>
                </div>
            </div>

            <div className="space-y-2">
                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sA > sB ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamA ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA.name}</span>
                        <span className="font-orbitron font-bold text-white">{sA}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>

                <div className="flex justify-center h-4 items-center">
                   <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                </div>

                <div className={`flex items-center gap-3 border p-2 rounded group/team ${sB > sA ? 'bg-[#dcb06b]/10 border-[#dcb06b]/40' : 'bg-black/40 border-white/5'}`}>
                {m.teamB ? (
                    <>
                        <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                        <span className={`flex-1 text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB.name}</span>
                        <span className="font-orbitron font-bold text-white">{sB}</span>
                    </>
                ) : (
                    <>
                        <div className="w-1.5 h-6 shrink-0 bg-white/10"></div>
                        <span className="flex-1 text-xs font-cinzel font-black tracking-widest truncate text-white/20">TBD / BYE</span>
                    </>
                )}
                </div>
            </div>

            <div className="mt-4 pt-4 border-t border-white/5 flex items-end gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1">
                        <span className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Status</span>
                        <div className="text-xs text-[#dcb06b] font-orbitron font-bold py-1.5 tracking-widest">
                            {isGhostA ? 'WAITING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1">
                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                        <input 
                        type="text" 
                        placeholder="0000"
                        value={matchRoomIds[m.id] || ''}
                        onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                        className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                        />
                    </div>
                )}

                {!isDone && m.teamA && (
                    <Button 
                        onClick={() => startMatchFlow(m.id)}
                        disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                        size="sm"
                        className="h-[30px] text-[8px] px-4"
                    >
                        {isBye ? 'ADVANCE' : 'START'}
                    </Button>
                )}
            </div>
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  // *** NEW: Tournament End Screen ***
  if (phase === 'TOURNAMENT_END' && tournamentChampion) {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] animate-slide-in overflow-hidden">
            {/* Background Effects */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] z-0"></div>
            <div className="god-rays opacity-20"></div>

            {/* Confetti */}
            {particles.map(i => (
                <div 
                    key={i} 
                    className="confetti-piece"
                    style={{
                    left: `${Math.random() * 100}%`,
                    animationDelay: `${Math.random() * 2}s`,
                    backgroundColor: Math.random() > 0.5 ? '#dcb06b' : tournamentChampion.color
                    }}
                ></div>
            ))}

            <div className="relative z-10 flex flex-col items-center w-full max-w-6xl px-4">
                <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">
                    GRAND FINAL WINNER
                </h3>

                <h1 className="text-4xl md:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-8 tracking-wider">
                    TOURNAMENT CHAMPION
                </h1>

                <div className="relative mb-12 transform hover:scale-105 transition-transform duration-500">
                    <div className="absolute inset-0 bg-white/10 blur-[50px]"></div>
                    <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 py-6 clip-corner-md shadow-[0_0_50px_rgba(220,176,107,0.3)]">
                        <h2 className="text-5xl md:text-6xl font-black font-cinzel text-white tracking-[0.2em] uppercase" style={{ color: tournamentChampion.color, textShadow: `0 0 20px ${tournamentChampion.color}` }}>
                            {tournamentChampion.name}
                        </h2>
                    </div>
                </div>

                {/* Winning Roster */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-16">
                    {ROLES_ORDER.map((role, idx) => {
                        const slot = tournamentChampion.slots.find((s: TeamSlot) => s.role === role);
                        return (
                            <div 
                                key={role} 
                                className="flex flex-col items-center p-4 bg-black/40 border border-white/10 clip-corner-sm backdrop-blur-sm animate-slide-in"
                                style={{ animationDelay: `${idx * 100}ms` }}
                            >
                                <div className="text-[#dcb06b] mb-2 opacity-80 scale-75">
                                    {RoleIcons[role]}
                                </div>
                                <span className="text-white font-orbitron font-bold text-sm tracking-wide">
                                    {slot?.player.name}
                                </span>
                            </div>
                        );
                    })}
                </div>

                <Button onClick={onReset} size="lg" className="px-16 py-5 text-xl shadow-[0_0_30px_#dcb06b] animate-pulse">
                    RETURN TO LOBBY
                </Button>
            </div>
        </div>
      );
  }

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-white tracking-[0.2em] drop-shadow-[0_2px_10px_rgba(255,255,255,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80">
               {hasQuarterFinals ? 'QUARTERS BO1 . ' : ''}SEMIS BO1 . GRAND FINAL BO3
             </p>
          </div>

          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-8 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            {/* FIX: Only show connector if match exists */}
                            {(m.teamA || m.teamB) && (
                                <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-48' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  {/* FIX: Only show connector if match exists */}
                  {(m.teamA || m.teamB) && (
                      <div className="absolute top-1/2 -right-8 md:-right-16 w-8 md:w-16 h-[1px] bg-gradient-to-r from-[#dcb06b]/40 to-[#dcb06b]/10 pointer-events-none"></div>
                  )}
                </div>
              ))}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[1px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/20 to-transparent flex items-center">
                 <div className="w-8 h-[1px] bg-[#dcb06b]/30"></div>
               </div>
            </div>

            <div className="relative z-20 animate-slide-in">
                 {(() => {
                    const m = grandFinalMatch;
                    const sA = scores[`${m.id}-A`] || 0;
                    const sB = scores[`${m.id}-B`] || 0;
                    const isSeriesDone = sA >= 2 || sB >= 2;
                    const canStart = m.teamA && m.teamB && !isSeriesDone;

                    return (
                    <div className={`w-80 bg-[#081221]/90 border clip-corner-sm p-4 relative shadow-[0_0_40px_rgba(220,176,107,0.1)] ${isSeriesDone ? 'border-[#dcb06b]' : 'border-[#dcb06b]/20'}`}>
                        <div className="flex justify-between items-center mb-4">
                        <h3 className="text-[10px] text-[#dcb06b] font-orbitron font-black uppercase tracking-widest">Grand Final</h3>
                        <div className="flex gap-2">
                            <span className="text-[8px] px-2 py-0.5 bg-white/5 text-[#8a9db8] font-black border border-white/10 rounded">BO3</span>
                        </div>
                        </div>

                        <div className="space-y-4">
                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sA > sB ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamA ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamA.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamA.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sA}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>

                        <div className="flex justify-center items-center h-2">
                            <span className="text-[8px] text-[#4a5f78] font-black italic">VS</span>
                        </div>

                        <div className={`bg-black/60 border border-white/5 p-2 rounded min-h-[50px] flex items-center gap-3 ${sB > sA ? 'border-[#dcb06b]/50' : ''}`}>
                            {m.teamB ? (
                                <>
                                    <div className="w-1.5 h-6 shrink-0" style={{ backgroundColor: m.teamB.color }}></div>
                                    <span className="flex-1 text-xs font-cinzel font-black text-white tracking-widest truncate">{m.teamB.name}</span>
                                    <span className="font-orbitron font-bold text-[#dcb06b] text-lg">{sB}</span>
                                </>
                            ) : (
                                <>
                                    <div className="w-1.5 h-6 bg-white/10"></div>
                                    <span className="text-xs font-cinzel font-black text-[#4a5f78] tracking-[0.4em] italic">TBD</span>
                                </>
                            )}
                        </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-white/5">
                            {canStart ? (
                                <div className="flex items-end gap-3">
                                    <div className="flex-1">
                                        <label className="block text-[8px] text-[#4a5f78] font-black tracking-widest uppercase mb-1">Room ID</label>
                                        <input 
                                            type="text" 
                                            placeholder="0000"
                                            value={matchRoomIds[m.id] || ''}
                                            onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                            className="bg-black/80 border border-[#1e3a5f] w-full text-center text-xs font-orbitron font-black text-white focus:outline-none focus:border-[#dcb06b] transition-all py-1.5 tracking-widest rounded"
                                        />
                                    </div>
                                    <Button 
                                        onClick={() => startMatchFlow(m.id)}
                                        disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4}
                                        size="sm"
                                        className="h-[30px] text-[8px] px-4"
                                    >
                                        {sA === 0 && sB === 0 ? 'START MATCH' : 'CONTINUE'}
                                    </Button>
                                </div>
                            ) : (
                                <div className="flex flex-col items-center opacity-40">
                                    <span className="text-[8px] text-[#4a5f78] font-black tracking-[0.3em] uppercase">Status</span>
                                    <span className="text-[10px] text-white font-orbitron font-bold">{isSeriesDone ? 'CHAMPION CROWNED' : 'WAITING FOR RESULTS'}</span>
                                </div>
                            )}
                        </div>
                    </div>
                 )})()}
            </div>
          </div>

          <div className="mt-12 animate-slide-in">
              <button 
                onClick={onReset} 
                className="px-16 py-3 bg-black/40 border border-white/10 text-[#4a5f78] hover:text-white hover:border-white transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col justify-center overflow-hidden">

            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamName === activeMatchData.teamA.name ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={wheelState.duration || 5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* TOP CONTROLS */}
                    <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center px-4">
                        <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>

                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>

                        {!isRevealFinished && (
                            <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                        )}
                    </div>

                    {/* Reveal Arena - SPLIT VIEW UI */}
                    <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

                        {/* TEAM TITLES */}
                        <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                            <div className="text-left">
                                <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamA.color }}>
                                    {activeMatchData.teamA.name}
                                </h2>
                                <div className="mt-2 h-1 w-full bg-gradient-to-r from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamA.color }}></div>
                            </div>
                            <div className="text-right">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamB.color }}>
                                            {activeMatchData.teamB.name}
                                        </h2>
                                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamB.color }}></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        {/* VS INDICATOR */}
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                            <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                        </div>

                        <div className="space-y-4 relative z-10">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', role, activeMatchData!.teamA)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', role, activeMatchData!.teamB) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom Controls */}
                    <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                       <div className="pointer-events-auto">
                           {!isRevealFinished ? (
                                <button 
                                    onClick={handleNextReveal}
                                    className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                                >
                                    {currentRoleIdx === -1 ? 'START DRAFT' : 'REVEAL NEXT UNIT'}
                                </button>
                           ) : (
                                <Button onClick={proceedFromReveal} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                                    {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                                </Button>
                           )}
                       </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);

  // Per-match Room IDs state
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});

  // Score state: key format "matchIdx-teamSide" (e.g. "0-A", "0-B")
  const [scores, setScores] = useState<Record<string, number>>({});

  // Evaluation Data State
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});

  // Temporary state for the current active game
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);

  // Tournament End State
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);
  const [particles, setParticles] = useState<number[]>([]);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number; // 0 or 1 relative to display (not global)
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // Effect for confetti particles on Tournament End
  useEffect(() => {
    if (phase === 'TOURNAMENT_END') {
       setParticles(Array.from({ length: 50 }).map((_, i) => i));
    }
  }, [phase]);

  // --- MEMOIZED BRACKET GENERATION (Fix for Lag/Freeze) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      // Helper to get winner from scores (local to useMemo to close over scores)
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA && teamB) return teamB;
        if (!teamB && scoreA > 0) return teamA;
        return null;
      };

      // 1. Generate Quarter Finals
      const quarterMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              const teamA = match.teams[i * 2] || null;
              const teamB = match.teams[i * 2 + 1] || null;
              quarterMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA,
                  teamB
              });
          }
      }

      // 2. Generate Semi Finals
      const semiMatches: any[] = [];
      if (hasQuarterFinals) {
          const q1 = quarterMatches[0];
          const q2 = quarterMatches[1];
          const q3 = quarterMatches[2];
          const q4 = quarterMatches[3];

          semiMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(q1.id, q1.teamA, q1.teamB),
              teamB: getWinnerTeam(q2.id, q2.teamA, q2.teamB)
          });
          semiMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(q3.id, q3.teamA, q3.teamB),
              teamB: getWinnerTeam(q4.id, q4.teamA, q4.teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              semiMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 3. Generate Grand Final
      const gfIndex = hasQuarterFinals ? 6 : 2;
      const s1 = semiMatches[0];
      const s2 = semiMatches[1];

      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(s1.id, s1.teamA, s1.teamB),
          teamB: getWinnerTeam(s2.id, s2.teamA, s2.teamB)
      };

      const allMatches = [...quarterMatches, ...semiMatches, grandFinalMatch];

      return { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals };
  }, [match, scores]); 


  // --- ACTIVE MATCH HELPERS ---

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  // --- ACTION FLOW ---

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);

    // If it's the Grand Final, NO ROLLING. Jump straight to Game Loop.
    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION'); // Enter Portal
    } else {
        // Semi/Quarter Finals: Start Rolling Phase
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  // --- REVEAL LOGIC ---

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;

    // Handle BYE or Single Team reveal
    if (!activeMatchData.teamB) {
        const role = ROLES_ORDER[currentRoleIdx + 1];
        if (!role) return;

        const slotId = getSlotId(currentMatchIdx, 'A', role);
        if (!revealedSlots.has(slotId)) {
            triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
        } else {
            setCurrentRoleIdx(prev => prev + 1);
        }
        return;
    }

    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];

    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);

    if (!revealedSlots.has(idA)) {
        triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    } else if (!revealedSlots.has(idB)) {
        triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
    }
  };

  const handleSkipAll = () => {
    if (!activeMatchData) return;
    const newRevealed = new Set(revealedSlots);
    const idx = activeMatchData.id;
    ROLES_ORDER.forEach(role => {
        newRevealed.add(getSlotId(idx, 'A', role));
        if (activeMatchData!.teamB) newRevealed.add(getSlotId(idx, 'B', role));
    });
    setRevealedSlots(newRevealed);
    setCurrentRoleIdx(ROLES_ORDER.length);
    setWheelState(null);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));

    setWheelState({
      isOpen: true,
      type: 'reveal',
      teamName,
      teamIndex: teamSide === 'A' ? 0 : 1,
      role,
      winnerName: winner.name,
      candidates,
      duration: Math.floor(Math.random() * (10000 - 5000 + 1)) + 5000
    });
  };

  const handleRerollClick = (teamSide: 'A' | 'B', role: Role, teamData: any) => {
    // 1. Identify Global Team Index
    const globalTeamIdx = match.teams.findIndex(t => t.name === teamData.name);
    if (globalTeamIdx === -1) return;

    // 2. Determine Bench Players (Active players NOT currently assigned to ANY bracket team)
    const assignedIds = new Set(match.teams.flatMap(t => t.slots.map(s => s.player.id)));
    const benchPlayers = activePlayers.filter(p => !assignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    // 3. Filter candidates for the role
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const candidateNames = candidates.map(p => p.name);

    // 4. Auto-swap if only 1 candidate, else wheel
    if (candidates.length === 1) {
        onReroll(globalTeamIdx, role, candidates[0]);
        // Trigger visual flash
        const slotId = getSlotId(currentMatchIdx, teamSide, role);
        setAutoFillFlash(slotId);
        setTimeout(() => setAutoFillFlash(null), 1000);
        return;
    }

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (9000 - 4000 + 1)) + 4000;

    setWheelState({
        isOpen: true,
        type: 'reroll',
        teamName: teamData.name,
        teamIndex: teamSide === 'A' ? 0 : 1,
        globalTeamIndex: globalTeamIdx,
        role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;

    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B' || !activeMatchData.teamB) setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }

    setWheelState(null);
  };

  const isRevealFinished = activeMatchData 
    ? (currentRoleIdx >= ROLES_ORDER.length - 1 && (activeMatchData.teamB ? revealedSlots.size === 10 : revealedSlots.size === 5))
    : true;

  const proceedFromReveal = () => {
      // Check for BYE (No Opponent)
      if (activeMatchData && !activeMatchData.teamB) {
          // Auto Advance Logic
          const idx = activeMatchData.id;
          setScores(prev => ({ 
             ...prev, 
             [`${idx}-A`]: 1, // Set Team A to Win (1-0)
             [`${idx}-B`]: 0 
          }));
          setPhase('OVERVIEW');
      } else {
          setPhase('TRANSITION');
      }
  };

  // --- GAME LOOP LOGIC ---

  const handleTransitionComplete = () => {
      setPhase('DECLARE_WIN');
  };

  const handleWinDeclared = (winner: 'azure' | 'crimson' | null) => {
      if (!winner) {
          setPhase('OVERVIEW');
          return;
      }
      setCurrentRoundWinner(winner);
      setPhase('CELEBRATION');
  };

  const handleCelebrationDismiss = () => {
      setPhase('EVALUATION');
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     // 1. Calculate new scores
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;

     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     let newScoreA = currentScoreA;
     let newScoreB = currentScoreB;

     if (currentRoundWinner === 'azure') newScoreA += 1;
     if (currentRoundWinner === 'crimson') newScoreB += 1;

     setScores(prev => ({
         ...prev,
         [scoreKeyA]: newScoreA,
         [scoreKeyB]: newScoreB
     }));

     setMatchEvaluations(prev => ({
        ...prev,
        [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings }
     }));

     // 3. Determine Progression
     if (currentMatchIdx < grandFinalMatch.id) {
         setPhase('OVERVIEW');
     } else {
         if (newScoreA >= 2 || newScoreB >= 2) {
             // SERIES WON! Set Tournament Champion
             const winnerTeam = newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB;
             setTournamentChampion(winnerTeam);
             setPhase('TOURNAMENT_END');
         } else {
             setPhase('TRANSITION');
         }
     }
  };


  // --- DATA CONSTRUCTION ---

  const getActiveMatchResult = (): MatchResult | null => {
      if (!activeMatchData || !activeMatchData.teamA) return null;
      return {
          roomId: activeRoomId,
          azureTeam: activeMatchData.teamA.slots,
          crimsonTeam: activeMatchData.teamB ? activeMatchData.teamB.slots : [],
          isCoachMode: false,
          timestamp: Date.now()
      };
  };

  const currentMatchObject = getActiveMatchResult();

  // --- RENDER HELPERS ---

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  // New Reroll-Compatible Card Renderer
  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const isAutoFilled = autoFillFlash === id;

    // Theme Construction based on Team Color or Default A/B
    const baseColor = teamData.color || (teamSide === 'A' ? '#00d2ff' : '#ef4444');

    // Inline styles for dynamic team colors
    const cardStyle = {
        borderColor: isAutoFilled ? '#dcb06b' : baseColor,
        boxShadow: isAutoFilled ? `0 0 30px #dcb06b` : (isRevealed ? `0 0 15px ${baseColor}` : 'none')
    };
    const textStyle = { color: isAutoFilled ? '#dcb06b' : (isRevealed ? baseColor : '#4a5f78') };

    if (!isRevealed) {
        return (
            <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
                <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
                    {RoleIcons[role]}
                </div>
            </div>
        );
    }

    return (
        <div className={`relative h-16 w-full animate-slide-in perspective-container group ${isAutoFilled ? 'scale-105 z-20' : ''}`}>
            <div 
                className={`absolute inset-0 clip-corner-md border-l-4 tilt-card bg-[#0a1a2f] border transition-all duration-300 shadow-[0_0_20px_rgba(0,0,0,0.6)]`}
                style={cardStyle}
            >
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'B' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className="mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 scale-[0.8] opacity-90" style={textStyle}>
                        {RoleIcons[role]}
                    </div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                        {slot?.player.name}
                    </span>
                    <div 
                        className="absolute inset-0 opacity-20 pointer-events-none"
                        style={{ background: `linear-gradient(${teamSide === 'B' ? 'to left' : 'to right'}, ${baseColor}, transparent)` }}
                    ></div>
                </div>

                {/* REROLL BUTTON */}
                <button 
                    onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role, teamData); }}
                    className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'A' ? 'right-4' : 'left-4'}`}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                    </svg>
                </button>
            </div>
        </div>
    );
  };

  const renderBracketMatchCard = (m: any) => {
      // FIX: Hide card if it's a ghost match (no teams), preserving space
      if (!m.teamA && !m.teamB) {
          return (
              <div className="w-80 h-[200px] invisible"></div>
          );
      }

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGhostA = !m.teamA;
      const isGrandFinal = m.label === 'GRAND FINAL';

      // Special styling for Grand Final
      const containerClass = isGrandFinal 
         ? "bg-[#0a1a2f]/90 border-2 border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.3)]" 
         : "bg-[#0a1a2f]/80 border border-[#1e3a5f] shadow-[0_0_20px_rgba(0,0,0,0.5)]";

      return (
        <div className={`w-80 ${containerClass} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50`}>

            {/* MATCH HEADER */}
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/20' : 'bg-[#05090f]/80'} border-b border-[#1e3a5f]`}>
                <div className="flex flex-col">
                    <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-xs uppercase tracking-widest`}>
                        {m.label}
                    </h3>
                </div>
                <div className="flex gap-2">
                    {isDone && <div className="h-2 w-2 rounded-full bg-green-500 shadow-[0_0_5px_lime] animate-pulse"></div>}
                    <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>
                        {m.mode}
                    </span>
                </div>
            </div>

            <div className="p-4 space-y-3">
                {/* TEAM A */}
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB ? 'opacity-100' : (isDone ? 'opacity-40 grayscale' : 'opacity-100')}`}>
                    {/* Active State Bar */}
                    <div className={`absolute left-0 top-0 bottom-0 w-1 ${m.teamA ? 'bg-[var(--team-color)]' : 'bg-[#4a5f78]'}`} style={{ '--team-color': m.teamA?.color } as React.CSSProperties}></div>

                    {m.teamA ? (
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>
                                {m.teamA.name}
                            </span>
                            <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                        </div>
                    ) : (
                         <div className="flex-1 ml-3 p-2 border-b border-dashed border-[#1e3a5f]/50">
                            <span className="text-[10px] font-orbitron text-[#4a5f78] italic">WAITING...</span>
                         </div>
                    )}
                </div>

                {/* VS Divider */}
                <div className="flex items-center gap-2 opacity-30">
                     <div className="h-[1px] flex-1 bg-white/20"></div>
                     <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                     <div className="h-[1px] flex-1 bg-white/20"></div>
                </div>

                {/* TEAM B */}
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100' : (isDone ? 'opacity-40 grayscale' : 'opacity-100')}`}>
                    <div className={`absolute left-0 top-0 bottom-0 w-1 ${m.teamB ? 'bg-[var(--team-color)]' : 'bg-[#4a5f78]'}`} style={{ '--team-color': m.teamB?.color } as React.CSSProperties}></div>

                    {m.teamB ? (
                         <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>
                                {m.teamB.name}
                            </span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    ) : (
                         <div className="flex-1 ml-3 p-2 border-b border-dashed border-[#1e3a5f]/50">
                             <span className="text-[10px] font-orbitron text-[#4a5f78] italic">{isBye ? 'BYE (NO OPPONENT)' : 'WAITING...'}</span>
                         </div>
                    )}
                </div>
            </div>

            {/* ACTION FOOTER */}
            <div className="p-3 bg-[#05090f]/50 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye || isGhostA ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#4a5f78] font-black tracking-widest uppercase">STATUS</span>
                        <div className="text-[10px] text-[#dcb06b] font-orbitron font-bold tracking-wider animate-pulse">
                            {isGhostA ? 'PENDING' : 'AUTO ADVANCE'}
                        </div>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                                type="text" 
                                placeholder="----"
                                value={matchRoomIds[m.id] || ''}
                                onChange={(e) => handleRoomIdChange(m.id, e.target.value)}
                                className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm transition-all"
                            />
                        </div>

                        {!isDone && m.teamA && (
                            <Button 
                                onClick={() => startMatchFlow(m.id)}
                                disabled={!isBye && (!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4)}
                                size="sm"
                                className={`h-[28px] text-[8px] px-3 ${isGrandFinal ? 'bg-[#dcb06b] text-black hover:bg-white' : ''}`}
                            >
                                {isBye ? 'ADVANCE' : 'ENTER'}
                            </Button>
                        )}
                    </>
                )}
            </div>

            {/* Grand Final Special Glow */}
            {isGrandFinal && <div className="absolute inset-0 border-2 border-[#dcb06b] opacity-20 animate-pulse pointer-events-none rounded-sm"></div>}
        </div>
      );
  };

  // --- COMPONENT RETURN ---

  // *** NEW: Tournament End Screen ***
  if (phase === 'TOURNAMENT_END' && tournamentChampion) {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] animate-slide-in overflow-hidden">
            {/* Background Effects */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000000_100%)] z-0"></div>
            <div className="god-rays opacity-20"></div>

            {/* Confetti */}
            {particles.map(i => (
                <div 
                    key={i} 
                    className="confetti-piece"
                    style={{
                    left: `${Math.random() * 100}%`,
                    animationDelay: `${Math.random() * 2}s`,
                    backgroundColor: Math.random() > 0.5 ? '#dcb06b' : tournamentChampion.color
                    }}
                ></div>
            ))}

            <div className="relative z-10 flex flex-col items-center w-full max-w-6xl px-4">
                <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">
                    GRAND FINAL WINNER
                </h3>

                <h1 className="text-4xl md:text-7xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] drop-shadow-[0_0_30px_rgba(220,176,107,0.4)] mb-8 tracking-wider">
                    TOURNAMENT CHAMPION
                </h1>

                <div className="relative mb-12 transform hover:scale-105 transition-transform duration-500">
                    <div className="absolute inset-0 bg-white/10 blur-[50px]"></div>
                    <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 py-6 clip-corner-md shadow-[0_0_50px_rgba(220,176,107,0.3)]">
                        <h2 className="text-5xl md:text-6xl font-black font-cinzel text-white tracking-[0.2em] uppercase" style={{ color: tournamentChampion.color, textShadow: `0 0 20px ${tournamentChampion.color}` }}>
                            {tournamentChampion.name}
                        </h2>
                    </div>
                </div>

                {/* Winning Roster */}
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-16">
                    {ROLES_ORDER.map((role, idx) => {
                        const slot = tournamentChampion.slots.find((s: TeamSlot) => s.role === role);
                        return (
                            <div 
                                key={role} 
                                className="flex flex-col items-center p-4 bg-black/40 border border-white/10 clip-corner-sm backdrop-blur-sm animate-slide-in"
                                style={{ animationDelay: `${idx * 100}ms` }}
                            >
                                <div className="text-[#dcb06b] mb-2 opacity-80 scale-75">
                                    {RoleIcons[role]}
                                </div>
                                <span className="text-white font-orbitron font-bold text-sm tracking-wide">
                                    {slot?.player.name}
                                </span>
                            </div>
                        );
                    })}
                </div>

                <Button onClick={onReset} size="lg" className="px-16 py-5 text-xl shadow-[0_0_30px_#dcb06b] animate-pulse">
                    RETURN TO LOBBY
                </Button>
            </div>
        </div>
      );
  }

  if (phase === 'TRANSITION' && currentMatchObject) {
      return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={handleTransitionComplete} />;
  }

  if (phase === 'DECLARE_WIN' && currentMatchObject) {
      return <MatchSummary match={currentMatchObject} onReset={handleWinDeclared} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) {
      return (
          <VictoryCelebration 
            winner={currentRoundWinner} 
            teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} 
            onDismiss={handleCelebrationDismiss} 
          />
      );
  }

  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) {
      return (
          <EvaluationScreen 
              match={currentMatchObject} 
              winner={currentRoundWinner} 
              onComplete={handleEvaluationComplete} 
          />
      );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-y-auto font-inter">
      {/* Dynamic Background Pattern */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'linear-gradient(#dcb06b 1px, transparent 1px), linear-gradient(90deg, #dcb06b 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen px-6 py-12 flex flex-col items-center">
          <div className="text-center mb-6 animate-slide-in">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] tracking-[0.2em] drop-shadow-[0_2px_20px_rgba(220,176,107,0.2)] mb-2">
               TOURNAMENT BRACKET
             </h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase opacity-80 border-t border-b border-[#4a5f78]/30 py-2 inline-block">
               {hasQuarterFinals ? 'QUARTERS BO1 • ' : ''}SEMIS BO1 • GRAND FINAL BO3
             </p>
          </div>

          <div className="w-full flex flex-nowrap items-center justify-center py-20 relative overflow-x-auto gap-16 md:gap-32 px-4 custom-scrollbar">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-12 relative z-20">
                    {quarterMatches.map((m) => (
                        <div key={m.id} className="relative group animate-slide-in">
                            {renderBracketMatchCard(m)}
                            {/* Connector */}
                            {(m.teamA || m.teamB) && (
                                <div className="absolute top-1/2 -right-16 w-16 h-[2px] bg-gradient-to-r from-[#1e3a5f] to-[#dcb06b]/40 pointer-events-none"></div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-64' : 'gap-16'} relative z-20 justify-center`}>
              {semiMatches.map((m) => (
                <div key={m.id} className="relative group animate-slide-in">
                  {renderBracketMatchCard(m)}
                  {/* Connector */}
                  {(m.teamA || m.teamB) && (
                      <div className="absolute top-1/2 -right-16 w-16 h-[2px] bg-gradient-to-r from-[#1e3a5f] to-[#dcb06b]/40 pointer-events-none"></div>
                  )}
                </div>
              ))}

               {/* Vertical Connector Line */}
               <div className="absolute top-1/2 -right-16 h-[60%] w-[2px] -translate-y-1/2 bg-gradient-to-b from-transparent via-[#dcb06b]/40 to-transparent flex items-center justify-center">
                   <div className="w-4 h-4 rounded-full bg-[#05090f] border-2 border-[#dcb06b] shadow-[0_0_10px_#dcb06b]"></div>
               </div>
            </div>

            <div className="relative z-20 animate-slide-in scale-110 origin-center ml-10">
                 {/* Grand Final Wrapper to Center */}
                 {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <div className="mt-12 animate-slide-in relative">
              <div className="absolute inset-0 bg-red-900/20 blur-xl"></div>
              <button 
                onClick={onReset} 
                className="relative px-12 py-3 bg-[#0a1a2f] border border-red-900/50 text-red-500 hover:text-white hover:bg-red-900 hover:border-red-500 transition-all text-xs font-cinzel font-bold tracking-[0.4em] uppercase clip-corner-sm shadow-[0_0_20px_rgba(0,0,0,0.5)]"
              >
                ABORT TOURNAMENT
              </button>
          </div>
        </div>
      ) : (
        <div className="relative z-10 w-full max-w-7xl mx-auto h-screen flex flex-col justify-center overflow-hidden">

            {wheelState && activeMatchData && (
                <SpinWheel 
                    candidates={wheelState.candidates} 
                    winnerName={wheelState.winnerName} 
                    onComplete={handleWheelComplete} 
                    onCancel={() => setWheelState(null)} 
                    team={wheelState.teamName === activeMatchData.teamA.name ? 'azure' : 'crimson'}
                    roleName={wheelState.role} 
                    roomId={activeRoomId} 
                    duration={wheelState.duration || 5000}
                />
            )}

            {activeMatchData && (
                <>
                    {/* TOP CONTROLS */}
                    <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center px-4">
                        <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-white/20 text-[#8a9db8]">BACK TO BRACKET</Button>

                        <div className="flex flex-col items-center scale-90">
                            <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1">{activeMatchData.label} REVEAL</span>
                            <div className="bg-black/60 border border-[#dcb06b]/40 px-6 py-1 clip-corner-sm shadow-[0_0_20px_rgba(220,176,107,0.2)]">
                                <span className="text-lg font-orbitron font-bold text-white tracking-widest animate-[chromatic_2s_infinite]">
                                   {activeMatchData.teamB ? `ROOM ${activeRoomId}` : 'AUTO ADVANCE'}
                                </span>
                            </div>
                        </div>

                        {!isRevealFinished && (
                            <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/50 text-[#dcb06b] hover:bg-[#dcb06b]/10">SKIP ALL</Button>
                        )}
                    </div>

                    {/* Reveal Arena - SPLIT VIEW UI */}
                    <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">

                        {/* TEAM TITLES */}
                        <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                            <div className="text-left">
                                <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamA.color }}>
                                    {activeMatchData.teamA.name}
                                </h2>
                                <div className="mt-2 h-1 w-full bg-gradient-to-r from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamA.color }}></div>
                            </div>
                            <div className="text-right">
                                {activeMatchData.teamB ? (
                                    <>
                                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]" style={{ color: activeMatchData.teamB.color }}>
                                            {activeMatchData.teamB.name}
                                        </h2>
                                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-white/20 to-transparent" style={{ backgroundColor: activeMatchData.teamB.color }}></div>
                                    </>
                                ) : (
                                    <h2 className="text-3xl md:text-5xl font-cinzel font-black text-[#4a5f78] tracking-widest italic mb-2">BYE</h2>
                                )}
                            </div>
                        </div>

                        {/* VS INDICATOR */}
                        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                            <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                        </div>

                        <div className="space-y-4 relative z-10">
                            {ROLES_ORDER.map((role) => (
                                <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                                    <div className="w-full">
                                        {renderPlayerCard(activeMatchData!.id, 'A', role, activeMatchData!.teamA)}
                                    </div>
                                    <div className="w-full">
                                        {activeMatchData!.teamB ? 
                                            renderPlayerCard(activeMatchData!.id, 'B', role, activeMatchData!.teamB) 
                                            : <div className="h-14 opacity-20 border border-dashed border-white/5 clip-corner-sm"></div>
                                        }
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* Bottom Controls */}
                    <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                       <div className="pointer-events-auto">
                           {!isRevealFinished ? (
                                <button 
                                    onClick={handleNextReveal}
                                    className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                                >
                                    {currentRoleIdx === -1 ? 'START DRAFT' : 'REVEAL NEXT UNIT'}
                                </button>
                           ) : (
                                <Button onClick={proceedFromReveal} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                                    {activeMatchData.teamB ? 'INITIALIZE BATTLE' : 'ADVANCE ROUND'}
                                </Button>
                           )}
                       </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => setElapsedSeconds(prev => prev + 1), 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     if (e.dataTransfer.getData("type") === "mvp-token") setMvpId(playerId);
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = (current < 0) ? 1 : (current === 0) ? 1 : (current === 1) ? 2 : 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = (current > 0) ? -1 : (current === 0) ? -1 : (current === -1) ? -2 : 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      const isActive = isUp ? currentRating > 0 : currentRating < 0;

      // Panah double hanya aktif jika nilai sesuai dengan arah tombol (2 untuk up, -2 untuk down)
      const isDouble = isUp ? currentRating === 2 : currentRating === -2;

      const colorClass = isUp ? (isActive ? 'text-green-400' : 'text-gray-600') : (isActive ? 'text-red-500' : 'text-gray-600');
      const glowClass = isActive ? (isUp ? 'drop-shadow-[0_0_10px_#4ade80]' : 'drop-shadow-[0_0_10px_#ef4444]') : '';

      return (
          <button onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} className={`p-1.5 hover:bg-white/10 transition-all ${colorClass} ${glowClass} flex flex-col items-center -space-y-1.5`}>
              {isUp ? (
                  <>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg></>
              ) : (
                  <><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}</>
              )}
          </button>
      );
  };

  if (isLoading) {
    return (
        <div className="fixed inset-0 z-[100] bg-[#05090f] flex flex-col items-center justify-center">
            <div className="w-16 h-16 border-4 border-[#1e3a5f] border-t-[#dcb06b] rounded-full animate-spin mb-6"></div>
            <h2 className="text-[#dcb06b] font-orbitron text-xl tracking-[0.3em] animate-pulse">ANALYZING BATTLE RESULTS...</h2>
        </div>
    );
  }

  const MVPToken = () => (
    <div draggable onDragStart={handleDragStart} className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform">
       <div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white/50 animate-pulse">
           <span className="font-black italic text-[#05090f] text-xs">MVP</span>
       </div>
    </div>
  );

  const renderTeamColumn = (teamSlots: any[], teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';
      const hexColor = teamColor === 'cyan' ? '#00d2ff' : '#ef4444';
      const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;

      // Determine background intensity based on winner status
      const innerBgColor = teamColor === 'cyan' 
        ? (isWinner ? 'bg-[#0a1a2f]/90' : 'bg-[#0a1a2f]/60') 
        : (isWinner ? 'bg-[#1a0505]/90' : 'bg-[#1a0505]/60');

      return (
        <div className={`
            flex-1 w-full relative flex flex-col h-full 
            clip-corner-md 
            transition-all duration-500
            p-[2px] /* Create space for the animated border */
            ${isWinner ? `shadow-[0_0_40px_${hexColor}] z-10 scale-[1.01]` : 'shadow-[0_0_20px_rgba(0,0,0,0.5)] opacity-80 scale-95'}
        `}>

            {/* ANIMATED BORDER LAYER (Back) */}
            {isWinner ? (
                <div className="absolute inset-[-50%] animate-[spin_3s_linear_infinite]"
                     style={{
                         background: `conic-gradient(from 0deg, transparent 0deg, transparent 80deg, ${hexColor} 140deg, ${hexColor} 180deg, transparent 240deg)`
                     }}
                ></div>
            ) : (
                /* Static border for loser */
                <div className={`absolute inset-0 ${teamColor === 'cyan' ? 'bg-[#1e3a5f]' : 'bg-[#450a0a]'}`}></div>
            )}

            {/* CONTENT CONTAINER (Front) */}
            <div className={`relative z-10 w-full h-full flex flex-col ${innerBgColor} clip-corner-md overflow-hidden`}>

                {/* Header */}
                <div className={`p-4 flex justify-between items-center border-b border-white/10 ${teamColor === 'cyan' ? 'bg-[#00d2ff]/20' : 'bg-[#ef4444]/20'}`}>
                    <h3 className={`${textColor} font-cinzel font-black text-lg tracking-[0.15em] drop-shadow-lg`}>{teamName.split(' ')[0]} GOLEM</h3>
                    {isWinner && <span className="text-[#05090f] font-black uppercase tracking-[0.2em] text-[10px] border border-[#dcb06b] px-3 py-1 rounded bg-[#dcb06b] shadow-[0_0_10px_#dcb06b] animate-pulse">Victory</span>}
                </div>

                {/* List */}
                <div className="p-3 space-y-2.5 overflow-y-auto flex-1 custom-scrollbar">
                    {rolesToRender.map(role => {
                        const slot = teamSlots.find(s => s.role === role);
                        if(!slot) return null;
                        const isMvp = slot.player.id === mvpId;
                        const rating = ratings[slot.player.id] || 0;
                        const isCoach = role === Role.COACH;

                        return (
                            <div key={role} 
                                onDragOver={!isCoach ? handleDragOver : undefined} 
                                onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined} 
                                className={`flex items-center justify-between bg-[#0a1a2f]/80 p-3 rounded-md border-2 h-16 relative transition-all duration-300 ${isMvp ? 'border-yellow-400 shadow-[0_0_20px_rgba(251,191,36,0.4)]' : isCoach ? 'border-white/20 bg-white/5 opacity-90' : 'border-white/5'}`}>
                                <div className="flex items-center gap-4 min-w-0 flex-1">
                                    <div className={`shrink-0 scale-[0.85] ${isCoach ? 'text-white' : (teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500')}`}>{RoleIcons[role]}</div>
                                    <div className="min-w-0 flex-1">
                                        <div className={`text-base md:text-lg font-orbitron truncate font-bold ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                    </div>
                                </div>

                                {!isCoach ? (
                                <div className="flex items-center gap-3 shrink-0">
                                    <div className="flex flex-col gap-1">{renderRatingButton(slot.player.id, 'up', rating)}{renderRatingButton(slot.player.id, 'down', rating)}</div>
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? <div className="w-9 h-9 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold] border border-white/30">MVP</div> : <div className="w-9 h-9 border-2 border-dashed border-white/10 rounded-full opacity-30"></div>}
                                    </div>
                                </div>
                                ) : (
                                    <div className="px-3 py-1 border-2 border-white/10 text-[9px] text-white/50 font-black uppercase tracking-widest rounded bg-white/5">COACH</div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4 overflow-hidden">
       <div className="w-full max-w-6xl h-full flex flex-col py-6 animate-slide-in">
          <div className="text-center mb-5 flex justify-between items-center px-6">
             <div className="text-left">
                <h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-[0.2em] uppercase mb-1">EVALUATION SESSION</h1>
                <p className="text-[10px] text-[#4a5f78] uppercase tracking-[0.4em] font-black">RATE PLAYER PERFORMANCE & ASSIGN MATCH MVP</p>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest uppercase mb-2">TIME SESSION</span>
                <div className="text-2xl font-mono font-bold text-white bg-black/70 px-8 py-1.5 rounded-md border-2 border-[#dcb06b]/30 shadow-[0_0_20px_rgba(220,176,107,0.2)]">{formatTime(elapsedSeconds)}</div>
             </div>
          </div>

          <div className="flex flex-col items-center mb-6 h-14">
             {!mvpId ? <MVPToken /> : <button onClick={() => setMvpId('')} className="text-[10px] text-red-400 border-2 border-red-500/30 px-6 py-2 uppercase font-black tracking-[0.2em] hover:bg-red-950/60 transition-all clip-corner-sm shadow-lg">RESET MVP SELECTION</button>}
          </div>

          <div className="flex flex-col md:flex-row gap-8 items-stretch justify-center flex-1 max-h-[68vh]">
             {renderTeamColumn(match.azureTeam, "AZURE", winner === 'azure', 'cyan')}
             {renderTeamColumn(match.crimsonTeam, "CRIMSON", winner === 'crimson', 'red')}
          </div>

          <div className="mt-8 flex justify-center pb-4">
             <Button onClick={() => onComplete(mvpId, ratings)} size="lg" className="px-20 py-5 text-sm shadow-[0_0_30px_rgba(220,176,107,0.3)]">FINISH BATTLE EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

export const LocalClock: React.FC = () => {
  const [time, setTime] = useState('');
  const [isVisible, setIsVisible] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: window.innerWidth - 150, y: 20 });
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      const options: Intl.DateTimeFormatOptions = {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false,
      };
      // Uses local system time automatically by omitting timeZone
      setTime(new Intl.DateTimeFormat(undefined, options).format(now));
    };

    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isMinimized) return;
    setIsDragging(true);
    dragOffset.current = {
      x: e.clientX - position.x,
      y: e.clientY - position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const newX = Math.max(0, Math.min(window.innerWidth - (isMinimized ? 40 : 128), e.clientX - dragOffset.current.x));
      const newY = Math.max(0, Math.min(window.innerHeight - (isMinimized ? 40 : 60), e.clientY - dragOffset.current.y));

      setPosition({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, isMinimized]);

  if (!isVisible) return (
    <button 
      onClick={() => setIsVisible(true)}
      className="fixed bottom-4 right-4 z-[100] w-10 h-10 bg-[#0a1a2f] border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_10px_rgba(220,176,107,0.3)]"
    >
      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    </button>
  );

  return (
    <div 
      style={{ left: position.x, top: position.y }}
      className={`fixed z-[100] transition-shadow duration-300 ${isDragging ? 'shadow-[0_0_20px_rgba(220,176,107,0.5)]' : 'shadow-xl'}`}
    >
      {isMinimized ? (
        <button 
          onClick={() => setIsMinimized(false)}
          className="w-10 h-10 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:scale-110 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </button>
      ) : (
        <div className="w-32 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b]/50 clip-corner-sm flex flex-col overflow-hidden shadow-2xl">
          {/* Draggable Header */}
          <div 
            onMouseDown={handleMouseDown}
            className={`h-5 bg-[#dcb06b]/20 flex items-center justify-between px-2 cursor-move select-none border-b border-[#dcb06b]/30 ${isDragging ? 'bg-[#dcb06b]/40' : ''}`}
          >
            <div className="flex gap-1 items-center">
               <div className="w-1 h-1 bg-[#dcb06b] rounded-full animate-pulse"></div>
               <span className="text-[7px] font-orbitron font-bold text-[#dcb06b] tracking-tighter">LOCAL SYSTEM</span>
            </div>
            <div className="flex gap-1">
              <button onClick={() => setIsMinimized(true)} className="text-[#dcb06b] hover:text-white">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" /></svg>
              </button>
              <button onClick={() => setIsVisible(false)} className="text-[#dcb06b] hover:text-red-500">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          </div>

          {/* Time Display */}
          <div className="p-2 flex flex-col items-center">
             <div className="text-lg font-orbitron font-black text-white tracking-widest drop-shadow-[0_0_5px_rgba(255,255,255,0.3)]">
                {time}
             </div>
             <div className="text-[6px] font-orbitron text-[#dcb06b] uppercase tracking-[0.2em] mt-0.5 opacity-60">
                LOCAL TIME
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);
  const [particles, setParticles] = useState<number[]>([]);

  // Reveal State
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [autoFillFlash, setAutoFillFlash] = useState<string | null>(null);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number;
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  useEffect(() => {
    if (phase === 'TOURNAMENT_END') {
       setParticles(Array.from({ length: 50 }).map((_, i) => i));
    }
  }, [phase]);

  // --- MEMOIZED BRACKET GENERATION (With Auto-Advance Logic) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        // Auto-win for BYE matches if no score is set yet
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      // 1. Generate Quarter Finals
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 2. Generate Semi Finals
      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 3. Generate Grand Final
      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch, allMatches: [...qMatches, ...sMatches, grandFinalMatch], hasQuarterFinals };
  }, [match, scores]); 

  // --- ACTIONS ---

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        // Direct advance for BYE
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleRoomIdChange = (idx: number, val: string) => {
    const cleaned = val.replace(/\D/g,'').slice(0,4);
    setMatchRoomIds(prev => ({ ...prev, [idx]: cleaned }));
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  // --- RENDERERS ---

  const ConnectorSVG = ({ type }: { type: 'fork' | 'single' }) => (
    <div className={`absolute top-1/2 -right-16 md:-right-32 w-16 md:w-32 h-full -translate-y-1/2 flex items-center z-0 pointer-events-none`}>
       <svg width="100%" height="100%" viewBox="0 0 100 100" preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.2" />
                <stop offset="50%" stopColor="#dcb06b" stopOpacity="0.8">
                    <animate attributeName="offset" values="0;1;0" dur="3s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#1e3a5f" stopOpacity="0.2" />
             </linearGradient>
          </defs>
          <path 
            d={type === 'fork' ? "M0,50 L50,50 L50,0 L100,0 M50,50 L50,100 L100,100" : "M0,50 L100,50"} 
            stroke="url(#energyGradient)" 
            strokeWidth="2" 
            fill="none" 
            className="animate-pulse"
          />
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[200px] invisible"></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/90 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.3)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/20' : 'bg-[#05090f]/80'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-xs uppercase tracking-widest`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100' : (isDone ? 'opacity-40 grayscale' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'WAITING...'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-30 px-6">
                        <div className="h-[1px] flex-1 bg-white/20"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white/20"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100' : (isDone ? 'opacity-40 grayscale' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'WAITING...'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-[#05090f]/50 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#4a5f78] font-black uppercase tracking-widest">ADVANCE BY BYE</span>
                        <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-3 bg-[#dcb06b]">NEXT STAGE</Button>
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => handleRoomIdChange(m.id, e.target.value)} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----"/>
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">ENTER</Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';
  const getSlotId = (matchIdx: number, teamSide: 'A' | 'B', role: Role) => `m${matchIdx}-${teamSide}-${role}`;

  const handleNextReveal = () => {
    if (!activeMatchData || !activeMatchData.teamA) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const idA = getSlotId(currentMatchIdx, 'A', role);
    const idB = getSlotId(currentMatchIdx, 'B', role);
    if (!revealedSlots.has(idA)) triggerWheel(currentMatchIdx, 'A', activeMatchData.teamA.name, role, activeMatchData.teamA.slots);
    else if (!revealedSlots.has(idB)) triggerWheel(currentMatchIdx, 'B', activeMatchData.teamB.name, role, activeMatchData.teamB.slots);
  };

  const triggerWheel = (matchIdx: number, teamSide: 'A' | 'B', teamName: string, role: Role, slots: TeamSlot[]) => {
    const winner = slots.find(s => s.role === role)?.player;
    if (!winner) return;
    const candidates = match.teams.flatMap(t => t.slots.map(s => s.player.name));
    setWheelState({ isOpen: true, type: 'reveal', teamName, teamIndex: teamSide === 'A' ? 0 : 1, role, winnerName: winner.name, candidates, duration: 6000 });
  };

  const handleWheelComplete = () => {
    if (!wheelState || !activeMatchData) return;
    if (wheelState.type === 'reveal') {
        const { role, teamIndex } = wheelState;
        const teamSide = teamIndex === 0 ? 'A' : 'B';
        const id = getSlotId(currentMatchIdx, teamSide, role);
        setRevealedSlots(prev => new Set(prev).add(id));
        if (teamSide === 'B') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
        onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const renderPlayerCard = (matchIdx: number, teamSide: 'A' | 'B', role: Role, teamData: any) => {
    const slots: TeamSlot[] = teamData.slots;
    const slot = slots.find(s => s.role === role);
    const id = getSlotId(matchIdx, teamSide, role);
    const isRevealed = revealedSlots.has(id);
    const baseColor = teamData.color || '#dcb06b';
    if (!isRevealed) return <div className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex items-center justify-center opacity-30">{RoleIcons[role]}</div>;
    return (
        <div className="relative h-16 w-full animate-slide-in">
            <div className="absolute inset-0 clip-corner-md border-l-4 bg-[#0a1a2f] border flex items-center px-6" style={{ borderColor: baseColor }}>
                <div className="text-white font-orbitron font-bold text-xl">{slot?.player.name}</div>
            </div>
        </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-12 py-6 clip-corner-md shadow-[0_0_50px_rgba(220,176,107,0.3)]">
                <h2 className="text-5xl font-black font-cinzel text-white" style={{ color: tournamentChampion.color }}>{tournamentChampion.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-12">RETURN TO LOBBY</Button>
        </div>
      );
  }

  const currentMatchObject = phase !== 'OVERVIEW' ? { roomId: activeRoomId, azureTeam: activeMatchData?.teamA?.slots || [], crimsonTeam: activeMatchData?.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() } : null;

  if (phase === 'TRANSITION' && currentMatchObject) return <PortalTransition azureTeam={currentMatchObject.azureTeam} crimsonTeam={currentMatchObject.crimsonTeam} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && currentMatchObject) return <MatchSummary match={currentMatchObject} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && currentMatchObject) return <VictoryCelebration winner={currentRoundWinner} teamSlots={currentRoundWinner === 'azure' ? currentMatchObject.azureTeam : currentMatchObject.crimsonTeam} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && currentMatchObject) return <EvaluationScreen match={currentMatchObject} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-12">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-widest mb-4">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.6em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">SEMIS BO1 • GRAND FINAL BO3</p>
          </div>

          <div className="flex gap-32 items-center justify-center relative">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-12 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <div className="absolute -right-32 top-1/2 w-32 h-24 border-r-2 border-t-2 border-[#1e3a5f]/40 rounded-tr-xl pointer-events-none"></div>}
                            {i % 2 === 1 && <div className="absolute -right-32 bottom-1/2 w-32 h-24 border-r-2 border-b-2 border-[#1e3a5f]/40 rounded-br-xl pointer-events-none"></div>}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-64' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <div className="absolute -right-32 top-1/2 w-32 h-[12rem] border-r-2 border-t-2 border-[#1e3a5f]/40 rounded-tr-xl pointer-events-none"></div>}
                  {i === 1 && <div className="absolute -right-32 bottom-1/2 w-32 h-[12rem] border-r-2 border-b-2 border-[#1e3a5f]/40 rounded-br-xl pointer-events-none"></div>}
                </div>
              ))}
            </div>

            <div className="relative scale-125">{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={onReset} className="mt-20 px-12 py-3 bg-red-900/20 border border-red-900/50 text-red-500 font-cinzel font-bold tracking-widest uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="relative z-10 w-full h-screen flex flex-col justify-center px-10">
            {wheelState && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration || 5000} />}
            <div className="absolute top-8 left-8 right-8 flex justify-between items-center px-4">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK</Button>
                <div className="text-center"><span className="text-[#dcb06b] font-orbitron text-xs tracking-[0.4em] uppercase">{activeMatchData?.label} REVEAL</span></div>
                <div className="w-20"></div>
            </div>
            <div className="grid grid-cols-2 gap-32 items-center mt-10">
                <div className="space-y-4">{ROLES_ORDER.map(r => renderPlayerCard(activeMatchData!.id, 'A', r, activeMatchData!.teamA))}</div>
                <div className="space-y-4">{ROLES_ORDER.map(r => renderPlayerCard(activeMatchData!.id, 'B', r, activeMatchData!.teamB))}</div>
            </div>
            <div className="fixed bottom-12 left-0 right-0 flex justify-center">
                {revealedSlots.size < (activeMatchData?.teamB ? 10 : 5) ? (
                    <button onClick={handleNextReveal} className="px-16 py-4 bg-[#0a1a2f] border-2 border-[#dcb06b] text-[#dcb06b] font-cinzel font-black tracking-widest animate-pulse shadow-[0_0_30px_rgba(220,176,107,0.3)]">REVEAL NEXT UNIT</button>
                ) : (
                    <Button onClick={() => setPhase('TRANSITION')} size="lg">INITIALIZE BATTLE</Button>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => setElapsedSeconds(prev => prev + 1), 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     if (e.dataTransfer.getData("type") === "mvp-token") setMvpId(playerId);
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = (current < 0) ? 1 : (current === 0) ? 1 : (current === 1) ? 2 : 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = (current > 0) ? -1 : (current === 0) ? -1 : (current === -1) ? -2 : 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      const isActive = isUp ? currentRating > 0 : currentRating < 0;
      const isDouble = isUp ? currentRating === 2 : currentRating === -2;
      const colorClass = isUp ? (isActive ? 'text-green-400' : 'text-gray-600') : (isActive ? 'text-red-500' : 'text-gray-600');
      const glowClass = isActive ? (isUp ? 'drop-shadow-[0_0_10px_#4ade80]' : 'drop-shadow-[0_0_10px_#ef4444]') : '';

      return (
          <button onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} className={`p-1.5 hover:bg-white/10 transition-all ${colorClass} ${glowClass} flex flex-col items-center -space-y-1.5`}>
              {isUp ? (
                  <>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg></>
              ) : (
                  <><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}</>
              )}
          </button>
      );
  };

  const renderTeamColumn = (teamSlots: any[], teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';
      const hexColor = teamColor === 'cyan' ? '#00d2ff' : '#ef4444';
      const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;
      const innerBgColor = teamColor === 'cyan' ? (isWinner ? 'bg-[#0a1a2f]/90' : 'bg-[#0a1a2f]/60') : (isWinner ? 'bg-[#1a0505]/90' : 'bg-[#1a0505]/60');

      return (
        <div className={`flex-1 w-full relative flex flex-col h-full clip-corner-md transition-all duration-500 p-[2px] ${isWinner ? `shadow-[0_0_40px_${hexColor}] z-10 scale-[1.01]` : 'shadow-[0_0_20px_rgba(0,0,0,0.5)] opacity-60 scale-95'}`}>
            {isWinner ? (
                <div className="absolute inset-[-50%] animate-[spin_4s_linear_infinite]" style={{ background: `conic-gradient(from 0deg, transparent 0deg, transparent 80deg, ${hexColor} 140deg, ${hexColor} 180deg, transparent 240deg)` }}></div>
            ) : (
                <div className={`absolute inset-0 ${teamColor === 'cyan' ? 'bg-[#1e3a5f]' : 'bg-[#450a0a]'}`}></div>
            )}
            <div className={`relative z-10 w-full h-full flex flex-col ${innerBgColor} clip-corner-md overflow-hidden`}>
                <div className={`p-4 flex justify-between items-center border-b border-white/10 ${teamColor === 'cyan' ? 'bg-[#00d2ff]/20' : 'bg-[#ef4444]/20'}`}>
                    <h3 className={`${textColor} font-cinzel font-black text-lg tracking-[0.15em] drop-shadow-lg`}>{teamName}</h3>
                    {isWinner && <span className="text-[#05090f] font-black uppercase tracking-[0.2em] text-[10px] border border-[#dcb06b] px-3 py-1 rounded bg-[#dcb06b] shadow-[0_0_10px_#dcb06b] animate-pulse">Victory</span>}
                </div>
                <div className="p-3 space-y-2.5 overflow-y-auto flex-1 custom-scrollbar">
                    {rolesToRender.map(role => {
                        const slot = teamSlots.find(s => s.role === role);
                        if(!slot) return null;
                        const isMvp = slot.player.id === mvpId;
                        const rating = ratings[slot.player.id] || 0;
                        const isCoach = role === Role.COACH;
                        return (
                            <div key={role} onDragOver={!isCoach ? handleDragOver : undefined} onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined} className={`flex items-center justify-between bg-[#0a1a2f]/80 p-3 rounded-md border-2 h-16 relative transition-all duration-300 ${isMvp ? 'border-yellow-400 shadow-[0_0_20px_rgba(251,191,36,0.4)]' : 'border-white/5'}`}>
                                <div className="flex items-center gap-4 min-w-0 flex-1">
                                    <div className={`shrink-0 scale-[0.85] ${teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500'}`}>{RoleIcons[role]}</div>
                                    <div className={`text-base font-orbitron truncate font-bold ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                                {!isCoach && (
                                <div className="flex items-center gap-3 shrink-0">
                                    <div className="flex flex-col gap-1">{renderRatingButton(slot.player.id, 'up', rating)}{renderRatingButton(slot.player.id, 'down', rating)}</div>
                                    <div className="w-10 h-10 flex items-center justify-center">
                                        {isMvp ? <div className="w-9 h-9 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_10px_gold] border border-white/30">MVP</div> : <div className="w-9 h-9 border-2 border-dashed border-white/10 rounded-full opacity-30"></div>}
                                    </div>
                                </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="w-full max-w-6xl h-full flex flex-col py-6 animate-slide-in">
          <div className="text-center mb-5 flex justify-between items-center px-6">
             <div className="text-left"><h1 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-[0.2em] mb-1 uppercase">EVALUATION SESSION</h1><p className="text-[10px] text-[#4a5f78] uppercase font-black tracking-widest">RATE PERFORMANCE & SELECT MVP</p></div>
             <div className="flex flex-col items-center"><span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest mb-2 uppercase">SESSION TIME</span><div className="text-2xl font-mono font-bold text-white bg-black/70 px-8 py-1.5 rounded-md border-2 border-[#dcb06b]/30">{formatTime(elapsedSeconds)}</div></div>
          </div>
          <div className="flex flex-col items-center mb-6 h-14">{!mvpId ? <div draggable onDragStart={handleDragStart} className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform"><div className="w-12 h-12 bg-gradient-to-br from-yellow-300 to-yellow-600 rounded-full flex items-center justify-center shadow-[0_0_15px_#fbbf24] border-2 border-white/50 animate-pulse"><span className="font-black italic text-[#05090f] text-xs">MVP</span></div></div> : <button onClick={() => setMvpId('')} className="text-[10px] text-red-400 border-2 border-red-500/30 px-6 py-2 uppercase font-black tracking-widest hover:bg-red-950/60 transition-all clip-corner-sm shadow-lg">RESET MVP SELECTION</button>}</div>
          <div className="flex flex-col md:flex-row gap-8 items-stretch justify-center flex-1 max-h-[68vh]">{renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}{renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}</div>
          <div className="mt-8 flex justify-center pb-4"><Button onClick={() => onComplete(mvpId, ratings)} size="lg" className="px-20 py-5">FINISH EVALUATION</Button></div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

export const LocalClock: React.FC = () => {
  const [time, setTime] = useState('');
  const [isVisible, setIsVisible] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [position, setPosition] = useState({ x: window.innerWidth - 150, y: 20 });
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const updateTime = () => {
      const now = new Date();
      const options: Intl.DateTimeFormatOptions = {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false,
      };
      // Uses local system time automatically by omitting timeZone
      setTime(new Intl.DateTimeFormat(undefined, options).format(now));
    };

    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (isMinimized) return;
    setIsDragging(true);
    dragOffset.current = {
      x: e.clientX - position.x,
      y: e.clientY - position.y
    };
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;

      const newX = Math.max(0, Math.min(window.innerWidth - (isMinimized ? 40 : 128), e.clientX - dragOffset.current.x));
      const newY = Math.max(0, Math.min(window.innerHeight - (isMinimized ? 40 : 60), e.clientY - dragOffset.current.y));

      setPosition({ x: newX, y: newY });
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, isMinimized]);

  if (!isVisible) return (
    <button 
      onClick={() => setIsVisible(true)}
      className="fixed bottom-4 right-4 z-[100] w-10 h-10 bg-[#0a1a2f] border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_10px_rgba(220,176,107,0.3)]"
    >
      <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
    </button>
  );

  return (
    <div 
      style={{ left: position.x, top: position.y }}
      className={`fixed z-[100] transition-shadow duration-300 ${isDragging ? 'shadow-[0_0_20px_rgba(220,176,107,0.5)]' : 'shadow-xl'}`}
    >
      {isMinimized ? (
        <button 
          onClick={() => setIsMinimized(false)}
          className="w-10 h-10 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b] text-[#dcb06b] flex items-center justify-center clip-corner-sm hover:scale-110 transition-transform"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
        </button>
      ) : (
        <div className="w-32 bg-[#0a1a2f]/90 backdrop-blur-md border border-[#dcb06b]/50 clip-corner-sm flex flex-col overflow-hidden shadow-2xl">
          {/* Draggable Header */}
          <div 
            onMouseDown={handleMouseDown}
            className={`h-5 bg-[#dcb06b]/20 flex items-center justify-between px-2 cursor-move select-none border-b border-[#dcb06b]/30 ${isDragging ? 'bg-[#dcb06b]/40' : ''}`}
          >
            <div className="flex gap-1 items-center">
               <div className="w-1 h-1 bg-[#dcb06b] rounded-full animate-pulse"></div>
               <span className="text-[7px] font-orbitron font-bold text-[#dcb06b] tracking-tighter">LOCAL SYSTEM</span>
            </div>
            <div className="flex gap-1">
              <button onClick={() => setIsMinimized(true)} className="text-[#dcb06b] hover:text-white">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" /></svg>
              </button>
              <button onClick={() => setIsVisible(false)} className="text-[#dcb06b] hover:text-red-500">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>
          </div>

          {/* Time Display */}
          <div className="p-2 flex flex-col items-center">
             <div className="text-lg font-orbitron font-black text-white tracking-widest drop-shadow-[0_0_5px_rgba(255,255,255,0.3)]">
                {time}
             </div>
             <div className="text-[6px] font-orbitron text-[#dcb06b] uppercase tracking-[0.2em] mt-0.5 opacity-60">
                LOCAL TIME
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Auto-Advance Logic) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;

        // Auto-win for BYE matches: If no teamB, teamA is the winner automatically
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      // 1. Generate Quarter Finals
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 2. Generate Semi Finals
      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 3. Generate Grand Final
      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  // --- ACTIONS ---

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);

    // Auto-advance logic for BYE (stuck prevention)
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }

    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  // --- RENDERERS ---

  const EnergyConnector = ({ type, height = 200 }: { type: 'fork' | 'straight', height?: number }) => (
    <div className="absolute top-0 -right-16 md:-right-24 w-16 md:w-24 pointer-events-none z-0" style={{ height: `${height}px` }}>
       <svg width="100%" height="100%" viewBox="0 0 100 200" preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyFlow" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="glow">
                <feGaussianBlur stdDeviation="2" result="coloredBlur"/>
                <feMerge>
                    <feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/>
                </feMerge>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d="M0,50 L50,50 L50,150 L0,150 M50,100 L100,100" 
                stroke="url(#energyFlow)" 
                strokeWidth="3" 
                fill="none" 
                filter="url(#glow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d="M0,100 L100,100" 
                stroke="url(#energyFlow)" 
                strokeWidth="3" 
                fill="none" 
                filter="url(#glow)"
                strokeLinecap="round"
             />
          )}
          {/* Animated Energy Pulse */}
          <circle r="3" fill="#fff" filter="url(#glow)">
              <animateMotion 
                path={type === 'fork' ? "M0,50 L50,50 L50,100 L100,100" : "M0,100 L100,100"} 
                dur="1.5s" 
                repeatCount="indefinite" 
              />
          </circle>
          <circle r="3" fill="#fff" filter="url(#glow)">
              <animateMotion 
                path={type === 'fork' ? "M0,150 L50,150 L50,100 L100,100" : "M0,100 L100,100"} 
                dur="1.5s" 
                begin="0.75s"
                repeatCount="indefinite" 
              />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] invisible"></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_30px_rgba(220,176,107,0.3)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/20' : 'bg-[#05090f]/80'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number;
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-10">
            {/* QUARTER FINALS */}
            {hasQuarterFinals && (
                <div className="flex flex-col gap-12 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={220} />}
                        </div>
                    ))}
                </div>
            )}

            {/* SEMI FINALS */}
            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-64' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 450 : 330} />}
                </div>
              ))}
            </div>

            {/* GRAND FINAL */}
            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="relative z-10 w-full h-screen flex flex-col justify-center px-10">
            {/* Reveal Logic Implementation... */}
            <div className="absolute top-8 left-8 flex items-center gap-4">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
            </div>
            <div className="text-center mb-12">
                <h2 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest">{activeMatchData?.label} REVEAL</h2>
                <p className="text-[#4a5f78] font-orbitron text-[10px] tracking-[0.5em] uppercase mt-2">BATTLE ID: {activeRoomId}</p>
            </div>

            <div className="grid grid-cols-2 gap-20 md:gap-40 items-center max-w-6xl mx-auto w-full">
                {/* Team A */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2">{activeMatchData?.teamA?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`a-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-A-${r}`) ? activeMatchData?.teamA?.slots.find(s => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
                {/* Team B */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2">{activeMatchData?.teamB?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`b-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-B-${r}`) ? activeMatchData?.teamB?.slots.find(s => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-12 left-0 right-0 flex justify-center">
                {revealedSlots.size < 10 ? (
                    <button 
                        onClick={() => {
                            const nextRoleIdx = currentRoleIdx + 1;
                            const role = ROLES_ORDER[nextRoleIdx];
                            setRevealedSlots(prev => {
                                const next = new Set(prev);
                                next.add(`m${currentMatchIdx}-A-${role}`);
                                next.add(`m${currentMatchIdx}-B-${role}`);
                                return next;
                            });
                            setCurrentRoleIdx(nextRoleIdx);
                        }} 
                        className="px-16 py-4 bg-[#0a1a2f] border-2 border-[#dcb06b] text-[#dcb06b] font-cinzel font-black tracking-widest animate-pulse shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:bg-[#dcb06b] hover:text-black transition-all"
                    >
                        REVEAL NEXT UNITS
                    </button>
                ) : (
                    <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-20 py-5 text-lg">INITIALIZE BATTLE</Button>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { MatchResult, Role } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';

interface EvaluationScreenProps {
  match: MatchResult;
  winner: 'azure' | 'crimson';
  onComplete: (mvpId?: string, ratings?: Record<string, number>) => void;
}

export const EvaluationScreen: React.FC<EvaluationScreenProps> = ({ match, winner, onComplete }) => {
  const [mvpId, setMvpId] = useState<string>('');
  const [isLoading, setIsLoading] = useState(true);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const timerRef = useRef<number | null>(null);
  const [ratings, setRatings] = useState<Record<string, number>>({});

  useEffect(() => {
    const loadingTimer = setTimeout(() => setIsLoading(false), 2000);
    return () => {
       clearTimeout(loadingTimer);
       if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!isLoading && !timerRef.current) {
        timerRef.current = window.setInterval(() => setElapsedSeconds(prev => prev + 1), 1000);
    }
  }, [isLoading]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleDragStart = (e: React.DragEvent) => {
    e.dataTransfer.setData("type", "mvp-token");
    e.dataTransfer.effectAllowed = "move";
  };

  const handleDragOver = (e: React.DragEvent) => { e.preventDefault(); e.dataTransfer.dropEffect = "move"; };
  const handleDrop = (e: React.DragEvent, playerId: string) => {
     e.preventDefault();
     if (e.dataTransfer.getData("type") === "mvp-token") setMvpId(playerId);
  };

  const cycleRatingUp = (playerId: string) => {
      setRatings(prev => {
          const current = prev[playerId] || 0;
          let next = (current < 0) ? 1 : (current === 0) ? 1 : (current === 1) ? 2 : 0;
          const newState = { ...prev, [playerId]: next };
          if (next === 0) delete newState[playerId];
          return newState;
      });
  };

  const cycleRatingDown = (playerId: string) => {
    setRatings(prev => {
        const current = prev[playerId] || 0;
        let next = (current > 0) ? -1 : (current === 0) ? -1 : (current === -1) ? -2 : 0;
        const newState = { ...prev, [playerId]: next };
        if (next === 0) delete newState[playerId];
        return newState;
    });
  };

  const renderRatingButton = (playerId: string, direction: 'up' | 'down', currentRating: number) => {
      const isUp = direction === 'up';
      const isActive = isUp ? currentRating > 0 : currentRating < 0;
      const isDouble = isUp ? currentRating === 2 : currentRating === -2;
      const colorClass = isUp ? (isActive ? 'text-green-400' : 'text-gray-600') : (isActive ? 'text-red-500' : 'text-gray-600');
      const glowClass = isActive ? (isUp ? 'drop-shadow-[0_0_10px_#4ade80]' : 'drop-shadow-[0_0_10px_#ef4444]') : '';

      return (
          <button onClick={() => isUp ? cycleRatingUp(playerId) : cycleRatingDown(playerId)} className={`p-1.5 hover:bg-white/10 transition-all ${colorClass} ${glowClass} flex flex-col items-center -space-y-1.5`}>
              {isUp ? (
                  <>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}<svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg></>
              ) : (
                  <><svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>{isDouble && <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={7}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}</>
              )}
          </button>
      );
  };

  const renderTeamColumn = (teamSlots: any[], teamName: string, isWinner: boolean, teamColor: 'cyan' | 'red') => {
      const textColor = teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500';
      const hexColor = teamColor === 'cyan' ? '#00d2ff' : '#ef4444';
      const rolesToRender = match.isCoachMode ? [Role.COACH, ...ROLES_ORDER] : ROLES_ORDER;
      const innerBgColor = teamColor === 'cyan' ? (isWinner ? 'bg-[#0a1a2f]/95' : 'bg-[#0a1a2f]/60') : (isWinner ? 'bg-[#1a0505]/95' : 'bg-[#1a0505]/60');

      return (
        <div className={`flex-1 w-full relative flex flex-col h-full clip-corner-md transition-all duration-700 p-[3px] ${isWinner ? `shadow-[0_0_50px_${hexColor}] z-10 scale-[1.02]` : 'shadow-[0_0_20px_rgba(0,0,0,0.5)] opacity-50 scale-95'}`}>
            {isWinner ? (
                <div className="absolute inset-[-50%] animate-[spin_3s_linear_infinite]" style={{ background: `conic-gradient(from 0deg, transparent 0deg, transparent 60deg, ${hexColor} 120deg, ${hexColor} 180deg, transparent 240deg)` }}></div>
            ) : (
                <div className={`absolute inset-0 ${teamColor === 'cyan' ? 'bg-[#1e3a5f]' : 'bg-[#450a0a]'}`}></div>
            )}
            <div className={`relative z-10 w-full h-full flex flex-col ${innerBgColor} clip-corner-md overflow-hidden`}>
                <div className={`p-5 flex justify-between items-center border-b border-white/10 ${teamColor === 'cyan' ? 'bg-[#00d2ff]/20' : 'bg-[#ef4444]/20'}`}>
                    <h3 className={`${textColor} font-cinzel font-black text-xl tracking-[0.2em] drop-shadow-[0_0_10px_rgba(0,0,0,0.5)]`}>{teamName}</h3>
                    {isWinner && <span className="text-[#05090f] font-black uppercase tracking-[0.2em] text-[10px] border border-[#dcb06b] px-4 py-1.5 rounded bg-[#dcb06b] shadow-[0_0_15px_#dcb06b] animate-pulse">Victory</span>}
                </div>
                <div className="p-4 space-y-3 overflow-y-auto flex-1 custom-scrollbar">
                    {rolesToRender.map(role => {
                        const slot = teamSlots.find(s => s.role === role);
                        if(!slot) return null;
                        const isMvp = slot.player.id === mvpId;
                        const rating = ratings[slot.player.id] || 0;
                        const isCoach = role === Role.COACH;
                        return (
                            <div key={role} onDragOver={!isCoach ? handleDragOver : undefined} onDrop={!isCoach ? (e) => handleDrop(e, slot.player.id) : undefined} className={`flex items-center justify-between bg-black/40 p-4 rounded-md border-2 h-20 relative transition-all duration-300 ${isMvp ? 'border-yellow-400 shadow-[0_0_25px_rgba(251,191,36,0.3)] scale-[1.02] z-10' : 'border-white/5 hover:border-white/10'}`}>
                                <div className="flex items-center gap-4 min-w-0 flex-1">
                                    <div className={`shrink-0 scale-[0.85] ${teamColor === 'cyan' ? 'text-cyan-400' : 'text-red-500'}`}>{RoleIcons[role]}</div>
                                    <div className={`text-lg font-orbitron truncate font-bold tracking-wider ${isMvp ? 'text-[#dcb06b]' : 'text-white'}`}>{slot.player.name}</div>
                                </div>
                                {!isCoach && (
                                <div className="flex items-center gap-4 shrink-0">
                                    <div className="flex flex-col gap-1">{renderRatingButton(slot.player.id, 'up', rating)}{renderRatingButton(slot.player.id, 'down', rating)}</div>
                                    <div className="w-12 h-12 flex items-center justify-center">
                                        {isMvp ? <div className="w-10 h-10 bg-yellow-500 rounded-full flex items-center justify-center font-black text-black text-[10px] shadow-[0_0_15px_gold] border-2 border-white/40">MVP</div> : <div className="w-10 h-10 border-2 border-dashed border-white/10 rounded-full opacity-30"></div>}
                                    </div>
                                </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
      );
  }

  return (
    <div className="min-h-screen bg-[#05090f] fixed inset-0 z-[50] flex flex-col items-center justify-center p-4">
       <div className="w-full max-w-7xl h-full flex flex-col py-6 animate-slide-in">
          <div className="text-center mb-8 flex justify-between items-center px-8">
             <div className="text-left">
                <h1 className="text-4xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-1 uppercase drop-shadow-[0_0_10px_rgba(220,176,107,0.3)]">EVALUATION SESSION</h1>
                <p className="text-[10px] text-[#4a5f78] uppercase font-black tracking-[0.5em]">ANALYZE COMBAT PERFORMANCE & REWARD VALOR</p>
             </div>
             <div className="flex flex-col items-center">
                <span className="text-[#8a9db8] text-[10px] font-orbitron tracking-widest mb-2 uppercase">BATTLE TIME</span>
                <div className="text-3xl font-mono font-bold text-white bg-black/80 px-10 py-2 rounded-md border-2 border-[#dcb06b]/30 shadow-[0_0_20px_rgba(0,0,0,0.5)]">{formatTime(elapsedSeconds)}</div>
             </div>
          </div>

          <div className="flex flex-col items-center mb-8 h-16">
            {!mvpId ? (
                <div draggable onDragStart={handleDragStart} className="cursor-grab active:cursor-grabbing hover:scale-110 transition-transform">
                    <div className="w-16 h-16 bg-gradient-to-br from-yellow-300 via-yellow-500 to-yellow-700 rounded-full flex items-center justify-center shadow-[0_0_30px_#fbbf24] border-4 border-white/30 animate-pulse">
                        <span className="font-black italic text-[#05090f] text-sm">MVP</span>
                    </div>
                </div>
            ) : (
                <button onClick={() => setMvpId('')} className="text-[10px] text-red-400 border-2 border-red-500/30 px-8 py-3 uppercase font-black tracking-[0.3em] hover:bg-red-950/60 transition-all clip-corner-sm shadow-[0_0_20px_rgba(239,68,68,0.2)]">RESET MVP SELECTION</button>
            )}
          </div>

          <div className="flex flex-col md:flex-row gap-10 items-stretch justify-center flex-1 max-h-[65vh]">
            {renderTeamColumn(match.azureTeam, "AZURE GOLEM", winner === 'azure', 'cyan')}
            {renderTeamColumn(match.crimsonTeam, "CRIMSON GOLEM", winner === 'crimson', 'red')}
          </div>

          <div className="mt-12 flex justify-center pb-6">
             <Button onClick={() => onComplete(mvpId, ratings)} size="lg" className="px-24 py-6 text-lg tracking-[0.4em] shadow-[0_0_30px_rgba(220,176,107,0.2)]">FINISH EVALUATION</Button>
          </div>
       </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    teamName: string;
    teamIndex: number;
    globalTeamIndex?: number;
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration?: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        // Auto-win for BYE matches
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      // 1. Generate Quarter Finals
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 2. Generate Semi Finals
      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      // 3. Generate Grand Final
      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  // --- ACTIONS ---

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);

    // Auto-advance for BYE matches - instant state update
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }

    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  // --- RENDERERS ---

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-16 md:-right-24 w-16 md:w-24 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, transform: 'translateY(-50%)' }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,${height/4} L 50,${height/4} L 50,${height * 0.75} L 0,${height * 0.75} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          {/* Energy Particles */}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height/4} L 50,${height/4} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height * 0.75} L 50,${height * 0.75} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                begin="1s"
                repeatCount="indefinite" 
              />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {/* QUARTER FINALS */}
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={226} />}
                        </div>
                    ))}
                </div>
            )}

            {/* SEMI FINALS */}
            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 480 : 340} />}
                </div>
              ))}
            </div>

            {/* GRAND FINAL */}
            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="relative z-10 w-full h-screen flex flex-col justify-center px-10">
            {wheelState && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} onComplete={() => {
                if (wheelState.type === 'reveal') {
                    const id = `m${currentMatchIdx}-${wheelState.teamIndex === 0 ? 'A' : 'B'}-${wheelState.role}`;
                    setRevealedSlots(prev => new Set(prev).add(id));
                    if (wheelState.teamIndex === 1) setCurrentRoleIdx(prev => prev + 1);
                } else if (wheelState.winnerPlayer && wheelState.globalTeamIndex !== undefined) {
                    onReroll(wheelState.globalTeamIndex, wheelState.role, wheelState.winnerPlayer);
                }
                setWheelState(null);
            }} onCancel={() => setWheelState(null)} team={wheelState.teamIndex === 0 ? 'azure' : 'crimson'} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration || 5000} />}

            <div className="absolute top-8 left-8 flex items-center gap-4">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
            </div>
            <div className="text-center mb-12">
                <h2 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest">{activeMatchData?.label} REVEAL</h2>
                <p className="text-[#4a5f78] font-orbitron text-[10px] tracking-[0.5em] uppercase mt-2">BATTLE ID: {activeRoomId}</p>
            </div>

            <div className="grid grid-cols-2 gap-20 md:gap-40 items-center max-w-6xl mx-auto w-full">
                {/* Team A */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`a-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-A-${r}`) ? activeMatchData?.teamA?.slots.find((s:TeamSlot) => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
                {/* Team B */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2" style={{ color: activeMatchData?.teamB?.color }}>{activeMatchData?.teamB?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`b-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-B-${r}`) ? activeMatchData?.teamB?.slots.find((s:TeamSlot) => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-12 left-0 right-0 flex justify-center">
                {revealedSlots.size < 10 ? (
                    <button 
                        onClick={() => {
                            const nextRoleIdx = currentRoleIdx + 1;
                            const role = ROLES_ORDER[nextRoleIdx];
                            setRevealedSlots(prev => {
                                const next = new Set(prev);
                                next.add(`m${currentMatchIdx}-A-${role}`);
                                next.add(`m${currentMatchIdx}-B-${role}`);
                                return next;
                            });
                            setCurrentRoleIdx(nextRoleIdx);
                        }} 
                        className="px-16 py-4 bg-[#0a1a2f] border-2 border-[#dcb06b] text-[#dcb06b] font-cinzel font-black tracking-widest animate-pulse shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:bg-[#dcb06b] hover:text-black transition-all"
                    >
                        REVEAL NEXT UNITS
                    </button>
                ) : (
                    <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-20 py-5 text-lg">INITIALIZE BATTLE</Button>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-16 md:-right-24 w-16 md:w-24 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, transform: 'translateY(-50%)' }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,${height/4} L 50,${height/4} L 50,${height * 0.75} L 0,${height * 0.75} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height/4} L 50,${height/4} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height * 0.75} L 50,${height * 0.75} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                begin="1s"
                repeatCount="indefinite" 
              />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        // Handle reroll if needed (bracket reroll logic)
    }
    setWheelState(null);
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={226} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 480 : 340} />}
                </div>
              ))}
            </div>

            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="relative z-10 w-full h-screen flex flex-col justify-center px-10">
            {wheelState && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} />}

            <div className="absolute top-8 left-8 flex items-center gap-4">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK TO BRACKET</Button>
            </div>
            <div className="text-center mb-12">
                <h2 className="text-3xl font-cinzel font-black text-[#dcb06b] tracking-widest">{activeMatchData?.label} REVEAL</h2>
                <p className="text-[#4a5f78] font-orbitron text-[10px] tracking-[0.5em] uppercase mt-2">BATTLE ID: {activeRoomId}</p>
            </div>

            <div className="grid grid-cols-2 gap-20 md:gap-40 items-center max-w-6xl mx-auto w-full">
                {/* Team A */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`a-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-A-${r}`) ? activeMatchData?.teamA?.slots.find((s:TeamSlot) => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
                {/* Team B */}
                <div className="space-y-4">
                    <h3 className="text-white font-cinzel font-bold text-xl mb-4 text-center border-b border-white/10 pb-2" style={{ color: activeMatchData?.teamB?.color }}>{activeMatchData?.teamB?.name}</h3>
                    {ROLES_ORDER.map(r => (
                        <div key={`b-${r}`} className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#0a1a2f] flex items-center px-6 transition-all duration-500 hover:border-[#dcb06b]/50">
                            <div className="text-[#dcb06b] mr-4 opacity-50">{RoleIcons[r]}</div>
                            <div className="text-white font-orbitron font-bold text-lg">
                                {revealedSlots.has(`m${currentMatchIdx}-B-${r}`) ? activeMatchData?.teamB?.slots.find((s:TeamSlot) => s.role === r)?.player.name : '??????'}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-12 left-0 right-0 flex justify-center">
                {revealedSlots.size < 10 ? (
                    <button 
                        onClick={handleNextReveal} 
                        className="px-16 py-4 bg-[#0a1a2f] border-2 border-[#dcb06b] text-[#dcb06b] font-cinzel font-black tracking-widest animate-pulse shadow-[0_0_30px_rgba(220,176,107,0.3)] hover:bg-[#dcb06b] hover:text-black transition-all"
                    >
                        {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}
                    </button>
                ) : (
                    <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-20 py-5 text-lg">INITIALIZE BATTLE</Button>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-16 md:-right-24 w-16 md:w-24 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, transform: 'translateY(-50%)' }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,${height/4} L 50,${height/4} L 50,${height * 0.75} L 0,${height * 0.75} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height/4} L 50,${height/4} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height * 0.75} L 50,${height * 0.75} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                begin="1s"
                repeatCount="indefinite" 
              />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           {/* Reroll Button - EXACT MATCH TO MatchDisplay */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={226} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 480 : 340} />}
                </div>
              ))}
            </div>

            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI - OVERHAULED TO MATCH MatchDisplay EXACTLY */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                <div className="w-[120px]"></div> {/* Spacer */}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-16 md:-right-24 w-16 md:w-24 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, transform: 'translateY(-50%)' }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,${height/4} L 50,${height/4} L 50,${height * 0.75} L 0,${height * 0.75} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height/4} L 50,${height/4} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,${height * 0.75} L 50,${height * 0.75} L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} 
                dur="2s" 
                begin="1s"
                repeatCount="indefinite" 
              />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { 
        allCards.add(`m${currentMatchIdx}-A-${r}`); 
        allCards.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           {/* Reroll Button - EXACT MATCH TO MatchDisplay */}
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={226} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 480 : 340} />}
                </div>
              ))}
            </div>

            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI - OVERHAULED TO MATCH MatchDisplay EXACTLY */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                {revealedSlots.size < 10 ? (
                    <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                        SKIP ALL
                    </Button>
                ) : (
                    <div className="w-[120px]"></div> 
                )}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const hasQuarterFinals = match.teams.length > 4;

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px` }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          {/* Moving particles */}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion 
                  path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} 
                  dur="2s" 
                  begin="1s"
                  repeatCount="indefinite" 
                />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { 
        allCards.add(`m${currentMatchIdx}-A-${r}`); 
        allCards.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  // Exact vertical centers calculation for connectors:
  // Card Height: 210px
  // Quarter Gap: 16 (64px) -> Center to Center: 210 + 64 = 274px
  // Semi Gap (with Quarters): 72 (288px) -> Center to Center: 210 + 288 = 498px
  // Semi Gap (no Quarters): 32 (128px) -> Center to Center: 210 + 128 = 338px

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={274} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : 'gap-32'} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {i === 0 && <EnergyConnector type="fork" height={hasQuarterFinals ? 498 : 338} />}
                </div>
              ))}
            </div>

            <div className="relative scale-125 ml-10">
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                {revealedSlots.size < 10 ? (
                    <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                        SKIP ALL
                    </Button>
                ) : (
                    <div className="w-[120px]"></div> 
                )}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- COMPLEX BRACKET GENERATION (Supports Odd & Even Counts) ---
  const { allMatches, grandFinalId, isOddBracket } = useMemo(() => {
      const numTeams = match.teams.length;
      const isOdd = numTeams % 2 !== 0;
      const matches: any[] = [];

      const getResult = (mIdx: number) => {
          const sA = scores[`${mIdx}-A`] || 0;
          const sB = scores[`${mIdx}-B`] || 0;
          const matchObj = matches.find(m => m.id === mIdx);
          if (!matchObj || (sA === 0 && sB === 0)) return { winner: null, loser: null };
          return sA > sB ? { winner: matchObj.teamA, loser: matchObj.teamB } : { winner: matchObj.teamB, loser: matchObj.teamA };
      };

      // --- 3 TEAMS LOGIC ---
      if (numTeams === 3) {
          matches.push({ id: 0, label: 'MATCH 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
          const m1 = getResult(0);
          matches.push({ id: 1, label: 'LOWER MATCH', mode: 'BO1', teamA: m1.loser, teamB: match.teams[2] });
          const m2 = getResult(1);
          matches.push({ id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: m1.winner, teamB: m2.winner });
          return { allMatches: matches, grandFinalId: 2, isOddBracket: true };
      }

      // --- 5 TEAMS LOGIC ---
      if (numTeams === 5) {
          matches.push({ id: 0, label: 'QF 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
          matches.push({ id: 1, label: 'QF 2', mode: 'BO1', teamA: match.teams[2], teamB: match.teams[3] });
          const m1 = getResult(0), m2 = getResult(1);
          matches.push({ id: 2, label: 'LOWER SEMI', mode: 'BO1', teamA: m1.loser, teamB: m2.loser });
          const m3 = getResult(2);
          matches.push({ id: 3, label: 'LOWER FINAL', mode: 'BO1', teamA: m3.winner, teamB: match.teams[4] });
          const m4 = getResult(3);
          matches.push({ id: 4, label: 'UPPER SEMI', mode: 'BO1', teamA: m1.winner, teamB: m2.winner });
          const m5 = getResult(4);
          matches.push({ id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: m5.winner, teamB: m4.winner });
          return { allMatches: matches, grandFinalId: 5, isOddBracket: true };
      }

      // --- STANDARD EVEN BRACKETS (4, 6, 8) ---
      const hasQuarter = numTeams > 4;
      const qMatches: any[] = [];
      if (hasQuarter) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarter) {
          const q1 = getResult(0), q2 = getResult(1), q3 = getResult(2), q4 = getResult(3);
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: q1.winner, teamB: q2.winner });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: q3.winner, teamB: q4.winner });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const gfId = hasQuarter ? 6 : 2;
      const s1 = getResult(hasQuarter ? 4 : 0), s2 = getResult(hasQuarter ? 5 : 1);
      const gfMatch = { id: gfId, label: 'GRAND FINAL', mode: 'BO3', teamA: s1.winner, teamB: s2.winner };

      return { allMatches: [...qMatches, ...sMatches, gfMatch], grandFinalId: gfId, isOddBracket: false };

  }, [match, scores]);

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    // Auto-advance if single team match (Bye)
    if (m && !m.teamB) {
        const side = scores[`${idx}-A`] ? 'B' : 'A';
        setScores(prev => ({ ...prev, [`${idx}-${side}`]: 1 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalId) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalId) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             const gf = allMatches.find(m => m.id === grandFinalId);
             setTournamentChampion(newScoreA >= 2 ? gf.teamA : gf.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" style={{ height: `${height}px` }}>
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b"><animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" /></stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%"><feGaussianBlur stdDeviation="3" result="blur"/><feComposite in="SourceGraphic" in2="blur" operator="over"/></filter>
          </defs>
          <path d={type === 'fork' ? `M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" /></circle>
          {type === 'fork' && <circle r="3" fill="#fff" filter="url(#energyGlow)"><animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" /></circle>}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m || (!m.teamA && !m.teamB)) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest uppercase">WAITING RESULTS</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.id === grandFinalId;

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color || '#1e3a5f' }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color || '#1e3a5f' }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between"><span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                    {!isDone && m.teamA && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}</div>
                ) : (
                    <>
                        <div className="flex-1 relative"><span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black uppercase">ID</span>
                        <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => setMatchRoomIds(prev => ({ ...prev, [m.id]: e.target.value.replace(/\D/g,'').slice(0,4) }))} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----"/></div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    let side: 'azure' | 'crimson' = revealedSlots.has(azureId) ? 'crimson' : 'azure';
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    setWheelState({ isOpen: true, type: 'reveal', team: side, role: role, winnerName: winner.name, candidates: candidateNames, duration: Math.floor(Math.random() * 4500) + 4500 });
  };

  const handleSkipAll = () => {
    const all = new Set<string>();
    ROLES_ORDER.forEach(r => { all.add(`m${currentMatchIdx}-A-${r}`); all.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(all); setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;
    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));
    const bench = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    if (bench.length === 0) return;
    const newP = bench[Math.floor(Math.random() * bench.length)];
    setWheelState({ isOpen: true, type: 'reroll', team: side, role: role, winnerName: newP.name, winnerPlayer: newP, candidates: bench.map(p => p.name), duration: Math.floor(Math.random() * 4000) + 4000 });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const id = `m${currentMatchIdx}-${wheelState.team === 'azure' ? 'A' : 'B'}-${wheelState.role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (wheelState.team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) onReroll(idx, wheelState.role, wheelState.winnerPlayer);
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };
    return (
      <div className="relative h-16 w-full animate-slide-in group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 ${theme.bg} ${theme.border} ${theme.glow} transition-all duration-300`}>
           <div className={`flex flex-col h-full px-6 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'}`}>{RoleIcons[role]}</div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron w-full">{slot?.player.name}</span>
           </div>
           <button onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]"><h2 className="text-5xl md:text-7xl font-black font-cinzel text-white uppercase" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2></div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>

          <div className="flex flex-col gap-24 items-center">
            {/* Upper / Main Path */}
            <div className="flex gap-24 items-center justify-center relative">
               {isOddBracket && <div className="absolute -top-12 left-0 text-[10px] font-black text-[#dcb06b] tracking-widest uppercase">Upper Path</div>}
               {match.teams.length === 3 ? (
                   <>
                    <div className="relative">{renderBracketMatchCard(allMatches[0])}<EnergyConnector type="fork" height={274} /></div>
                    <div className="relative">{renderBracketMatchCard(allMatches[2])}</div>
                   </>
               ) : match.teams.length === 5 ? (
                   <>
                    <div className="flex flex-col gap-16 relative">
                        {renderBracketMatchCard(allMatches[0])}
                        <EnergyConnector type="fork" height={274} />
                        {renderBracketMatchCard(allMatches[1])}
                    </div>
                    <div className="relative">{renderBracketMatchCard(allMatches[4])}<EnergyConnector type="straight" height={0} /></div>
                    <div className="relative">{renderBracketMatchCard(allMatches[5])}</div>
                   </>
               ) : (
                   /* Default Even Bracket Rendering */
                   <div className="flex gap-24 items-center">
                      <div className="flex flex-col gap-16 relative">
                        {allMatches.filter(m => m.label.includes('QF') || m.label.includes('QUARTER')).map((m, i) => (
                            <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={274} />}</div>
                        ))}
                      </div>
                      <div className="flex flex-col gap-72 relative">
                        {allMatches.filter(m => m.label.includes('SEMI')).map((m, i) => (
                            <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i === 0 && <EnergyConnector type="fork" height={498} />}</div>
                        ))}
                      </div>
                      <div className="relative scale-125 ml-10">{renderBracketMatchCard(allMatches.find(m => m.id === grandFinalId))}</div>
                   </div>
               )}
            </div>

            {/* Lower / Waiting Path (for Odd Brackets) */}
            {isOddBracket && (
                <div className="mt-12 pt-12 border-t border-white/5 w-full flex flex-col items-center">
                   <div className="text-[10px] font-black text-red-500 tracking-widest uppercase mb-8">Lower / Consolation Path</div>
                   <div className="flex gap-24 items-center">
                        {match.teams.length === 3 ? (
                            <div className="relative">{renderBracketMatchCard(allMatches[1])}</div>
                        ) : match.teams.length === 5 ? (
                            <div className="flex gap-24 items-center">
                                <div className="relative">{renderBracketMatchCard(allMatches[2])}<EnergyConnector type="straight" height={0} /></div>
                                <div className="relative">{renderBracketMatchCard(allMatches[3])}</div>
                            </div>
                        ) : null}
                   </div>
                </div>
            )}
          </div>
          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL UI - IDENTICAL TO COACH/CASUAL */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center scale-[0.85]"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em]">{activeRoomId}</span></div></div>
            {revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name}</h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest" style={{ color: activeMatchData?.teamB?.color }}>{activeMatchData?.teamB?.name}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => (<div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>))}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // Reveal state
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- LOGIKA GENERASI BRACKET DINAMIS (UPPER & LOWER) ---
  const { allMatches, grandFinalId, isOdd } = useMemo(() => {
    const numTeams = match.teams.length;
    const isOdd = numTeams % 2 !== 0;
    const matches: any[] = [];

    const getResult = (mIdx: number) => {
      const sA = scores[`${mIdx}-A`] || 0;
      const sB = scores[`${mIdx}-B`] || 0;
      const m = matches.find(item => item.id === mIdx);
      if (!m || (sA === 0 && sB === 0)) return { winner: null, loser: null };
      return sA > sB ? { winner: m.teamA, loser: m.teamB } : { winner: m.teamB, loser: m.teamA };
    };

    if (numTeams === 3) {
      // 3 TEAMS: Match1 (1v2), Lower (L1 v 3), GF (W1 v WLower)
      matches.push({ id: 0, label: 'MATCH 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
      const r0 = getResult(0);
      matches.push({ id: 1, label: 'LOWER MATCH', mode: 'BO1', teamA: r0.loser, teamB: match.teams[2] });
      const r1 = getResult(1);
      matches.push({ id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: r0.winner, teamB: r1.winner });
      return { allMatches: matches, grandFinalId: 2, isOdd: true };
    } 

    if (numTeams === 5) {
      // 5 TEAMS: QF1 (1v2), QF2 (3v4), LowerSemi (L1 v L2), LowerFinal (WLS v 5), UpperSemi (W1 v W2), GF (WUS v WLF)
      matches.push({ id: 0, label: 'QF 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
      matches.push({ id: 1, label: 'QF 2', mode: 'BO1', teamA: match.teams[2], teamB: match.teams[3] });
      const r0 = getResult(0), r1 = getResult(1);
      matches.push({ id: 2, label: 'LOWER SEMI', mode: 'BO1', teamA: r0.loser, teamB: r1.loser });
      const r2 = getResult(2);
      matches.push({ id: 3, label: 'LOWER FINAL', mode: 'BO1', teamA: r2.winner, teamB: match.teams[4] });
      const r3 = getResult(3);
      matches.push({ id: 4, label: 'UPPER SEMI', mode: 'BO1', teamA: r0.winner, teamB: r1.winner });
      const r4 = getResult(4);
      matches.push({ id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: r4.winner, teamB: r3.winner });
      return { allMatches: matches, grandFinalId: 5, isOdd: true };
    }

    if (numTeams === 7) {
      // 7 TEAMS logic...
      matches.push({ id: 0, label: 'QF 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
      matches.push({ id: 1, label: 'QF 2', mode: 'BO1', teamA: match.teams[2], teamB: match.teams[3] });
      matches.push({ id: 2, label: 'QF 3', mode: 'BO1', teamA: match.teams[4], teamB: match.teams[5] });
      const r0 = getResult(0), r1 = getResult(1), r2 = getResult(2);
      matches.push({ id: 3, label: 'LOWER R1', mode: 'BO1', teamA: r0.loser, teamB: r1.loser });
      const r3 = getResult(3);
      matches.push({ id: 4, label: 'LOWER R2', mode: 'BO1', teamA: r3.winner, teamB: r2.loser });
      const r4 = getResult(4);
      matches.push({ id: 5, label: 'LOWER FINAL', mode: 'BO1', teamA: r4.winner, teamB: match.teams[6] });
      const r5 = getResult(5);
      matches.push({ id: 6, label: 'UPPER SEMI', mode: 'BO1', teamA: r0.winner, teamB: r1.winner });
      const r6 = getResult(6);
      matches.push({ id: 7, label: 'UPPER FINAL', mode: 'BO1', teamA: r6.winner, teamB: r2.winner });
      const r7 = getResult(7);
      matches.push({ id: 8, label: 'GRAND FINAL', mode: 'BO3', teamA: r7.winner, teamB: r5.winner });
      return { allMatches: matches, grandFinalId: 8, isOdd: true };
    }

    // Default: Even Brackets (4, 6, 8)
    const hasQF = numTeams > 4;
    const qfCount = hasQF ? 4 : 0;
    for (let i = 0; i < qfCount; i++) {
      matches.push({ id: i, label: `QUARTER ${i+1}`, mode: 'BO1', teamA: match.teams[i*2] || null, teamB: match.teams[i*2+1] || null });
    }
    const sfIdxStart = hasQF ? 4 : 0;
    for (let i = 0; i < 2; i++) {
      let tA = null, tB = null;
      if (hasQF) {
        tA = getResult(i*2).winner; tB = getResult(i*2+1).winner;
      } else {
        tA = match.teams[i*2]; tB = match.teams[i*2+1];
      }
      matches.push({ id: sfIdxStart + i, label: `SEMI FINAL ${i+1}`, mode: 'BO1', teamA: tA, teamB: tB });
    }
    const gfId = hasQF ? 6 : 2;
    const s1 = getResult(sfIdxStart).winner, s2 = getResult(sfIdxStart+1).winner;
    matches.push({ id: gfId, label: 'GRAND FINAL', mode: 'BO3', teamA: s1, teamB: s2 });
    return { allMatches: matches, grandFinalId: gfId, isOdd: false };
  }, [match, scores]);

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    if (idx === grandFinalId) setPhase('TRANSITION');
    else {
      setPhase('REVEAL');
      setRevealedSlots(new Set());
      setCurrentRoleIdx(-1);
    }
  };

  const handleSkipAll = () => {
    const all = new Set<string>();
    ROLES_ORDER.forEach(r => { 
      all.add(`m${currentMatchIdx}-A-${r}`); 
      all.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(all);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleNextReveal = () => {
    const m = allMatches.find(x => x.id === currentMatchIdx);
    if (!m) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    let side: 'azure' | 'crimson' = revealedSlots.has(azureId) ? 'crimson' : 'azure';
    const teamData = side === 'azure' ? m.teamA : m.teamB;
    const winner = teamData?.slots.find((s:any) => s.role === role)?.player;
    if (!winner) return;

    const revealedIds = new Set<string>();
    m.teamA?.slots.forEach((s: any) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedIds.add(s.player.id); });
    m.teamB?.slots.forEach((s: any) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => !revealedIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    setWheelState({
      isOpen: true,
      type: 'reveal',
      team: side,
      role: role,
      winnerName: winner.name,
      candidates: candidateNames,
      duration: Math.floor(Math.random() * 4000) + 4000
    });
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const m = allMatches.find(x => x.id === currentMatchIdx);
    if (!m) return;
    const teamData = side === 'azure' ? m.teamA : m.teamB;
    if (!teamData) return;
    const azureIds = new Set(m.teamA?.slots.map((s:any) => s.player.id));
    const crimsonIds = new Set(m.teamB?.slots.map((s:any) => s.player.id));
    const bench = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    if (bench.length === 0) return;
    const newP = bench[Math.floor(Math.random() * bench.length)];
    setWheelState({
      isOpen: true,
      type: 'reroll',
      team: side,
      role: role,
      winnerName: newP.name,
      winnerPlayer: newP,
      candidates: bench.map(p => p.name),
      duration: 4000
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
      const id = `m${currentMatchIdx}-${wheelState.team === 'azure' ? 'A' : 'B'}-${wheelState.role}`;
      setRevealedSlots(prev => new Set(prev).add(id));
      if (wheelState.team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
      const m = allMatches.find(x => x.id === currentMatchIdx);
      const teamData = wheelState.team === 'azure' ? m?.teamA : m?.teamB;
      const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
      if (teamIdx !== -1) onReroll(teamIdx, wheelState.role, wheelState.winnerPlayer);
    }
    setWheelState(null);
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0" style={{ height: `${height}px` }}>
      <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
        <path 
          d={type === 'fork' ? `M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} 
          stroke="#dcb06b" strokeWidth="2" fill="none" strokeOpacity="0.5" 
        />
        <circle r="3" fill="#fff"><animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" /></circle>
      </svg>
    </div>
  );

  const renderMatchCard = (m: any) => {
    if (!m || (!m.teamA && !m.teamB)) return <div className="w-80 h-32 bg-black/20 border border-white/5 flex items-center justify-center opacity-30 text-[10px] uppercase font-orbitron tracking-widest">Waiting</div>;
    const sA = scores[`${m.id}-A`] || 0;
    const sB = scores[`${m.id}-B`] || 0;
    const isDone = sA > 0 || sB > 0;
    const isGF = m.id === grandFinalId;

    return (
      <div className={`w-80 bg-[#0a1a2f] border ${isGF ? 'border-[#dcb06b] shadow-[0_0_20px_#dcb06b33]' : 'border-[#1e3a5f]'} clip-corner-sm p-3 relative group z-10`}>
        <div className="flex justify-between items-center mb-3 border-b border-white/10 pb-1">
          <span className="text-[10px] font-black font-orbitron text-[#dcb06b] uppercase">{m.label}</span>
          <span className="text-[8px] px-1 bg-black/40 text-white/50 border border-white/10 rounded">{m.mode}</span>
        </div>
        <div className="space-y-2">
          {[m.teamA, m.teamB].map((t, idx) => {
            const sc = idx === 0 ? sA : sB;
            const isWinner = isDone && sc > (idx === 0 ? sB : sA);
            return (
              <div key={idx} className={`flex justify-between items-center p-2 border-l-2 ${t ? '' : 'opacity-20'} ${isWinner ? 'bg-[#dcb06b]/10 border-[#dcb06b]' : 'border-[#1e3a5f]'}`}>
                <span className="text-xs font-cinzel font-black truncate max-w-[180px]">{t?.name || 'TBD'}</span>
                <span className="font-orbitron font-bold text-lg">{sc}</span>
              </div>
            );
          })}
        </div>
        {!isDone && m.teamA && m.teamB && (
          <div className="mt-3 flex gap-2">
            <input 
              type="text" 
              placeholder="Room" 
              value={matchRoomIds[m.id] || ''}
              onChange={(e) => setMatchRoomIds(prev => ({ ...prev, [m.id]: e.target.value.replace(/\D/g,'').slice(0,4) }))}
              className="flex-1 bg-black/40 border border-[#1e3a5f] text-[10px] font-orbitron text-center text-[#dcb06b] rounded-sm py-1"
            />
            <Button size="sm" onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} className="h-7 px-3 text-[10px]">START</Button>
          </div>
        )}
      </div>
    );
  };

  const renderPlayerCard = (role: Role, side: 'azure' | 'crimson') => {
    const m = allMatches.find(x => x.id === currentMatchIdx);
    const teamData = side === 'azure' ? m?.teamA : m?.teamB;
    const slot = teamData?.slots.find((s:any) => s.role === role);
    const id = `m${currentMatchIdx}-${side === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-black/40 flex items-center justify-center opacity-30">{RoleIcons[role]}</div>;

    const theme = side === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-cyan-500', text: 'text-cyan-400' } : { bg: 'bg-[#1a0505]', border: 'border-red-500', text: 'text-red-500' };
    return (
      <div className={`relative h-16 w-full clip-corner-md border-l-4 ${theme.bg} ${theme.border} p-4 flex items-center justify-between group animate-slide-in`}>
        <div className="flex flex-col">
          <div className={`${theme.text} scale-[0.7] origin-left mb-1`}>{RoleIcons[role]}</div>
          <span className="font-orbitron font-bold text-lg text-white">{slot?.player.name}</span>
        </div>
        <button onClick={() => handleRerollClick(side, role)} className="opacity-0 group-hover:opacity-100 p-2 bg-black/50 rounded-full text-white hover:text-[#dcb06b] transition-all">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
        </button>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return (
    <div className="fixed inset-0 z-[200] bg-black flex flex-col items-center justify-center p-8">
      <h2 className="text-[#dcb06b] font-cinzel text-5xl font-black mb-8 animate-pulse">TOURNAMENT CHAMPION</h2>
      <div className="p-12 border-4 border-[#dcb06b] clip-corner-md bg-[#0a1a2f] shadow-[0_0_50px_#dcb06b55]">
        <h1 className="text-7xl font-cinzel font-black uppercase text-white" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h1>
      </div>
      <Button onClick={onReset} size="lg" className="mt-16 px-16">BACK TO LOBBY</Button>
    </div>
  );

  if (phase === 'TRANSITION') return <PortalTransition azureTeam={allMatches.find(x => x.id === currentMatchIdx)?.teamA?.slots || []} crimsonTeam={allMatches.find(x => x.id === currentMatchIdx)?.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN') return <MatchSummary match={{ roomId: matchRoomIds[currentMatchIdx], azureTeam: allMatches.find(x => x.id === currentMatchIdx)?.teamA?.slots || [], crimsonTeam: allMatches.find(x => x.id === currentMatchIdx)?.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION') return <VictoryCelebration winner={currentRoundWinner!} teamSlots={(currentRoundWinner === 'azure' ? allMatches.find(x => x.id === currentMatchIdx)?.teamA?.slots : allMatches.find(x => x.id === currentMatchIdx)?.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION') return <EvaluationScreen match={{ roomId: matchRoomIds[currentMatchIdx], azureTeam: allMatches.find(x => x.id === currentMatchIdx)?.teamA?.slots || [], crimsonTeam: allMatches.find(x => x.id === currentMatchIdx)?.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner!} onComplete={(mvp, rat) => {
    const scoreKeyA = `${currentMatchIdx}-A`; const scoreKeyB = `${currentMatchIdx}-B`;
    const sA = scores[scoreKeyA] || 0; const sB = scores[scoreKeyB] || 0;
    const newA = sA + (currentRoundWinner === 'azure' ? 1 : 0);
    const newB = sB + (currentRoundWinner === 'crimson' ? 1 : 0);
    setScores(prev => ({ ...prev, [scoreKeyA]: newA, [scoreKeyB]: newB }));
    if (currentMatchIdx === grandFinalId && (newA >= 2 || newB >= 2)) {
      setTournamentChampion(newA >= 2 ? allMatches.find(x => x.id === grandFinalId).teamA : allMatches.find(x => x.id === grandFinalId).teamB);
      setPhase('TOURNAMENT_END');
    } else { setPhase('OVERVIEW'); }
  }} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto p-12">
      {phase === 'OVERVIEW' ? (
        <div className="min-w-max flex flex-col items-center gap-24 relative z-10">
          <div className="text-center">
            <h1 className="text-5xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] uppercase mb-4">TOURNAMENT BRACKET</h1>
            <p className="text-[10px] text-white/40 font-orbitron tracking-widest uppercase">Special Odd-Bracket Balancing Enabled</p>
          </div>

          <div className="flex flex-col gap-16">
            {/* UPPER PATH */}
            <div className="flex flex-col items-center">
              <span className="text-[10px] text-[#dcb06b] font-black uppercase mb-8 opacity-40">Upper Path</span>
              <div className="flex gap-24 items-center">
                {match.teams.length === 3 ? (
                  <>
                    <div className="relative">{renderMatchCard(allMatches[0])}<EnergyConnector type="fork" height={274} /></div>
                    <div className="relative">{renderMatchCard(allMatches[2])}</div>
                  </>
                ) : match.teams.length === 5 ? (
                  <>
                    <div className="flex flex-col gap-12 relative">{renderMatchCard(allMatches[0])}{renderMatchCard(allMatches[1])}<EnergyConnector type="fork" height={192} /></div>
                    <div className="relative">{renderMatchCard(allMatches[4])}<EnergyConnector type="straight" height={0} /></div>
                    <div className="relative">{renderMatchCard(allMatches[5])}</div>
                  </>
                ) : (
                  /* Standard 4, 6, 8 teams */
                  <div className="flex gap-24 items-center">
                    <div className="flex flex-col gap-12">
                      {allMatches.filter(m => m.label.includes('QUARTER') || m.label.includes('QF')).map(m => renderMatchCard(m))}
                    </div>
                    <div className="flex flex-col gap-32">
                      {allMatches.filter(m => m.label.includes('SEMI')).map(m => renderMatchCard(m))}
                    </div>
                    <div className="scale-110">{renderMatchCard(allMatches.find(m => m.id === grandFinalId))}</div>
                  </div>
                )}
              </div>
            </div>

            {/* LOWER PATH */}
            {isOdd && (
              <div className="flex flex-col items-center border-t border-white/5 pt-16">
                <span className="text-[10px] text-red-500 font-black uppercase mb-8 opacity-40">Lower / Consolation Path</span>
                <div className="flex gap-24 items-center">
                  {match.teams.length === 3 ? (
                    <div className="relative opacity-80 scale-95">{renderMatchCard(allMatches[1])}</div>
                  ) : match.teams.length === 5 ? (
                    <div className="flex gap-12 items-center opacity-80 scale-95">{renderMatchCard(allMatches[2])}{renderMatchCard(allMatches[3])}</div>
                  ) : (
                    <div className="flex gap-12 items-center opacity-80 scale-95">{allMatches.filter(m => m.label.includes('LOWER')).map(m => renderMatchCard(m))}</div>
                  )}
                </div>
              </div>
            )}
          </div>
          <Button onClick={onReset} variant="outline" className="mt-12 text-red-500 border-red-900/40 px-12">ABORT TOURNAMENT</Button>
        </div>
      ) : (
        /* REVEAL PHASE */
        <div className="fixed inset-0 z-[150] bg-[#05090f] flex flex-col justify-center overflow-hidden">
          {wheelState?.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={matchRoomIds[currentMatchIdx]} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}

          <div className="absolute top-8 left-8 right-8 flex justify-between items-center">
            <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')}>BACK</Button>
            <div className="text-center">
              <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest">Room ID</span>
              <h2 className="text-3xl font-orbitron font-black text-white">{matchRoomIds[currentMatchIdx]}</h2>
            </div>
            {revealedSlots.size < 10 ? (
              <Button variant="outline" size="sm" onClick={handleSkipAll} className="text-[#dcb06b] border-[#dcb06b]/40">SKIP ALL</Button>
            ) : <div className="w-24"></div>}
          </div>

          <div className="max-w-6xl mx-auto w-full px-12 space-y-4">
            {ROLES_ORDER.map(r => (
              <div key={r} className="grid grid-cols-2 gap-16">
                {renderPlayerCard(r, 'azure')}
                {renderPlayerCard(r, 'crimson')}
              </div>
            ))}
          </div>

          <div className="absolute bottom-12 left-0 right-0 flex justify-center">
            {revealedSlots.size < 10 ? (
              <button onClick={handleNextReveal} className="px-12 h-14 bg-black border-2 border-[#dcb06b] text-[#dcb06b] font-cinzel font-black text-lg hover:bg-[#dcb06b] hover:text-black transition-all shadow-[0_0_30px_#dcb06b33]">
                {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx+1]}`) ? 'SELECT CRIMSON' : 'SELECT AZURE'} {ROLES_ORDER[currentRoleIdx+1]?.replace(' Lane', '').toUpperCase()}
              </button>
            ) : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-20 h-16 animate-pulse">INITIALIZE BATTLE</Button>}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (Supports 3-Team Lower Bracket Logic) ---
  const { allMatches, grandFinalId, isOddBracket } = useMemo(() => {
      const numTeams = match.teams.length;
      const matches: any[] = [];

      const getResult = (mIdx: number) => {
          const sA = scores[`${mIdx}-A`] || 0;
          const sB = scores[`${mIdx}-B`] || 0;
          const matchObj = matches.find(m => m.id === mIdx);
          if (!matchObj || (sA === 0 && sB === 0)) return { winner: null, loser: null };
          return sA > sB ? { winner: matchObj.teamA, loser: matchObj.teamB } : { winner: matchObj.teamB, loser: matchObj.teamA };
      };

      // --- 3 TEAMS LOWER BRACKET LOGIC ---
      if (numTeams === 3) {
          // M0: Alpha vs Beta
          matches.push({ id: 0, label: 'MATCH 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
          const r0 = getResult(0);

          // M1: Loser of Match 1 vs Charlie
          matches.push({ id: 1, label: 'LOWER MATCH', mode: 'BO1', teamA: r0.loser, teamB: match.teams[2] });
          const r1 = getResult(1);

          // M2: Winner of Match 1 vs Winner of Lower Match
          matches.push({ id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: r0.winner, teamB: r1.winner });

          return { allMatches: matches, grandFinalId: 2, isOddBracket: true };
      }

      // --- 5 TEAMS LOWER BRACKET LOGIC ---
      if (numTeams === 5) {
          matches.push({ id: 0, label: 'QF 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] });
          matches.push({ id: 1, label: 'QF 2', mode: 'BO1', teamA: match.teams[2], teamB: match.teams[3] });
          const r0 = getResult(0), r1 = getResult(1);

          matches.push({ id: 2, label: 'LOWER SEMI', mode: 'BO1', teamA: r0.loser, teamB: r1.loser });
          const r2 = getResult(2);

          matches.push({ id: 3, label: 'LOWER FINAL', mode: 'BO1', teamA: r2.winner, teamB: match.teams[4] });
          const r3 = getResult(3);

          matches.push({ id: 4, label: 'UPPER SEMI', mode: 'BO1', teamA: r0.winner, teamB: r1.winner });
          const r4 = getResult(4);

          matches.push({ id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: r4.winner, teamB: r3.winner });

          return { allMatches: matches, grandFinalId: 5, isOddBracket: true };
      }

      // --- STANDARD EVEN BRACKET LOGIC (4, 6, 8) ---
      const hasQuarterFinals = numTeams > 4;
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }
      const sMatches: any[] = [];
      const gfIdxStart = hasQuarterFinals ? 4 : 0;
      for (let i = 0; i < 2; i++) {
          let tA = null, tB = null;
          if (hasQuarterFinals) {
              tA = getResult(i * 2).winner;
              tB = getResult(i * 2 + 1).winner;
          } else {
              tA = match.teams[i * 2];
              tB = match.teams[i * 2 + 1];
          }
          sMatches.push({ id: gfIdxStart + i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: tA, teamB: tB });
      }
      const gfId = hasQuarterFinals ? 6 : 2;
      const s1 = getResult(gfIdxStart).winner, s2 = getResult(gfIdxStart + 1).winner;
      const gfMatch = { id: gfId, label: 'GRAND FINAL', mode: 'BO3', teamA: s1, teamB: s2 };

      return { allMatches: [...qMatches, ...sMatches, gfMatch], grandFinalId: gfId, isOddBracket: false };
  }, [match, scores]);

  const startMatchFlow = (idx: number) => {
    setCurrentMatchIdx(idx);
    if (idx === grandFinalId) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalId) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             const gf = allMatches.find(m => m.id === grandFinalId);
             setTournamentChampion(newScoreA >= 2 ? gf.teamA : gf.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight' | 'bent', height: number }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px` }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : type === 'bent' ? (
             <path d={`M 0,0 L 50,0 L 50,${height} L 100,${height}`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          ) : (
             <path d={`M 0,0 L 100,0`} stroke="url(#energyLine)" strokeWidth="2.5" fill="none" filter="url(#energyGlow)" strokeLinecap="round" />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : type === 'bent' ? `M 0,0 L 50,0 L 50,${height} L 100,${height}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" />
          </circle>
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m || (!m.teamA && !m.teamB)) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest uppercase">WAITING RESULTS</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.id === grandFinalId;

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color || '#4a5f78' }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color || '#4a5f78' }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && m.teamA && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    let side: 'azure' | 'crimson' = revealedSlots.has(azureId) ? 'crimson' : 'azure';

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    setWheelState({ isOpen: true, type: 'reveal', team: side, role: role, winnerName: winner.name, candidates: candidateNames, duration: Math.floor(Math.random() * 4500) + 4500 });
  };

  const handleSkipAll = () => {
    const all = new Set<string>();
    ROLES_ORDER.forEach(r => { all.add(`m${currentMatchIdx}-A-${r}`); all.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(all);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;
    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));
    const bench = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    if (bench.length === 0) return;
    const newP = bench[Math.floor(Math.random() * bench.length)];
    setWheelState({ isOpen: true, type: 'reroll', team: side, role: role, winnerName: newP.name, winnerPlayer: newP, candidates: bench.map(p => p.name), duration: 4000 });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const id = `m${currentMatchIdx}-${wheelState.team === 'azure' ? 'A' : 'B'}-${wheelState.role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (wheelState.team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) onReroll(idx, wheelState.role, wheelState.winnerPlayer);
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };
    return (
      <div className="relative h-16 w-full animate-slide-in group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 ${theme.bg} ${theme.border} ${theme.glow} transition-all duration-300`}>
           <div className={`flex flex-col h-full px-6 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'}`}>{RoleIcons[role]}</div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron w-full">{slot?.player.name}</span>
           </div>
           <button onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return (
    <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
        <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]"><h2 className="text-5xl md:text-7xl font-black font-cinzel text-white uppercase" style={{ color: tournamentChampion?.color }}>{tournamentChampion?.name}</h2></div>
        <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
    </div>
  );

  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto p-12">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>

          <div className="flex flex-col gap-24 items-center">
             {/* 3-Team Specialized Layout */}
             {match.teams.length === 3 ? (
                <div className="flex gap-40 items-center justify-center relative">
                   {/* Column 1: Match 1 */}
                   <div className="flex flex-col gap-32">
                      <div className="relative">
                        <div className="absolute -top-8 left-0 text-[10px] font-black text-[#dcb06b] tracking-widest uppercase opacity-40">Upper Bracket</div>
                        {renderBracketMatchCard(allMatches[0])}
                        <EnergyConnector type="fork" height={274} />
                      </div>
                   </div>

                   {/* Column 2: Lower Match */}
                   <div className="flex flex-col">
                      <div className="relative translate-y-32">
                        <div className="absolute -top-8 left-0 text-[10px] font-black text-red-500 tracking-widest uppercase opacity-40">Lower Path</div>
                        {renderBracketMatchCard(allMatches[1])}
                        <EnergyConnector type="bent" height={-128} />
                      </div>
                   </div>

                   {/* Column 3: Grand Final */}
                   <div className="relative scale-125">
                      {renderBracketMatchCard(allMatches[2])}
                   </div>
                </div>
             ) : (
                /* Default Bracket Layout for Even / Other counts */
                <div className="flex gap-24 items-center justify-center relative py-20">
                   <div className="flex flex-col gap-16 relative">
                      {allMatches.filter(m => m.label.includes('QF') || m.label.includes('QUARTER')).map((m, i) => (
                        <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={274} />}</div>
                      ))}
                   </div>
                   <div className="flex flex-col gap-72 relative">
                      {allMatches.filter(m => m.label.includes('SEMI')).map((m, i) => (
                        <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i === 0 && <EnergyConnector type="fork" height={498} />}</div>
                      ))}
                   </div>
                   <div className="relative scale-125 ml-10">
                      {renderBracketMatchCard(allMatches.find(m => m.id === grandFinalId))}
                   </div>
                </div>
             )}
          </div>
          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL UI */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center scale-[0.85]"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em]">{activeRoomId}</span></div></div>
            {revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name}</h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-white tracking-widest" style={{ color: activeMatchData?.teamB?.color }}>{activeMatchData?.teamB?.name}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => (<div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>))}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};
